    /* ★ 프록시 서버 파일명 — 여기서 한 번만 수정하면 전체 적용 */
    window.PROXY_FILENAME = 'proxy_server_floor_v4.py';
    /* ★ 프록시 서버 주소 (포트 변경 시 여기만 수정) */
    window.PROXY_URL = 'http://127.0.0.1:8080'; // 로컬 py 서버 (항상 고정)
    window.EDGE_URL = 'https://qgfkhbcpidmraxxjtetl.supabase.co/functions/v1/proxy';

    // Edge Function 호출 시 anon key 자동 추가
    window._proxyFetch = function(url, options = {}) {
      if (url && url.startsWith('https://qgfkhbcpidmraxxjtetl.supabase.co/functions')) {
        options.headers = options.headers || {};
        options.headers['Authorization'] = 'Bearer ' + (typeof SUPABASE_KEY !== 'undefined' ? SUPABASE_KEY : '');
      }
      return fetch(url, options);
    };

/* ════════════════════════════════════════════════════════
   블록2: Supabase
════════════════════════════════════════════════════════ */
  (function() {
    const SUPABASE_URL = 'https://pjwxjnsvvgbicuqnphkr.supabase.co';
    const SUPABASE_KEY = 'sb_publishable_WyWdFsQNlyrfEDY5qRWYGw_3Vs_9C6n';

    // Supabase 클라이언트 초기화
    window._sb = supabase.createClient(SUPABASE_URL, SUPABASE_KEY, {
      auth: {
        persistSession: true,
        autoRefreshToken: true,
        detectSessionInUrl: true,
        storageKey: 'sb_sangkwon_session'
      }
    });

    // 인증 상태 변화 감지 (자동 로그인 유지 + 비밀번호 재설정)
    let _sbInitLoadCalled = false;
    window._sb.auth.onAuthStateChange((event, session) => {
      if ((event === 'SIGNED_IN' || event === 'INITIAL_SESSION') && session) {
        window._sbHideLogin && window._sbHideLogin();
        window._sbHideRecovery && window._sbHideRecovery();
        window._sbAddLogoutBtn && window._sbAddLogoutBtn();
        // ★ 로그인 시 클라우드 동기화 자동 실행 (중복 방지)
        if (!_sbInitLoadCalled) {
          _sbInitLoadCalled = true;
          setTimeout(() => {
            if (window._sbInitLoad) window._sbInitLoad().catch(e => console.warn('[SB] initLoad on auth', e));
          }, 300);
        }
      } else if (event === 'PASSWORD_RECOVERY') {
        window._sbShowRecovery && window._sbShowRecovery();
      } else if (event === 'SIGNED_OUT') {
        _sbCachedUserId = null;
        window._sbShowLogin && window._sbShowLogin();
      }
    });

    function _sbEl(id) { return document.getElementById(id); }
    function _sbClearHash() {
      try {
        history.replaceState(null, '', window.location.pathname + window.location.search);
      } catch(e) {
        window.location.hash = '';
      }
    }
    function _sbGetRedirectUrl() {
      return window.location.origin + window.location.pathname;
    }
    function _sbSetLoginState(isLoading, text) {
      const btn = _sbEl('_sbLoginBtn');
      if (!btn) return;
      btn.disabled = !!isLoading;
      btn.textContent = text || (isLoading ? '처리 중...' : '로그인');
      btn.style.opacity = isLoading ? '0.7' : '1';
      btn.style.cursor = isLoading ? 'default' : 'pointer';
    }
    function _sbSetRecoveryState(isLoading, text) {
      const btn = _sbEl('_sbRecoveryBtn');
      if (!btn) return;
      btn.disabled = !!isLoading;
      btn.textContent = text || (isLoading ? '변경 중...' : '비밀번호 변경');
      btn.style.opacity = isLoading ? '0.7' : '1';
      btn.style.cursor = isLoading ? 'default' : 'pointer';
    }
    function _sbIsRecoveryUrl() {
      const hash = window.location.hash || '';
      const hasToken = /access_token=/.test(hash) || /type=recovery/.test(hash);
      return hasToken;
    }

    // ─── 범용 헬퍼 ───────────────────────────────────────────
    // user_id 캐시
    let _sbCachedUserId = null;
    async function _sbGetUserId() {
      if (_sbCachedUserId) return _sbCachedUserId;
      try {
        const { data: { session } } = await window._sb.auth.getSession();
        _sbCachedUserId = session?.user?.id || null;
        return _sbCachedUserId;
      } catch(e) { return null; }
    }

    // ── kv_store 헬퍼 (섹션/API키 등 키-값 단건 저장) ──────
    async function kvGet(key) {
      try {
        const uid = await _sbGetUserId();
        if (!uid) return null;
        const id = uid + '_' + key;
        const { data, error } = await window._sb.from('kv_store').select('value').eq('id', id).maybeSingle();
        if (error && error.code !== 'PGRST116') throw error;
        return data ? data.value : null;
      } catch(e) { console.warn('[SB] kvGet error', key, e); return null; }
    }
    async function kvSet(key, value) {
      try {
        const uid = await _sbGetUserId();
        if (!uid) return;
        const id = uid + '_' + key;
        await window._sb.from('kv_store').upsert(
          { id, user_id: uid, key, value, updated_at: new Date().toISOString() },
          { onConflict: 'id' }
        );
      } catch(e) { console.warn('[SB] kvSet error', key, e); }
    }

    // ── 배열 테이블 헬퍼 (items / notes / workrooms / snapshots) ──
    // 배열 → 테이블에 행별 upsert
    async function tblSaveArr(table, arr) {
      try {
        const uid = await _sbGetUserId();
        if (!uid || !arr || !arr.length) return;
        const rows = arr.map(item => ({
          id: uid + '_' + (item.id || item.item_id || Math.random().toString(36).slice(2)),
          user_id: uid,
          item_id: item.id || item.item_id || '',
          data: item,
          updated_at: new Date(item.updatedAt || item.timestamp || Date.now()).toISOString()
        }));
        // 50개씩 나눠서 upsert (Supabase 요청 크기 제한 대비)
        for (let i = 0; i < rows.length; i += 50) {
          const chunk = rows.slice(i, i + 50);
          const { error } = await window._sb.from(table).upsert(chunk, { onConflict: 'id' });
          if (error) throw error;
        }
      } catch(e) { console.warn('[SB] tblSaveArr error', table, e); }
    }
    // 테이블 → 배열 로드 (본인 데이터만, RLS가 자동 필터)
    async function tblLoadArr(table) {
      try {
        const uid = await _sbGetUserId();
        if (!uid) return null;
        const { data, error } = await window._sb.from(table)
          .select('data, updated_at')
          .eq('user_id', uid)
          .order('updated_at', { ascending: false });
        if (error) throw error;
        return (data || []).map(r => r.data).filter(Boolean);
      } catch(e) { console.warn('[SB] tblLoadArr error', table, e); return null; }
    }
    // 삭제된 항목 클라우드에서 제거 (deletedAt 있는 item_id 삭제)
    async function tblDeleteItems(table, itemIds) {
      try {
        const uid = await _sbGetUserId();
        if (!uid || !itemIds.length) return;
        const ids = itemIds.map(iid => uid + '_' + iid);
        await window._sb.from(table).delete().in('id', ids);
      } catch(e) { console.warn('[SB] tblDeleteItems error', table, e); }
    }

    // ─── 동기화 상태 표시 ─────────────────────────────────────
    window._sbSyncStatus = function(msg, ok) {
      let el = document.getElementById('_sbStatusBar');
      if (!el) {
        el = document.createElement('div');
        el.id = '_sbStatusBar';
        el.style.cssText = 'position:fixed;bottom:60px;right:16px;z-index:99999;padding:6px 14px;border-radius:20px;font-size:12px;font-weight:600;pointer-events:none;transition:opacity 1s;';
        document.body.appendChild(el);
      }
      el.textContent = msg;
      el.style.background = ok ? '#10b981' : '#f59e0b';
      el.style.color = '#fff';
      el.style.opacity = '1';
      clearTimeout(window._sbStatusTimer);
      window._sbStatusTimer = setTimeout(() => { el.style.opacity = '0'; }, 2500);
    };

    // ─── re_sv 메모리 캐시 getter/setter (localStorage 용량 초과 방지) ──
    window._svCache = null;
    window._getSv = function() {
      if (window._svCache) return window._svCache;
      try { return JSON.parse(localStorage.getItem('re_sv') || '[]'); } catch(e) { return []; }
    };
    window._setSv = function(arr) {
      window._svCache = arr;
      try { localStorage.setItem('re_sv', JSON.stringify(arr)); } catch(e) {
        localStorage.removeItem('re_sv'); // 용량 초과 시 메모리만 사용
      }
    };

    // ─── re_sv (저장목록) 동기화 ─────────────────────────────
    window._sbSaveSv = async function(arr) {
      await tblSaveArr('items', arr);
      // 소프트삭제 항목 클라우드에서도 제거
      const deleted = (arr || []).filter(i => i.deletedAt).map(i => i.id);
      if (deleted.length) await tblDeleteItems('items', deleted);
      window._sbSyncStatus('☁️ 저장목록 동기화 완료', true);
    };
    window._sbLoadSv = async function() {
      return await tblLoadArr('items');
    };

    // ─── 노트 동기화 ─────────────────────────────────────────
    window._sbSaveNotes = async function(key, arr) {
      await kvSet('notes_' + key, arr);
    };
    window._sbSaveNtNotes = async function(arr) {
      await tblSaveArr('notes', arr);
      window._sbSyncStatus('☁️ 노트 동기화 완료', true);
    };
    window._sbLoadNtNotes = async function() { return await tblLoadArr('notes'); };

    // ─── 작업룸 동기화 ────────────────────────────────────────
    window._sbSaveRooms = async function(arr) {
      try {
        const active = (arr || []).filter(r => !r.deletedAt);
        const deleted = (arr || []).filter(r => r.deletedAt).map(r => r.id);
        await tblSaveArr('workrooms', active);
        if (deleted.length) await tblDeleteItems('workrooms', deleted);
        // 로컬 동기화
        const _orig = localStorage.setItem.bind(localStorage);
        _orig('wr2_rooms', JSON.stringify(active));
        if (window.wr2State) window.wr2State.rooms = active;
      } catch(e) { console.warn('[SB] saveRooms error', e); }
      window._sbSyncStatus('☁️ 작업룸 동기화 완료', true);
    };
    window._sbLoadRooms = async function() { return await tblLoadArr('workrooms'); };

    // 섹션은 kv_store에 통째로 저장 (섹션은 roomId 참조 구조라 개별 행 관리 복잡)
    window._sbSaveSections = async function(arr) {
      await kvSet('wr2_sections', arr);
    };
    window._sbLoadSections = async function() {
      const d = await kvGet('wr2_sections');
      return Array.isArray(d) ? d : null;
    };

    // ─── 작업씬(WorkScene) 동기화 ────────────────────────────
    window._sbSaveWorkScenes = async function(arr) {
      await tblSaveArr('snapshots', arr);
      window._sbSyncStatus('☁️ 작업씬 동기화 완료', true);
    };
    window._sbLoadWorkScenes = async function() { return await tblLoadArr('snapshots'); };

    // ─── ID 기반 merge: 두 배열을 id로 합치고 최신 updatedAt 우선 ───
    function _sbMergeById(cloud, local) {
      const map = new Map();
      (local || []).forEach(item => { if (item && item.id) map.set(item.id, item); });
      (cloud || []).forEach(item => {
        if (!item || !item.id) return;
        const existing = map.get(item.id);
        if (!existing) {
          if (!item.deletedAt) map.set(item.id, item);
          return;
        }
        const cTime = new Date(item.updatedAt || item.timestamp || 0).getTime();
        const lTime = new Date(existing.updatedAt || existing.timestamp || 0).getTime();
        if (cTime >= lTime) map.set(item.id, item);
      });
      return Array.from(map.values()).filter(item => !item.deletedAt);
    }

    // localStorage 안전 쓰기 (QuotaExceeded 시 해당 키만 skip)
    function _safeLocalSet(key, value) {
      try {
        localStorage.setItem(key, value);
      } catch(e) {
        console.warn('[SB] localStorage 용량 초과, 스킵:', key);
        localStorage.removeItem(key); // 공간 확보 시도
      }
    }

    window._sbInitLoad = async function() {
      try {
        const { data: { session } } = await window._sb.auth.getSession();
        if (!session) { window._sbShowLogin(); return; }
        _sbCachedUserId = session.user.id; // 캐시 즉시 세팅
        window._sbAddLogoutBtn();
        window._sbSyncStatus('☁️ 클라우드에서 불러오는 중...', true);

        // ── 저장목록 ──
        const svCloud = await window._sbLoadSv();
        if (svCloud !== null) {
          const svLocal = JSON.parse(localStorage.getItem('re_sv') || '[]');
          const merged = _sbMergeById(svCloud, svLocal);
          // 메모리 캐시에 저장 (localStorage 용량 초과 방지)
          window._svCache = merged;
          try { localStorage.setItem('re_sv', JSON.stringify(merged)); } catch(e) {
            localStorage.removeItem('re_sv');
          }
          if (merged.length > svCloud.length) window._sbSaveSv(merged).catch(()=>{});
        } else {
          const svLocal = JSON.parse(localStorage.getItem('re_sv') || '[]');
          window._svCache = svLocal;
          if (svLocal.length) window._sbSaveSv(svLocal).catch(()=>{});
        }

        // ── 노트 ──
        const ntCloud = await window._sbLoadNtNotes();
        if (ntCloud !== null) {
          const ntLocal = JSON.parse(localStorage.getItem('nt_notes') || '[]');
          const merged = _sbMergeById(ntCloud, ntLocal);
          _safeLocalSet('nt_notes', JSON.stringify(merged));
          if (merged.length > ntCloud.length) window._sbSaveNtNotes(merged).catch(()=>{});
        } else {
          const ntLocal = JSON.parse(localStorage.getItem('nt_notes') || '[]');
          if (ntLocal.length) window._sbSaveNtNotes(ntLocal).catch(()=>{});
        }

        // ── 작업룸 ──
        const roomsCloud = await window._sbLoadRooms();
        if (roomsCloud !== null) {
          const roomsLocal = JSON.parse(localStorage.getItem('wr2_rooms') || '[]');
          const merged = _sbMergeById(roomsCloud, roomsLocal);
          const mergedActive = merged.filter(r => !r.deletedAt);
          _safeLocalSet('wr2_rooms', JSON.stringify(mergedActive));
          if (window.wr2State) window.wr2State.rooms = mergedActive;
          if (mergedActive.length > roomsCloud.filter(r=>!r.deletedAt).length)
            window._sbSaveRooms(merged).catch(()=>{});
        } else {
          const roomsLocal = JSON.parse(localStorage.getItem('wr2_rooms') || '[]');
          if (roomsLocal.length) window._sbSaveRooms(roomsLocal).catch(()=>{});
        }

        // ── 섹션 ──
        const secCloud = await window._sbLoadSections();
        if (secCloud && secCloud.length > 0) {
          _safeLocalSet('wr2_sections', JSON.stringify(secCloud));
          if (window.wr2State) window.wr2State.sections = secCloud;
        } else {
          const secLocal = JSON.parse(localStorage.getItem('wr2_sections') || '[]');
          if (secLocal.length) {
            if (window.wr2State) window.wr2State.sections = secLocal;
            window._sbSaveSections(secLocal).catch(()=>{});
          }
        }

        // ── 작업씬 ──
        const wsCloud = await window._sbLoadWorkScenes();
        if (wsCloud !== null) {
          const wsLocal = JSON.parse(localStorage.getItem('re_ws') || '[]');
          const merged = _sbMergeById(wsCloud, wsLocal);
          _safeLocalSet('re_ws', JSON.stringify(merged));
          if (merged.length > wsCloud.length) window._sbSaveWorkScenes(merged).catch(()=>{});
        } else {
          const wsLocal = JSON.parse(localStorage.getItem('re_ws') || '[]');
          if (wsLocal.length) window._sbSaveWorkScenes(wsLocal).catch(()=>{});
        }

        // ── API 키 ──
        try {
          const apiKeys = ['g_api', 'kakao_api', 'kakao_rest_key', 'sbiz_api'];
          const cloud = await kvGet('api_keys');
          if (cloud) {
            apiKeys.forEach(k => { if (cloud[k]) localStorage.setItem(k, cloud[k]); });
            const mapping = { g_api:'apiKey', kakao_api:'kakaoApiKey', kakao_rest_key:'kakaoRestKey', sbiz_api:'sbizApiKey' };
            Object.entries(mapping).forEach(([lsKey, elId]) => {
              const el = document.getElementById(elId);
              const val = cloud[lsKey];
              if (el && val) { el.value = val; el.dispatchEvent(new Event('input')); }
            });
          } else {
            const payload = {};
            let hasAny = false;
            apiKeys.forEach(k => { const v = localStorage.getItem(k); if (v) { payload[k] = v; hasAny = true; } });
            if (hasAny) await kvSet('api_keys', payload);
          }
        } catch(e) { console.warn('[SB] API key sync error', e); }

        window._sbSyncStatus('✅ 클라우드 로드 완료', true);
      } catch(e) {
        console.warn('[SB] initLoad error', e);
        // QuotaExceededError는 네트워크 문제가 아니므로 오프라인 모드 표시 안 함
        if (e && e.name === 'QuotaExceededError') {
          window._sbSyncStatus('✅ 클라우드 로드 완료 (로컬저장 일부 생략)', true);
        } else {
          window._sbSyncStatus('⚠️ 오프라인 모드', false);
        }
      }
    };

    // API 키 변경 시 Supabase 자동 저장
    window._sbSaveApiKeys = async function() {
      try {
        const payload = {};
        ['g_api','kakao_api','kakao_rest_key','sbiz_api'].forEach(k => { const v = localStorage.getItem(k); if (v) payload[k] = v; });
        await kvSet('api_keys', payload);
      } catch(e) {}
    };

    // ─── localStorage.setItem 패치: 변경 시 자동 Supabase 동기화 ──
    (function() {
      const _origSet = localStorage.setItem.bind(localStorage);
      let _debounceRooms, _debounceSec, _debounceSv;
      localStorage.setItem = function(key, value) {
        _origSet(key, value);
        if (key === 'wr2_rooms') {
          clearTimeout(_debounceRooms);
          _debounceRooms = setTimeout(() => {
            try {
              const arr = JSON.parse(value);
              if (window._sbSaveRooms) window._sbSaveRooms(arr).catch(e=>{});
            } catch(e) {}
          }, 1500);
        }
        if (key === 'wr2_sections') {
          clearTimeout(_debounceSec);
          _debounceSec = setTimeout(() => {
            try {
              const arr = JSON.parse(value);
              if (window._sbSaveSections) window._sbSaveSections(arr).catch(e=>{});
            } catch(e) {}
          }, 1500);
        }
        if (key === 're_sv') {
          // 메모리 캐시도 동기 업데이트
          try { window._svCache = JSON.parse(value); } catch(e) {}
          clearTimeout(_debounceSv);
          _debounceSv = setTimeout(() => {
            try {
              const arr = JSON.parse(value);
              if (window._sbSaveSv) window._sbSaveSv(arr).catch(e=>{});
            } catch(e) {}
          }, 2000);
        }
      };
    })();



    // ─── 로그인 / 인증 ────────────────────────────────────────
    window._sbShowLogin = function() {
      const el = _sbEl('_sbLoginOverlay');
      if (el) el.style.display = 'flex';
      const err = _sbEl('_sbLoginErr');
      if (err) err.textContent = '';
      if (_sbIsRecoveryUrl()) window._sbHideRecovery && window._sbHideRecovery();
    };
    window._sbHideLogin = function() {
      const el = _sbEl('_sbLoginOverlay');
      if (el) el.style.display = 'none';
    };

    window._sbShowRecovery = function() {
      const overlay = _sbEl('_sbRecoveryOverlay');
      if (overlay) overlay.style.display = 'flex';
      const err = _sbEl('_sbRecoveryErr');
      if (err) err.textContent = '';
      const pw1 = _sbEl('_sbNewPw');
      const pw2 = _sbEl('_sbNewPw2');
      if (pw1) pw1.value = '';
      if (pw2) pw2.value = '';
      window._sbHideLogin();
    };
    window._sbHideRecovery = function() {
      const overlay = _sbEl('_sbRecoveryOverlay');
      if (overlay) overlay.style.display = 'none';
    };

    window._sbSendReset = async function() {
      const emailEl = _sbEl('_sbEmail');
      const errEl = _sbEl('_sbLoginErr');
      const email = emailEl ? emailEl.value.trim() : '';
      if (errEl) errEl.textContent = '';
      if (!email) {
        if (errEl) errEl.textContent = '비밀번호 재설정 메일을 받을 이메일을 먼저 입력해주세요.';
        return;
      }
      const btn = _sbEl('_sbForgotBtn');
      try {
        if (btn) { btn.disabled = true; btn.textContent = '메일 전송 중...'; }
        const { error } = await window._sb.auth.resetPasswordForEmail(email, {
          redirectTo: _sbGetRedirectUrl()
        });
        if (error) throw error;
        if (errEl) errEl.style.color = '#22c55e';
        if (errEl) errEl.textContent = '재설정 메일을 보냈어요. 최신 메일의 링크를 한 번만 열어주세요.';
      } catch(e) {
        if (errEl) errEl.style.color = '#f87171';
        if (errEl) errEl.textContent = '재설정 메일 전송 실패: ' + (e.message || '잠시 후 다시 시도');
      } finally {
        if (btn) { btn.disabled = false; btn.textContent = '비밀번호 재설정'; }
      }
    };

    window._sbLogin = async function() {
      const email = (_sbEl('_sbEmail') || { value: '' }).value.trim();
      const pw = (_sbEl('_sbPw') || { value: '' }).value.trim();
      const errEl = _sbEl('_sbLoginErr');
      if (errEl) { errEl.textContent = ''; errEl.style.color = '#f87171'; }
      if (!email || !pw) { if (errEl) errEl.textContent = '이메일과 비밀번호를 입력해주세요.'; return; }
      _sbSetLoginState(true, '로그인 중...');
      try {
        const { error } = await window._sb.auth.signInWithPassword({ email, password: pw });
        if (error) throw error;
        window._sbHideLogin();
        window._sbSyncStatus('✅ 로그인 완료', true);
        await window._sbInitLoad();
      } catch(e) {
        if (errEl) errEl.textContent = '로그인 실패: ' + (e.message || '이메일/비밀번호 확인');
      } finally {
        _sbSetLoginState(false, '로그인');
      }
    };

    window._sbApplyRecovery = async function() {
      const pw1 = (_sbEl('_sbNewPw') || { value: '' }).value.trim();
      const pw2 = (_sbEl('_sbNewPw2') || { value: '' }).value.trim();
      const errEl = _sbEl('_sbRecoveryErr');
      if (errEl) errEl.textContent = '';
      if (!pw1 || !pw2) { if (errEl) errEl.textContent = '새 비밀번호를 두 칸 모두 입력해주세요.'; return; }
      if (pw1.length < 6) { if (errEl) errEl.textContent = '비밀번호는 6자 이상으로 입력해주세요.'; return; }
      if (pw1 !== pw2) { if (errEl) errEl.textContent = '비밀번호 확인이 일치하지 않습니다.'; return; }
      _sbSetRecoveryState(true, '변경 중...');
      try {
        const { error } = await window._sb.auth.updateUser({ password: pw1 });
        if (error) throw error;
        _sbClearHash();
        window._sbHideRecovery();
        window._sbShowLogin();
        const loginErr = _sbEl('_sbLoginErr');
        if (loginErr) { loginErr.style.color = '#22c55e'; loginErr.textContent = '비밀번호가 변경됐어요. 새 비밀번호로 로그인해주세요.'; }
      } catch(e) {
        if (errEl) errEl.textContent = '비밀번호 변경 실패: ' + (e.message || '잠시 후 다시 시도');
      } finally {
        _sbSetRecoveryState(false, '비밀번호 변경');
      }
    };

    window._sbLogout = async function() {
      await window._sb.auth.signOut();
      _sbClearHash();
      window._sbHideRecovery();
      window._sbShowLogin();
    };

    window._sbInitRecoveryUI = async function() {
      try {
        if (!_sbIsRecoveryUrl()) return;
        const { data } = await window._sb.auth.getSession();
        if (data && data.session) {
          window._sbShowRecovery();
        }
      } catch(e) {
        console.warn('[SB] recovery ui init error', e);
      }
    };

    // 로그아웃 버튼 (우측 상단에 작게)
    window._sbAddLogoutBtn = function() {
      if (document.getElementById('_sbLogoutBtn')) return;
      const btn = document.createElement('button');
      btn.id = '_sbLogoutBtn';
      btn.textContent = '☁️ 로그아웃';
      btn.onclick = window._sbLogout;
      btn.style.cssText = 'position:fixed;top:8px;right:8px;z-index:99998;background:rgba(30,35,55,0.85);color:#94a3b8;border:1px solid #334;border-radius:8px;padding:4px 10px;font-size:11px;cursor:pointer;';
      document.body.appendChild(btn);
    };

    // DOM 로드 후 초기화
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', function() {
        window._sbInitRecoveryUI && window._sbInitRecoveryUI();
        window._sbInitLoad();
      });
    } else {
      setTimeout(function() {
        window._sbInitRecoveryUI && window._sbInitRecoveryUI();
        window._sbInitLoad();
      }, 500);
    }

  })();

/* ════════════════════════════════════════════════════════
   블록3: WorkRoom JS (HTML 내부)
════════════════════════════════════════════════════════ */
              (function () {
                const LS_KEY_ROOMS = 'wr2_rooms';
                const LS_KEY_SECTIONS = 'wr2_sections';

                let wr2State = {
                  rooms: [],
                  sections: [],
                  activeRoomId: null,
                  activePhase: 'interest',
                  sort: 'updated',
                  search: '',
                  statusFilter: 'all'
                };

                function safeJSONParse(raw, fallback) {
                  try { return raw ? JSON.parse(raw) : fallback; } catch (e) { return fallback; }
                }

                function loadRooms() { wr2State.rooms = safeJSONParse(localStorage.getItem(LS_KEY_ROOMS), []); }
                function saveRooms() {
                  // 렌더링용 rooms는 deletedAt 포함 유지, 로컬 저장·Supabase는 deletedAt 없는 것만
                  const toSave = wr2State.rooms.filter(r => !r.deletedAt);
                  localStorage.setItem(LS_KEY_ROOMS, JSON.stringify(toSave));
                  // 소프트삭제 정보는 Supabase에만 전달 (deletedAt 포함 전달해야 다기기 삭제 동기화)
                  if (window._sbSaveRooms) window._sbSaveRooms(wr2State.rooms).catch(e => {});
                }
                function loadSections() { wr2State.sections = safeJSONParse(localStorage.getItem(LS_KEY_SECTIONS), []); }
                function saveSections() { localStorage.setItem(LS_KEY_SECTIONS, JSON.stringify(wr2State.sections)); }

                function genId(prefix) { return prefix + '_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 7); }
                function getActiveRoom() { return wr2State.rooms.find(r => r.id === wr2State.activeRoomId) || null; }

                function statusLabel(st) {
                  if (st === 'interest') return '관심';
                  if (st === 'review') return '검토';
                  if (st === 'field') return '현장';
                  if (st === 'bid') return '입찰';
                  if (st === 'won') return '낙찰';
                  if (st === 'sell') return '매도';
                  if (st === 'closed') return '종료';
                  return '미정';
                }

                function phaseHint(phase) {
                  const map = {
                    interest: '관심 단계: 빠르게 후보를 모으고, “왜 이 물건인가/아닌가”를 적는 구간',
                    review: '검토 단계: 권리·임대차·공실·수익률·리스크를 구조적으로 정리하는 구간',
                    field: '현장 단계: 현황/임차인/주변/동선/하자/민원 등 “눈으로 본 사실”을 남기는 구간',
                    bid: '입찰 단계: 서류·보증금·대리·입찰가 전략 등 실수를 막는 체크 중심 구간',
                    won: '낙찰 단계: 잔금·명도·대출·세금·인허가 등 실행/정리 구간',
                    sell: '매도 단계: 매도 전략·가격·광고·협상 기록을 쌓는 구간'
                  };
                  return map[phase] || '';
                }

                function setActiveRoom(id) {
                  wr2State.activeRoomId = id;
                  const r = getActiveRoom();
                  if (r && r.phase) wr2State.activePhase = r.phase;
                  wr2Render();
                }

                function updateRoom(id, patch, silentRender) {
                  const idx = wr2State.rooms.findIndex(r => r.id === id);
                  if (idx === -1) return;
                  wr2State.rooms[idx] = Object.assign({}, wr2State.rooms[idx], patch, { updatedAt: Date.now() });
                  saveRooms();
                  if (!silentRender) wr2Render();
                }

                function defaultSectionTitle(type) {
                  if (type === 'memo') return '노트';
                  if (type === 'checklist') return '체크리스트';
                  if (type === 'metrics') return '메트릭';
                  if (type === 'log') return '로그';
                  return '섹션';
                }
                function defaultSectionData(type) {
                  if (type === 'memo') return { content: '' };
                  if (type === 'checklist') return { items: [] };
                  if (type === 'metrics') return { rows: [] };
                  if (type === 'log') return { entries: [] };
                  return {};
                }
                function nextSectionOrder(roomId, phase) {
                  const list = wr2State.sections.filter(s => s.roomId === roomId && s.phase === phase);
                  if (!list.length) return 1;
                  return Math.max.apply(null, list.map(s => s.order || 1)) + 1;
                }

                function createSection(phase, type, title, dataOverride) {
                  const room = getActiveRoom();
                  if (!room) return;
                  const sec = {
                    id: genId('sec'),
                    roomId: room.id,
                    type,
                    phase,
                    title: title || defaultSectionTitle(type),
                    order: nextSectionOrder(room.id, phase),
                    data: Object.assign(defaultSectionData(type), dataOverride || {})
                  };
                  wr2State.sections.push(sec);
                  saveSections();
                }

                function seedDefaults(roomId) {
                  // roomId is active at creation time; still pass for safety
                  const r = wr2State.rooms.find(x => x.id === roomId);
                  if (!r) return;
                  wr2State.activeRoomId = roomId;

                  const mkChecklist = (phase, title, items) => {
                    createSection(phase, 'checklist', title, { items: (items || []).map(t => ({ id: genId('chk'), text: t, done: false })) });
                  };
                  const mkMemo = (phase, title, content) => createSection(phase, 'memo', title, { content: content || '' });
                  const mkMetrics = (phase, title, rows) => createSection(phase, 'metrics', title, { rows: (rows || []).map(r => ({ label: r[0], value: r[1] })) });
                  const mkLog = (phase, title) => createSection(phase, 'log', title, { entries: [] });

                  // 👀 관심
                  mkMemo('interest', '1) 관심 이유', '• 한 줄 결론\n• 내가 관심 갖는 이유\n• 가장 큰 리스크 1개');
                  mkChecklist('interest', '관심 체크', ['위치/입지 확인', '용도·업종 적합성', '경쟁 물건 비교', '대략적 수익 시뮬레이션']);
                  // 🔍 검토
                  mkChecklist('review', '2) 서류/권리/임대차', ['등기부등본 확인', '건축물대장 확인', '토지이용계획 확인', '임대차/점유 조사', '선순위/말소기준 검토', '명도 난이도 가늠']);
                  mkMetrics('review', '3) 수익/가격 시나리오', [['예상낙찰가(하)', ''], ['예상낙찰가(상)', ''], ['보증금', ''], ['월세', ''], ['연 순수익(추정)', ''], ['목표 수익률(%)', '']]);
                  mkMemo('review', '검토 메모', '• 권리 특이사항\n• AI 분석 결과 요약\n• 추가 확인 필요 사항');
                  // 📍 현장
                  mkMemo('field', '4) 현장 메모', '• 건물/호실 상태\n• 임차인/관리인 대화\n• 주변 상권/동선\n• 사진/영상 링크(필요 시)');
                  mkLog('field', '현장/통화 로그');
                  // 🎯 입찰
                  mkChecklist('bid', '5) 입찰 준비', ['입찰가 최종 확정', '보증금 준비', '입찰 서류 준비', '대리인/위임장 여부 확인', '입찰 장소/시간 확인']);
                  mkMemo('bid', '입찰 전략 메모', '• 최고 입찰 한도\n• 경쟁 예상\n• 특이사항');
                  // ✅ 낙찰
                  mkChecklist('won', '6) 낙찰 후 실행', ['대금지급기한 확인', '잔금/대출 실행', '인도/명도 계획', '세금/취득 신고', '필요 시 인허가/용도 검토']);
                  mkMemo('won', '낙찰 메모', '• 낙찰가\n• 잔금 일정\n• 명도 계획');
                  // 💰 매도
                  mkMemo('sell', '7) 매도 전략', '• 희망가/최저가\n• 광고/중개 전략\n• 협상 룰\n• 일정(목표 매도일)');
                  mkLog('sell', '매도/협상 로그');

                  saveSections();
                  wr2State.activePhase = r.phase || 'interest';
                }

                function createRoomFromModal() {
                  const title = document.getElementById('wr2NewTitle').value.trim();
                  const address = document.getElementById('wr2NewAddress').value.trim();
                  const auctionId = document.getElementById('wr2NewAuctionId').value.trim();
                  const listingId = document.getElementById('wr2NewListingId').value.trim();
                  const tagsStr = document.getElementById('wr2NewTags').value.trim();
                  const seed = document.getElementById('wr2NewSeedDefaults').checked;

                  if (!title) { alert('제목을 입력해주세요.'); return; }

                  const now = Date.now();
                  const room = {
                    id: genId('room'),
                    title,
                    address,
                    auctionId: auctionId || null,
                    listingId: listingId || null,
                    status: 'interest',
                    phase: 'interest',
                    tags: tagsStr ? tagsStr.split(',').map(t => t.trim()).filter(Boolean) : [],
                    createdAt: now,
                    updatedAt: now
                  };

                  wr2State.rooms.push(room);
                  saveRooms();

                  hideNewModal();

                  wr2State.activeRoomId = room.id;
                  wr2State.activePhase = room.phase;

                  if (seed) seedDefaults(room.id);

                  wr2Render();
                }

                function deleteRoom(id) {
                  if (!confirm('이 작업룸을 삭제할까요? 삭제 후 모든 기기에서 제거됩니다.')) return;
                  // 소프트 삭제: deletedAt 표시 후 클라우드 동기화
                  const roomIdx = wr2State.rooms.findIndex(r => r.id === id);
                  if (roomIdx !== -1) {
                    wr2State.rooms[roomIdx].deletedAt = Date.now();
                    wr2State.rooms[roomIdx].updatedAt = Date.now();
                  }
                  // 렌더링에선 deletedAt 있는 룸 제외
                  wr2State.sections = wr2State.sections.filter(s => s.roomId !== id);
                  saveRooms(); saveSections();
                  if (wr2State.activeRoomId === id) wr2State.activeRoomId = null;
                  wr2Render();
                }

                function updateSection(id, patch) {
                  const idx = wr2State.sections.findIndex(s => s.id === id);
                  if (idx === -1) return;
                  wr2State.sections[idx] = Object.assign({}, wr2State.sections[idx], patch);
                  saveSections();
                  wr2Render();
                }

                function deleteSection(id) {
                  if (!confirm('이 섹션을 삭제할까요?')) return;
                  wr2State.sections = wr2State.sections.filter(s => s.id !== id);
                  saveSections();
                  wr2Render();
                }

                function addChecklistItem(secId) {
                  const sec = wr2State.sections.find(s => s.id === secId);
                  if (!sec || sec.type !== 'checklist') return;
                  if (!sec.data.items) sec.data.items = [];
                  sec.data.items.push({ id: genId('chk'), text: '', done: false });
                  saveSections();
                  wr2Render();
                }

                function toggleChecklistDone(secId, itemId, done) {
                  const sec = wr2State.sections.find(s => s.id === secId);
                  if (!sec || sec.type !== 'checklist' || !sec.data.items) return;
                  sec.data.items = sec.data.items.map(it => it.id === itemId ? Object.assign({}, it, { done }) : it);
                  saveSections();
                  wr2Render();
                }

                function updateChecklistText(secId, itemId, textVal) {
                  const sec = wr2State.sections.find(s => s.id === secId);
                  if (!sec || sec.type !== 'checklist' || !sec.data.items) return;
                  sec.data.items = sec.data.items.map(it => it.id === itemId ? Object.assign({}, it, { text: textVal }) : it);
                  saveSections();
                }

                function addLogEntry(secId, textVal) {
                  const sec = wr2State.sections.find(s => s.id === secId);
                  if (!sec || sec.type !== 'log') return;
                  if (!sec.data.entries) sec.data.entries = [];
                  const t = (textVal || '').trim();
                  if (!t) return;
                  sec.data.entries.unshift({ id: genId('log'), at: Date.now(), text: t });
                  saveSections();
                  wr2Render();
                }

                function formatDateTime(ts) {
                  const d = new Date(ts);
                  const y = d.getFullYear();
                  const m = ('0' + (d.getMonth() + 1)).slice(-2);
                  const da = ('0' + d.getDate()).slice(-2);
                  const hh = ('0' + d.getHours()).slice(-2);
                  const mm = ('0' + d.getMinutes()).slice(-2);
                  return y + '-' + m + '-' + da + ' ' + hh + ':' + mm;
                }

                // RENDER
                function wr2Render() {
                  renderList();
                  renderDetail();
                }
                window.wr2Render = wr2Render;
                window.wr2State = wr2State; // 전역 노출 (스냅샷 브리지용)

                // ── 대시보드 수익률 계산기 ──────────────────────────
                let _wr2CalcTarget = 'price'; // 기본: 매매가를 구함

                window.wr2SetTarget = function (field) {
                  _wr2CalcTarget = field;
                  ['price', 'deposit', 'rent', 'yield'].forEach(f => {
                    const btn = document.getElementById('wc_t_' + f);
                    if (btn) btn.classList.toggle('active', f === field);
                    const inp = document.getElementById('wc_' + f);
                    if (inp) inp.style.background = f === field ? 'rgba(255,209,102,.08)' : '';
                  });
                  wr2RunCalc(null);
                };

                window.wr2RunCalc = function (changed) {
                  const parse = id => parseFloat((document.getElementById(id) || { value: '' }).value.replace(/[^0-9.]/g, '')) || 0;
                  const price = parse('wc_price');
                  const deposit = parse('wc_deposit');
                  const rent = parse('wc_rent');
                  const yld = parseFloat((document.getElementById('wc_yield') || { value: '' }).value) || 0;

                  let calcVal = null, mainHtml = '', subHtml = '', rows = [];

                  const fmt = n => Math.round(n).toLocaleString() + '원';
                  const fmtY = n => n.toFixed(2) + '%';

                  if (_wr2CalcTarget === 'price' && deposit >= 0 && rent > 0 && yld > 0) {
                    calcVal = rent * 12 / (yld / 100) + deposit;
                    mainHtml = '매매가 <b style="color:#4f8eff;font-size:15px;">' + fmt(calcVal) + '</b>';
                    rows = [['실투입금', fmt(calcVal - deposit)], ['연 임대수익', fmt(rent * 12)]];
                    const el = document.getElementById('wc_price'); if (el && changed !== 'price') el.value = Math.round(calcVal).toLocaleString();
                  } else if (_wr2CalcTarget === 'yield' && price > 0 && rent > 0) {
                    calcVal = rent * 12 / (price - deposit) * 100;
                    mainHtml = '수익률 <b style="color:#ffd166;font-size:15px;">' + fmtY(calcVal) + '</b>';
                    rows = [['실투입금', fmt(price - deposit)], ['연 임대수익', fmt(rent * 12)]];
                    const el = document.getElementById('wc_yield'); if (el && changed !== 'yield') el.value = calcVal.toFixed(2);
                  } else if (_wr2CalcTarget === 'rent' && price > 0 && yld > 0) {
                    calcVal = (price - deposit) * yld / 100 / 12;
                    mainHtml = '월세 <b style="color:#4ade80;font-size:15px;">' + fmt(calcVal) + '/월</b>';
                    rows = [['연 임대수익', fmt(calcVal * 12)], ['실투입금', fmt(price - deposit)]];
                    const el = document.getElementById('wc_rent'); if (el && changed !== 'rent') el.value = Math.round(calcVal).toLocaleString();
                  } else if (_wr2CalcTarget === 'deposit' && price > 0 && rent > 0 && yld > 0) {
                    calcVal = price - rent * 12 / (yld / 100);
                    mainHtml = '보증금 <b style="color:#a78bfa;font-size:15px;">' + fmt(calcVal) + '</b>';
                    rows = [['실투입금', fmt(price - calcVal)], ['연 임대수익', fmt(rent * 12)]];
                    const el = document.getElementById('wc_deposit'); if (el && changed !== 'deposit') el.value = Math.round(calcVal).toLocaleString();
                  }

                  const resEl = document.getElementById('wc_result');
                  if (resEl && calcVal !== null) {
                    resEl.style.display = '';
                    resEl.innerHTML = '<div class="wr2-calc-result-main">' + mainHtml + '</div>' +
                      rows.map(([l, v]) => `<div class="wr2-calc-result-row"><span>${l}</span><span>${v}</span></div>`).join('');
                  } else if (resEl) resEl.style.display = 'none';

                  // 수익률%별 매매가 테이블
                  const tblEl = document.getElementById('wc_table');
                  const curRent = parse('wc_rent'), curDep = parse('wc_deposit');
                  if (tblEl && curRent > 0) {
                    const rates = [4, 5, 6, 7, 8, 10];
                    const curYld = parse('wc_yield') || (_wr2CalcTarget === 'yield' && calcVal ? calcVal : 0);
                    tblEl.style.display = '';
                    tblEl.innerHTML = '<div class="wr2-yield-table-title">수익률별 매매가</div>' +
                      rates.map(r => {
                        const p = Math.round(curRent * 12 / (r / 100) + curDep);
                        const near = Math.abs(curYld - r) < 0.5;
                        return `<div class="wr2-yield-row${near ? ' highlight' : ''}"><span>${r}%</span><span>${p.toLocaleString()}원</span></div>`;
                      }).join('');
                  } else if (tblEl) tblEl.style.display = 'none';

                  // 계산 상태 저장
                  const room = getActiveRoom();
                  if (room) {
                    room.calcState = {
                      price: (document.getElementById('wc_price') || {}).value || '',
                      deposit: (document.getElementById('wc_deposit') || {}).value || '',
                      rent: (document.getElementById('wc_rent') || {}).value || '',
                      yield: (document.getElementById('wc_yield') || {}).value || '',
                      target: _wr2CalcTarget
                    };
                    clearTimeout(window._wr2CalcSaveTimer);
                    window._wr2CalcSaveTimer = setTimeout(() => { room.updatedAt = Date.now(); saveRooms(); }, 800);
                  }
                };

                window.wr2CalcClear = function () {
                  ['wc_price', 'wc_deposit', 'wc_rent', 'wc_yield'].forEach(id => {
                    const el = document.getElementById(id); if (el) el.value = '';
                  });
                  const resEl = document.getElementById('wc_result'); if (resEl) resEl.style.display = 'none';
                  const tblEl = document.getElementById('wc_table'); if (tblEl) tblEl.style.display = 'none';
                  const room = getActiveRoom();
                  if (room) { room.calcState = null; saveRooms(); }
                };

                function renderList() {
                  const listEl = document.getElementById('wr2RoomList');
                  const emptyEl = document.getElementById('wr2ListEmpty');
                  const countEl = document.getElementById('wr2RoomCount');
                  if (!listEl || !emptyEl) return;

                  let rooms = wr2State.rooms.filter(r => !r.deletedAt);
                  const q = (wr2State.search || '').trim().toLowerCase();
                  if (q) rooms = rooms.filter(r =>
                    (r.title || '').toLowerCase().includes(q) ||
                    (r.address || '').toLowerCase().includes(q) ||
                    (r.tags || []).some(t => (t || '').toLowerCase().includes(q))
                  );
                  if (wr2State.statusFilter !== 'all') rooms = rooms.filter(r => r.status === wr2State.statusFilter);
                  rooms.sort((a, b) => wr2State.sort === 'created' ? (b.createdAt || 0) - (a.createdAt || 0) : (b.updatedAt || 0) - (a.updatedAt || 0));

                  listEl.innerHTML = '';
                  rooms.forEach(r => {
                    const item = document.createElement('div');
                    item.className = 'wr2-room-item' + (r.id === wr2State.activeRoomId ? ' active' : '');
                    item.dataset.id = r.id;
                    item.draggable = true;

                    // 드래그 핸들
                    const handle = document.createElement('span');
                    handle.className = 'wr2-room-drag-handle';
                    handle.textContent = '⠿';
                    handle.title = '드래그하여 순서 변경';

                    // 콘텐츠
                    const content = document.createElement('div');
                    content.className = 'wr2-room-item-content';
                    content.onclick = () => setActiveRoom(r.id);

                    const title = document.createElement('div');
                    title.className = 'wr2-room-title';
                    title.textContent = r.title || '(제목 없음)';

                    const meta = document.createElement('div');
                    meta.className = 'wr2-room-meta';
                    const badge = document.createElement('span');
                    badge.className = 'wr2-status-badge ' + (r.status || 'interest');
                    badge.textContent = statusLabel(r.status);
                    meta.appendChild(badge);
                    if (r.address) {
                      const addr = document.createElement('span');
                      addr.textContent = r.address.length > 16 ? r.address.slice(0, 16) + '…' : r.address;
                      meta.appendChild(addr);
                    }
                    const updated = document.createElement('span');
                    updated.textContent = '수정 ' + (r.updatedAt ? formatDateTime(r.updatedAt) : '-');
                    meta.appendChild(updated);
                    content.appendChild(title);
                    content.appendChild(meta);

                    // 액션 버튼
                    const actions = document.createElement('div');
                    actions.className = 'wr2-room-item-actions';

                    const renameBtn = document.createElement('button');
                    renameBtn.className = 'wr2-room-act-btn';
                    renameBtn.textContent = '✏';
                    renameBtn.title = '이름 변경';
                    renameBtn.onclick = e => {
                      e.stopPropagation();
                      const newTitle = prompt('새 이름:', r.title || '');
                      if (newTitle !== null && newTitle.trim()) {
                        updateRoom(r.id, { title: newTitle.trim() });
                      }
                    };

                    const delBtn = document.createElement('button');
                    delBtn.className = 'wr2-room-act-btn del';
                    delBtn.textContent = '✕';
                    delBtn.title = '삭제';
                    delBtn.onclick = e => { e.stopPropagation(); deleteRoom(r.id); };

                    actions.appendChild(renameBtn);
                    actions.appendChild(delBtn);

                    item.appendChild(handle);
                    item.appendChild(content);
                    item.appendChild(actions);
                    listEl.appendChild(item);
                  });

                  initListDrag(listEl);
                  if (countEl) countEl.textContent = '(' + wr2State.rooms.length + ')';
                  emptyEl.style.display = rooms.length ? 'none' : 'flex';
                }

                // 목록 드래그 앤 드롭 순서변경
                function initListDrag(listEl) {
                  let dragId = null;
                  listEl.querySelectorAll('.wr2-room-item').forEach(el => {
                    el.addEventListener('dragstart', e => {
                      dragId = el.dataset.id;
                      el.classList.add('dragging');
                      e.dataTransfer.effectAllowed = 'move';
                    });
                    el.addEventListener('dragend', () => {
                      el.classList.remove('dragging');
                      listEl.querySelectorAll('.wr2-room-item').forEach(e => e.classList.remove('drag-over'));
                    });
                    el.addEventListener('dragover', e => {
                      e.preventDefault();
                      if (el.dataset.id !== dragId) {
                        listEl.querySelectorAll('.wr2-room-item').forEach(e => e.classList.remove('drag-over'));
                        el.classList.add('drag-over');
                      }
                    });
                    el.addEventListener('drop', e => {
                      e.preventDefault();
                      const targetId = el.dataset.id;
                      if (!dragId || dragId === targetId) return;
                      // 순서 교환
                      const arr = wr2State.rooms;
                      const fi = arr.findIndex(r => r.id === dragId);
                      const ti = arr.findIndex(r => r.id === targetId);
                      if (fi < 0 || ti < 0) return;
                      const [moved] = arr.splice(fi, 1);
                      arr.splice(ti, 0, moved);
                      saveRooms(); wr2Render();
                    });
                  });
                }

                function renderDetail() {
                  const emptyEl = document.getElementById('wr2DetailEmpty');
                  const detailEl = document.getElementById('wr2Detail');
                  const room = getActiveRoom();
                  if (!emptyEl || !detailEl) return;

                  if (!room) {
                    emptyEl.style.display = 'flex';
                    detailEl.style.display = 'none';
                    return;
                  }
                  emptyEl.style.display = 'none';
                  detailEl.style.display = 'flex';

                  // 헤더바 값 바인딩
                  const titleInput = document.getElementById('wr2Title');
                  const addrInput = document.getElementById('wr2Address');
                  const statusSel = document.getElementById('wr2Status');
                  const auctionIn = document.getElementById('wr2AuctionId');
                  const listingIn = document.getElementById('wr2ListingId');
                  if (titleInput) titleInput.value = room.title || '';
                  if (addrInput) addrInput.value = room.address || '';
                  if (statusSel) statusSel.value = room.status || 'interest';
                  if (auctionIn) auctionIn.value = room.auctionId || '';
                  if (listingIn) listingIn.value = room.listingId || '';

                  renderPhaseTabs(room);
                  renderDashboard(room);
                  renderSections(room);
                  renderTimeline(room);
                }

                // ── 단계 탭 + 개요 탭 렌더 ──────────────────────────
                function renderPhaseTabs(room) {
                  const el = document.getElementById('wr2PhaseTabs');
                  if (!el) return;
                  const phases = [
                    { id: 'interest', label: '👀 관심' },
                    { id: 'review', label: '🔍 검토' },
                    { id: 'field', label: '📍 현장' },
                    { id: 'bid', label: '🎯 입찰' },
                    { id: 'won', label: '✅ 낙찰' },
                    { id: 'sell', label: '💰 매도' }
                  ];
                  if (!wr2State.activePhase) wr2State.activePhase = room.phase || 'interest';

                  // 개요 탭 버튼 (항상 첫 번째)
                  if (!document.getElementById('wr2OverviewTabBtn')) {
                    const bar = el.parentElement; // .wr2-phase-tabs
                    const overviewBtn = document.createElement('button');
                    overviewBtn.id = 'wr2OverviewTabBtn';
                    overviewBtn.className = 'wr2-overview-tab' + (wr2State.activeView === 'overview' || !wr2State.activeView ? ' active' : '');
                    overviewBtn.textContent = '📊 개요';
                    overviewBtn.onclick = () => wr2SwitchView('overview');
                    bar.insertBefore(overviewBtn, el);
                    // 구분선
                    const sep = document.createElement('div');
                    sep.style.cssText = 'width:1px;background:var(--b1);margin:6px 4px;align-self:stretch;';
                    bar.insertBefore(sep, el);
                  } else {
                    const btn = document.getElementById('wr2OverviewTabBtn');
                    btn.className = 'wr2-overview-tab' + (wr2State.activeView === 'overview' || !wr2State.activeView ? ' active' : '');
                  }

                  el.innerHTML = '';
                  const PHASE_ORDER = ['interest','review','field','bid','won','sell'];
                  const curStatus = typeof _migrateStatus === 'function' ? _migrateStatus(room.status || 'interest') : (room.status || 'interest');
                  const curIdx = PHASE_ORDER.indexOf(curStatus);

                  phases.forEach(p => {
                    const pIdx = PHASE_ORDER.indexOf(p.id);
                    const isActive = wr2State.activeView === 'phase' && wr2State.activePhase === p.id;
                    // sell 탭은 won 이후면 항상 열림, 나머지는 현재 status 이하만 활성
                    const isLocked = pIdx > curIdx && p.id !== 'sell';
                    const btn = document.createElement('button');
                    btn.className = 'wr2-phase-tab' + (isActive ? ' active' : '') + (isLocked ? ' locked' : '');
                    btn.dataset.phase = p.id;
                    btn.textContent = p.label;
                    btn.title = isLocked ? `현재 단계(${(UNIFIED_STATUS[curStatus]||{}).label||curStatus})를 먼저 완료하세요` : '';
                    btn.onclick = () => {
                      if (isLocked) {
                        // 잠긴 탭: 승급 confirm
                        const targetLabel = (UNIFIED_STATUS[p.id]||{}).label || p.label;
                        const curLabel = (UNIFIED_STATUS[curStatus]||{}).label || curStatus;
                        if (!confirm(`"${targetLabel}" 단계로 이동할까요?
(현재 "${curLabel}" → "${targetLabel}"로 status가 변경됩니다)`)) return;
                        // 승급 처리
                        room.status = p.id;
                        const sel = document.getElementById('wr2Status');
                        if (sel) sel.value = p.id;
                        if (typeof window.wrDbUpdateStatus === 'function') window.wrDbUpdateStatus(room.id, p.id);
                      }
                      wr2State.activePhase = p.id;
                      wr2State.activeView = 'phase';
                      const validStatusPhases = ['interest','review','field','bid','won'];
                      const patch = { phase: p.id };
                      if (validStatusPhases.indexOf(p.id) >= 0 && !isLocked) {
                        patch.status = p.id;
                        const sel = document.getElementById('wr2Status');
                        if (sel) sel.value = p.id;
                        if (typeof window.wrDbUpdateStatus === 'function') window.wrDbUpdateStatus(room.id, p.id);
                      } else if (isLocked) {
                        patch.status = p.id;
                      }
                      updateRoom(room.id, patch);
                      // 탭 잠금 상태 즉시 갱신
                      renderPhaseTabs(room);
                      wr2SwitchView('phase');
                    };
                    el.appendChild(btn);
                  });
                }

                function wr2SwitchView(view) {
                  wr2State.activeView = view;
                  const overview = document.getElementById('wr2TabOverview');
                  const phase = document.getElementById('wr2TabPhase');
                  const ovBtn = document.getElementById('wr2OverviewTabBtn');
                  if (overview) overview.classList.toggle('active', view === 'overview');
                  if (phase) phase.classList.toggle('active', view === 'phase');
                  if (ovBtn) ovBtn.className = 'wr2-overview-tab' + (view === 'overview' ? ' active' : '');
                  // phase 탭 버튼 active 상태 업데이트
                  document.querySelectorAll('#wr2PhaseTabs .wr2-phase-tab').forEach(btn => {
                    btn.classList.toggle('active', view === 'phase' && btn.textContent.includes(
                      ({ interest: '관심', review: '검토', field: '현장', bid: '입찰', won: '낙찰', sell: '매도' })[wr2State.activePhase] || ''
                    ));
                  });
                  if (view === 'phase') {
                    const hint = document.getElementById('wr2PhaseHint');
                    if (hint) hint.textContent = phaseHint(wr2State.activePhase);
                  }
                }
                window.wr2SwitchView = wr2SwitchView;

                // ── 대시보드 렌더 ────────────────────────────────────
                function renderDashboard(room) {
                  renderCaptureWidget(room);
                  renderSnapList(room);
                  renderItemSummary(room);
                  renderChecklistWidget(room);
                  renderNoteWidget(room);
                  renderCalcWidget(room);
                }

                // ── 지도 캡처 위젯 ──────────────────────────────────
                // 마이그레이션: 단일 captureImage → captureImages 배열
                function migrateCaptures(room) {
                  if (!room.captureImages) room.captureImages = [];
                  if (room.captureImage && !room._migrated) {
                    room.captureImages.unshift({ src: room.captureImage, savedAt: room.updatedAt || Date.now(), snapName: null });
                    delete room.captureImage;
                    room._migrated = true;
                    saveRooms();
                  }
                }

                function renderCaptureWidget(room) {
                  migrateCaptures(room);
                  var body = document.getElementById('wr2CaptureBody');
                  if (!body) return;
                  var imgs = room.captureImages || [];
                  if (imgs.length) {
                    var gridHtml = '<div class="wr2-img-grid">';
                    imgs.forEach(function(img, i) {
                      var snapLabel = img.snapName ? '<div class="wr2-img-snap-label">📷 ' + img.snapName + '</div>' : '';
                      var goBtn = img.snapName ? '<button class="wr2-img-go-map" onclick="event.stopPropagation();wr2GoToSnap(this.dataset.snap)" data-snap="' + img.snapName.replace(/"/g,'&quot;') + '" title="이 스냅샷으로 지도 이동">🗺 지도로</button>' : '';
                      gridHtml += '<div class="wr2-img-thumb" onclick="wr2Lightbox(' + i + ')">'
                        + '<img src="' + img.src + '" alt="캡처 ' + (i+1) + '">'
                        + '<div class="wr2-img-overlay"><span class="wr2-img-zoom">🔍</span>' + snapLabel + '</div>'
                        + goBtn
                        + '<button class="wr2-img-del" onclick="event.stopPropagation();wr2DeleteCaptureAt(' + i + ')">✕</button>'
                        + '</div>';
                    });
                    gridHtml += '<div class="wr2-img-add" onclick="wr2CaptureMap()" title="새 캡처 추가">＋<br><span style="font-size:9px;">캡처</span></div>';
                    gridHtml += '</div>';
                    body.innerHTML = gridHtml;
                  renderSnapList(room);
                  } else {
                    body.innerHTML = '<div class="wr2-capture-drop" id="wr2CaptureDrop">'
                      + '<div class="wr2-capture-drop-icon" style="font-size:20px;">🖼</div>'
                      + '<div class="wr2-capture-drop-txt">이미지가 없습니다<br/><span style="color:#4f8eff;cursor:pointer;" onclick="captureMapScreen()">📷 지도 캡처</span>하거나 이미지를 드래그/업로드하세요</div>'
                      + '</div>';
                    initCaptureDrop();
                  }
                  renderSnapList(room);
                }

                window.wr2Lightbox = function(startIdx) {
                  var room = getActiveRoom(); if (!room) return;
                  migrateCaptures(room);
                  var imgs = room.captureImages || [];
                  if (!imgs.length) return;
                  var cur = startIdx || 0;
                  var overlay = document.createElement('div');
                  overlay.id = 'wr2LightboxOverlay';
                  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.88);z-index:99999;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;';

                  function renderLb() {
                    var img = imgs[cur];
                    var snapBtn = img.snapName
                      ? '<button id="wr2LbSnapBtn" style="padding:6px 14px;background:rgba(79,142,255,.2);border:1px solid rgba(79,142,255,.5);border-radius:7px;color:#4f8eff;font-size:12px;cursor:pointer;font-family:inherit;">🗺 이 스냅샷으로 지도 이동</button>'
                      : '';
                    var prevBtn = imgs.length > 1 ? '<button id="wr2LbPrevBtn" style="position:absolute;left:-44px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,.1);border:none;color:#fff;font-size:22px;padding:8px 12px;border-radius:8px;cursor:pointer;">&#8249;</button>' : '';
                    var nextBtn = imgs.length > 1 ? '<button id="wr2LbNextBtn" style="position:absolute;right:-44px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,.1);border:none;color:#fff;font-size:22px;padding:8px 12px;border-radius:8px;cursor:pointer;">&#8250;</button>' : '';
                    overlay.innerHTML = '<div style="position:relative;max-width:90vw;max-height:75vh;">'
                      + '<img src="' + img.src + '" style="max-width:90vw;max-height:75vh;border-radius:10px;object-fit:contain;display:block;">'
                      + prevBtn + nextBtn
                      + '</div>'
                      + '<div style="display:flex;gap:8px;align-items:center;">'
                      + '<span style="color:#aaa;font-size:12px;">' + (cur+1) + ' / ' + imgs.length + (img.snapName ? ' · 📷 ' + img.snapName : '') + '</span>'
                      + snapBtn
                      + '</div>'
                      + '<button id="wr2LbClose" style="position:fixed;top:16px;right:20px;background:none;border:none;color:#fff;font-size:24px;cursor:pointer;padding:6px;">✕</button>';

                    var closeBtn = overlay.querySelector('#wr2LbClose');
                    if (closeBtn) closeBtn.onclick = function() { overlay.remove(); document.removeEventListener('keydown', onKey); };
                    var prevB = overlay.querySelector('#wr2LbPrevBtn');
                    if (prevB) prevB.onclick = function() { cur = (cur - 1 + imgs.length) % imgs.length; renderLb(); };
                    var nextB = overlay.querySelector('#wr2LbNextBtn');
                    if (nextB) nextB.onclick = function() { cur = (cur + 1) % imgs.length; renderLb(); };
                    var snapB = overlay.querySelector('#wr2LbSnapBtn');
                    if (snapB) {
                      var sn = img.snapName;
                      snapB.onclick = function() { overlay.remove(); document.removeEventListener('keydown', onKey); wr2GoToSnap(sn); };
                    }
                  }

                  function onKey(e) {
                    if (e.key === 'Escape' || e.key === ' ') { e.preventDefault(); overlay.remove(); document.removeEventListener('keydown', onKey); }
                    if (e.key === 'ArrowLeft') { e.preventDefault(); cur = (cur - 1 + imgs.length) % imgs.length; renderLb(); }
                    if (e.key === 'ArrowRight') { e.preventDefault(); cur = (cur + 1) % imgs.length; renderLb(); }
                  }

                  renderLb();
                  document.body.appendChild(overlay);
                  overlay.addEventListener('click', function(e) { if (e.target === overlay) { overlay.remove(); document.removeEventListener('keydown', onKey); } });
                  document.addEventListener('keydown', onKey);
                };

                window.wr2DeleteCaptureAt = function(idx) {
                  var room = getActiveRoom(); if (!room) return;
                  migrateCaptures(room);
                  if (!confirm('이 캡처 이미지를 삭제할까요?')) return;
                  room.captureImages.splice(idx, 1);
                  room.updatedAt = Date.now();
                  saveRooms(); renderCaptureWidget(room);
                };

                window.wr2GoToSnap = function(snapName) {
                  if (typeof swLoadSnap === 'function') {
                    showPage(2);
                    setTimeout(function() { swLoadSnap(snapName, null); }, 300);
                  } else { showToast('스냅샷을 찾을 수 없습니다', 'warn'); }
                };

                // 스냅샷 목록 렌더 (작업룸 캡처 위젯 하단)
                function renderSnapList(room) {
                  var el = document.getElementById('wr2SnapList');
                  if (!el) return;
                  var restoreBtn = document.getElementById('wr2RestoreMapBtn');

                  // mapScene 있으면 복원 버튼 강조
                  if (restoreBtn) {
                    var hasScene = room && (room.mapScene || (room.mapScenes && room.mapScenes.length));
                    if (hasScene) {
                      restoreBtn.style.display = '';
                      restoreBtn.style.color = '#4f8eff';
                    } else {
                      restoreBtn.style.display = 'none';
                    }
                  }

                  // 이미지에서 snapName 수집
                  var imgs = (room && room.captureImages) || [];
                  var snapNames = [];
                  imgs.forEach(function(img) { if (img.snapName && snapNames.indexOf(img.snapName) === -1) snapNames.push(img.snapName); });

                  // mapScenes 배열의 모든 sceneName 포함 (배열 없으면 mapScene 단일로 fallback)
                  var sceneData = room && room.mapScene;
                  var allMapScenes = (room && room.mapScenes && room.mapScenes.length) ? room.mapScenes : (sceneData ? [sceneData] : []);
                  allMapScenes.forEach(function(ms) {
                    if (ms.sceneName && snapNames.indexOf(ms.sceneName) === -1) snapNames.unshift(ms.sceneName);
                    if (ms.children) {
                      ms.children.forEach(function(ch) {
                        if (ch.name && snapNames.indexOf(ch.name) === -1) snapNames.push(ch.name);
                      });
                    }
                  });

                  if (!snapNames.length) {
                    el.innerHTML = '<div style="font-size:10px;color:var(--di);padding:4px 0;">연결된 스냅샷 없음 · 지도탭에서 캡처하면 자동 연결됩니다</div>';
                    return;
                  }

                  var scenes = typeof getWorkScenes === 'function' ? getWorkScenes() : [];
                  var html = '';

                  // 캡처 이미지에 연결된 스냅샷들 (부모-자식 트리 구조)
                  snapNames.forEach(function(sn) {
                    var sc = scenes.find(function(s){ return s.name === sn; });
                    var imgCount = imgs.filter(function(i){ return i.snapName === sn; }).length;
                    var exists = !!sc;
                    var isChild = sc && sc.parentName;
                    var parentName = sc ? sc.parentName : null;
                    // 부모 스냅샷인 경우 자식 목록 수집
                    var children = exists && !isChild ? scenes.filter(function(s){ return s.parentName === sn; }) : [];
                    var indent = isChild ? 'margin-left:16px;' : '';
                    var prefix = isChild ? '<span style="color:var(--di);font-size:9px;margin-right:4px;">ㄴ</span>' : '';
                    html += '<div style="' + indent + 'display:flex;align-items:center;gap:6px;padding:4px 7px;background:var(--s2);border:1px solid var(--b1);border-radius:6px;margin-bottom:3px;">';
                    html += '<span style="font-size:11px;">' + prefix + (exists ? '📷' : '🔸') + '</span>';
                    html += '<div style="flex:1;min-width:0;">';
                    html += '<div style="font-size:10px;font-weight:600;color:' + (exists ? 'var(--tx)' : 'var(--di)') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + sn + (exists ? '' : ' <span style="font-size:8px;color:var(--di);">(삭제됨)</span>') + '</div>';
                    html += '<div style="font-size:9px;color:var(--di);">';
                    if (isChild && parentName) html += '↑ ' + parentName + ' · ';
                    html += '이미지 ' + imgCount + '장' + (children.length ? ' · 하위 ' + children.length + '개' : '') + '</div>';
                    html += '</div>';
                    if (exists) {
                      html += '<button onclick="wr2GoToSnap(this.dataset.snap)" data-snap="' + sn.replace(/"/g,'&quot;') + '" style="padding:3px 8px;font-size:10px;background:rgba(79,142,255,.1);border:1px solid rgba(79,142,255,.3);border-radius:5px;color:#4f8eff;cursor:pointer;font-family:inherit;white-space:nowrap;">↗ 이동</button>';
                    }
                    html += '</div>';
                    // 자식 스냅샷이 있으면 하위 목록도 표시
                    if (children.length) {
                      children.forEach(function(child) {
                        var childImgCount = imgs.filter(function(i){ return i.snapName === child.name; }).length;
                        var childExists = scenes.some(function(s){ return s.name === child.name; });
                        html += '<div style="margin-left:16px;display:flex;align-items:center;gap:6px;padding:4px 7px;background:var(--s2);border:1px solid var(--b1);border-radius:6px;margin-bottom:3px;">';
                        html += '<span style="color:var(--di);font-size:9px;margin-right:2px;">ㄴ</span><span style="font-size:11px;">📷</span>';
                        html += '<div style="flex:1;min-width:0;"><div style="font-size:10px;font-weight:600;color:var(--tx);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + child.name + '</div>';
                        html += '<div style="font-size:9px;color:var(--di);">↑ ' + sn + (childImgCount ? ' · 이미지 ' + childImgCount + '장' : '') + '</div>';
                        html += '</div>';
                        if (childExists) html += '<button onclick="wr2GoToSnap(this.dataset.snap)" data-snap="' + child.name.replace(/"/g,'&quot;') + '" style="padding:3px 8px;font-size:10px;background:rgba(79,142,255,.1);border:1px solid rgba(79,142,255,.3);border-radius:5px;color:#4f8eff;cursor:pointer;font-family:inherit;white-space:nowrap;">↗ 이동</button>';
                        html += '</div>';
                      });
                    }
                  });

                  el.innerHTML = html || '<div style="font-size:10px;color:var(--di);">연결된 스냅샷 없음</div>';
                }
                function initCaptureDrop() {
                  const drop = document.getElementById('wr2CaptureDrop');
                  if (!drop) return;
                  drop.addEventListener('dragover', e => { e.preventDefault(); drop.classList.add('drag-over'); });
                  drop.addEventListener('dragleave', () => drop.classList.remove('drag-over'));
                  drop.addEventListener('drop', e => {
                    e.preventDefault(); drop.classList.remove('drag-over');
                    const file = e.dataTransfer.files[0];
                    if (file && file.type.startsWith('image/')) wr2LoadCaptureFile(file);
                  });
                  drop.addEventListener('click', () => {
                    const inp = document.createElement('input');
                    inp.type = 'file'; inp.accept = 'image/*';
                    inp.onchange = () => { if (inp.files[0]) wr2LoadCaptureFile(inp.files[0]); };
                    inp.click();
                  });
                }

                window.wr2UploadCapture = function (input) {
                  if (input.files[0]) wr2LoadCaptureFile(input.files[0]);
                };
                function wr2LoadCaptureFile(file) {
                  const r = new FileReader();
                  r.onload = e => {
                    const room = getActiveRoom(); if (!room) return;
                    migrateCaptures(room);
                    const _snapName = window._lastLoadedSnap || null;
                    if (!room.captureImages) room.captureImages = [];
                    room.captureImages.push({ src: e.target.result, savedAt: Date.now(), snapName: _snapName });
                    room.updatedAt = Date.now();
                    saveRooms(); renderCaptureWidget(room);
                  };
                  r.readAsDataURL(file);
                }
                window.wr2DeleteCapture = function () {
                  // 하위호환: 전체 삭제
                  const room = getActiveRoom(); if (!room) return;
                  if (!confirm('모든 캡처 이미지를 삭제할까요?')) return;
                  room.captureImages = []; delete room.captureImage;
                  room.updatedAt = Date.now();
                  saveRooms(); renderCaptureWidget(room);
                };
                window.wr2CaptureMap = function () {
                  // html2canvas 방식 (카카오맵 타일 제한으로 부분 캡처)
                  const mapEl = document.getElementById('map');
                  if (!mapEl) { showToast('지도를 먼저 불러오세요', 'warn'); return; }
                  if (typeof html2canvas !== 'undefined') {
                    showToast('지도 캡처 중...', 'info');
                    html2canvas(mapEl, { useCORS: true, scale: 1 }).then(canvas => {
                      // CORS 체크: 실제 이미지 데이터가 있는지 확인
                      const testCtx = canvas.getContext('2d');
                      const px = testCtx ? testCtx.getImageData(canvas.width>>1, canvas.height>>1, 1, 1).data : null;
                      const isBlank = !px || (px[0]===0 && px[1]===0 && px[2]===0 && px[3]===0);
                      if (isBlank) { showToast('⚠️ 카카오맵 CORS 제한으로 자동 캡처 불가. 지도탭 📷 버튼을 이용하세요', 'warn'); return; }
                      const room = getActiveRoom(); if (!room) return;
                      migrateCaptures(room);
                      const _snapName = window._lastLoadedSnap || null;
                      if (!room.captureImages) room.captureImages = [];
                      room.captureImages.push({ src: canvas.toDataURL('image/jpeg', 0.85), savedAt: Date.now(), snapName: _snapName });
                      room.updatedAt = Date.now();
                      saveRooms(); renderCaptureWidget(room);
                      showToast('📸 캡처 저장됨' + (_snapName ? ' (📷 ' + _snapName + ')' : ''), 'ok');
                    }).catch(() => showToast('캡처 실패. 직접 업로드를 이용하세요.', 'warn'));
                  } else {
                    // html2canvas 없으면 canvas로 직접 시도
                    try {
                      const canvas = document.createElement('canvas');
                      canvas.width = mapEl.offsetWidth; canvas.height = mapEl.offsetHeight;
                      const ctx = canvas.getContext('2d');
                      ctx.fillStyle = '#1a1f2e'; ctx.fillRect(0, 0, canvas.width, canvas.height);
                      ctx.fillStyle = '#4f8eff'; ctx.font = '14px sans-serif';
                      ctx.textAlign = 'center';
                      ctx.fillText('지도 캡처 (html2canvas 없음)', canvas.width / 2, canvas.height / 2);
                      const room = getActiveRoom(); if (!room) return;
                      room.captureImage = canvas.toDataURL();
                      room.updatedAt = Date.now();
                      saveRooms(); renderCaptureWidget(room);
                      showToast('지도 탭에서 직접 스크린샷 후 [직접 업로드]를 이용하세요', 'warn');
                    } catch (e) { showToast('캡처 실패. 직접 업로드를 이용하세요.', 'warn'); }
                  }
                };

                // ── 물건 요약 (저장목록 연결) ──────────────────────
                function renderItemSummary(room) {
                  const el = document.getElementById('wr2ItemSummary');
                  const openBtn = document.getElementById('wr2OpenSavedBtn');
                  if (!el) return;
                  const sv = (typeof getSv === 'function') ? getSv() : (() => { try { return JSON.parse(localStorage.getItem('re_sv') || '[]'); } catch (e) { return []; } })();
                  const linkedId = room.linkedSavedId || room.auctionId;
                  const item = linkedId ? sv.find(s => String(s.id) === String(linkedId)) : null;

                  if (openBtn) openBtn.style.display = item ? '' : 'none';
                  if (openBtn && item) {
                    openBtn.onclick = () => { if (typeof openPopup === 'function') openPopup(item.id); };
                  }

                  if (!item) {
                    el.innerHTML = '<div class="wr2-no-item">연결된 물건이 없습니다.<br/><span style="color:#4f8eff;cursor:pointer;" onclick="document.getElementById(\'wr2LinkSavedBtn\').click()">🔗 물건연결</span> 버튼으로 저장목록과 연결하세요.</div>';
                    return;
                  }
                  const d = item.data || {};
                  const fmt = v => v ? Number(String(v).replace(/[^0-9]/g, '')).toLocaleString() + '원' : '-';
                  const rows = [
                    ['소재지', d['소재지'] || d['주소'] || room.address || '-'],
                    ['물건종류', d['물건종류'] || d['type'] || d['용도'] || '-'],
                    ['감정가', d['감정가'] ? fmt(d['감정가']) : '-'],
                    ['최저가', d['최저가'] ? `<span class="wr2-info-highlight">${fmt(d['최저가'])}</span>` : '-'],
                    ['전용면적', d['전용면적'] || d['면적'] || d['전용면적_m2'] ? (d['전용면적_m2'] || d['면적'] || '') + '㎡' : '-'],
                    ['사건번호', d['사건번호'] || d['caseNo'] || item.id || '-'],
                  ].filter(([, v]) => v && v !== '-');
                  el.innerHTML = rows.map(([l, v]) =>
                    `<div class="wr2-info-row"><span class="wr2-info-lbl">${l}</span><span class="wr2-info-val">${v}</span></div>`
                  ).join('') || '<div class="wr2-no-item">연결된 물건 정보가 없습니다.</div>';
                }

                // ── 저장목록 연결 모달 ──────────────────────────────
                window.wr2ShowLinkModal = function () {
                  if (document.getElementById('wr2LinkModal')) return;
                  const sv = ((typeof getSv === 'function') ? getSv() : []).filter(s => (s.mode || '') === 'auction');
                  const modal = document.createElement('div');
                  modal.id = 'wr2LinkModal';
                  modal.innerHTML = `
                    <div class="wr2-lm-inner">
                      <div class="wr2-lm-hd">🔗 저장목록 물건 연결
                        <button onclick="document.getElementById('wr2LinkModal').remove()" style="background:none;border:none;color:var(--mu);font-size:16px;cursor:pointer;">✕</button>
                      </div>
                      <div class="wr2-lm-search"><input id="wr2LmSearch" placeholder="🔍 물건 검색..." oninput="wr2FilterLmList(this.value)"></div>
                      <div class="wr2-lm-list" id="wr2LmList"></div>
                    </div>`;
                  document.body.appendChild(modal);
                  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
                  wr2RenderLmList(sv, '');
                  setTimeout(() => document.getElementById('wr2LmSearch')?.focus(), 50);
                };

                window.wr2FilterLmList = function (q) {
                  const sv = ((typeof getSv === 'function') ? getSv() : []).filter(s => (s.mode || '') === 'auction');
                  wr2RenderLmList(sv, q);
                };
                function wr2RenderLmList(sv, q) {
                  const el = document.getElementById('wr2LmList'); if (!el) return;
                  const lower = q.toLowerCase();
                  const filtered = q ? sv.filter(s => {
                    const d = s.data || {};
                    return [s.title, d['소재지'], d['주소'], d['사건번호'], String(s.id)].some(v => v && String(v).toLowerCase().includes(lower));
                  }) : sv;
                  if (!filtered.length) { el.innerHTML = '<div style="padding:20px;text-align:center;font-size:12px;color:var(--mu);">검색 결과가 없습니다</div>'; return; }
                  el.innerHTML = filtered.slice(0, 50).map(s => {
                    const d = s.data || {};
                    const title = s.title || d['소재지'] || d['주소'] || '(이름없음)';
                    const meta = [d['물건종류'] || d['용도'], d['감정가'] ? Number(String(d['감정가']).replace(/[^0-9]/g, '')).toLocaleString() + '원' : ''].filter(Boolean).join(' · ');
                    return `<div class="wr2-lm-item" onclick="wr2LinkSaved('${s.id}')">
                      <div class="wr2-lm-item-title">${title}</div>
                      <div class="wr2-lm-item-meta">${meta || String(s.id)}</div>
                    </div>`;
                  }).join('');
                }
                window.wr2LinkSaved = function (savedId) {
                  const room = getActiveRoom(); if (!room) return;
                  const sv = (typeof getSv === 'function') ? getSv() : [];
                  const item = sv.find(s => String(s.id) === String(savedId));
                  if (!item) return;
                  room.linkedSavedId = String(savedId);
                  // 주소/제목 자동 채움
                  const d = item.data || {};
                  if (!room.address || room.address === '') {
                    room.address = d['소재지'] || d['주소'] || d['도로명주소'] || '';
                    const addrEl = document.getElementById('wr2Address');
                    if (addrEl) addrEl.value = room.address;
                  }
                  if (!room.title || room.title === '새 작업룸') {
                    room.title = item.title || d['소재지'] || '';
                    const titleEl = document.getElementById('wr2Title');
                    if (titleEl) titleEl.value = room.title;
                  }
                  room.updatedAt = Date.now();
                  saveRooms();
                  document.getElementById('wr2LinkModal')?.remove();
                  renderItemSummary(room);
                  showToast('✅ 물건 연결 완료', 'ok');
                };

                // ── 체크리스트 위젯 ──────────────────────────────────
                const DEFAULT_CHECKLIST = [
                  { group: '권리분석', items: ['말소기준권리 확인', '인수되는 권리 확인', '가처분·가압류 확인', '배당요구 종기일 확인'] },
                  { group: '임차관계', items: ['임차인 현황 파악', '대항력 여부 확인', '전입세대 열람', '확정일자 확인'] },
                  { group: '현장', items: ['현장 방문 완료', '실거주 여부 확인', '건물 상태 확인', '주변 임대시세 조사'] },
                  { group: '입찰준비', items: ['감정평가서 열람', '매각물건명세서 확인', '등기부등본 최신본', '입찰 보증금 준비'] },
                ];

                function getChecklist(room) {
                  if (!room.checklist) {
                    room.checklist = DEFAULT_CHECKLIST.map(g => ({
                      group: g.group,
                      items: g.items.map(txt => ({ id: genId('cl'), txt, done: false }))
                    }));
                  }
                  return room.checklist;
                }

                function renderChecklistWidget(room) {
                  const el = document.getElementById('wr2ChecklistBody'); if (!el) return;
                  const cl = getChecklist(room);
                  el.innerHTML = cl.map((g, gi) => {
                    const done = g.items.filter(i => i.done).length;
                    return `<div class="wr2-cl-group">
                      <div class="wr2-cl-group-title">
                        <span>${g.group}</span>
                        <span style="margin-left:auto;display:flex;align-items:center;gap:6px;">
                          <button onclick="wr2AddCheckItem(${gi})" style="background:none;border:none;color:var(--ac);font-size:11px;cursor:pointer;padding:0 2px;font-family:inherit;opacity:.7;" title="이 그룹에 항목 추가">＋</button>
                          <span class="wr2-cl-progress">${done}/${g.items.length}</span>
                        </span>
                      </div>
                      ${g.items.map((item, ii) => `
                        <div class="wr2-cl-item">
                          <input type="checkbox" ${item.done ? 'checked' : ''} onchange="wr2ClToggle(${gi},${ii},this.checked)">
                          <input class="wr2-cl-item-txt${item.done ? ' done' : ''}" value="${item.txt.replace(/"/g, '&quot;')}" onchange="wr2ClEdit(${gi},${ii},this.value)" onblur="wr2ClEdit(${gi},${ii},this.value)">
                          <button class="wr2-cl-item-del" onclick="wr2ClDel(${gi},${ii})">✕</button>
                        </div>`).join('')}
                    </div>`;
                  }).join('');
                }

                window.wr2ClToggle = function (gi, ii, val) {
                  const room = getActiveRoom(); if (!room) return;
                  getChecklist(room)[gi].items[ii].done = val;
                  room.updatedAt = Date.now(); saveRooms(); renderChecklistWidget(room);
                };
                window.wr2ClEdit = function (gi, ii, val) {
                  const room = getActiveRoom(); if (!room) return;
                  getChecklist(room)[gi].items[ii].txt = val;
                  room.updatedAt = Date.now(); saveRooms();
                };
                window.wr2ClDel = function (gi, ii) {
                  const room = getActiveRoom(); if (!room) return;
                  getChecklist(room)[gi].items.splice(ii, 1);
                  room.updatedAt = Date.now(); saveRooms(); renderChecklistWidget(room);
                };
                window.wr2AddCheckItem = function (gi) {
                  const room = getActiveRoom(); if (!room) return;
                  const cl = getChecklist(room);
                  const txt = prompt('새 항목 이름:', '');
                  if (!txt || !txt.trim()) return;
                  // gi가 지정되면 해당 그룹에, 아니면 마지막 그룹에 추가
                  if (typeof gi === 'number' && gi >= 0 && gi < cl.length) {
                    cl[gi].items.push({ id: genId('cl'), txt: txt.trim(), done: false });
                  } else {
                    if (!cl.length) cl.push({ group: '기타', items: [] });
                    cl[cl.length - 1].items.push({ id: genId('cl'), txt: txt.trim(), done: false });
                  }
                  room.updatedAt = Date.now(); saveRooms(); renderChecklistWidget(room);
                };
                window.wr2ResetChecklist = function () {
                  const room = getActiveRoom(); if (!room) return;
                  if (!confirm('체크리스트를 기본값으로 초기화할까요?')) return;
                  delete room.checklist; room.updatedAt = Date.now();
                  saveRooms(); renderChecklistWidget(room);
                };

                // 노트 위젯: textarea 값 바인딩 (저장은 debounce)
                let _noteTimer = null;
                let _activeNoteId = null;

                // 기존 room.note → room.notes 마이그레이션
                function migrateRoomNote(room) {
                  if (room.note && (!room.notes || !room.notes.length)) {
                    room.notes = [{ id: 'note_' + Date.now(), title: '노트 1', body: room.note, createdAt: Date.now() }];
                    delete room.note;
                    saveRooms();
                  }
                  if (!room.notes) room.notes = [];
                }

                function renderNoteWidget(room) {
                  migrateRoomNote(room);
                  _renderNoteList(room);
                  // 첫 노트 또는 현재 활성 노트 선택
                  const notes = room.notes || [];
                  const target = (_activeNoteId && notes.find(n => n.id === _activeNoteId)) || notes[0] || null;
                  _renderNoteEditor(room, target ? target.id : null);
                  renderAttachments(room);
                }

                function _renderNoteList(room) {
                  const listEl = document.getElementById('wr2NoteList');
                  if (!listEl) return;
                  const notes = room.notes || [];
                  listEl.innerHTML = notes.map(n => {
                    const isActive = n.id === _activeNoteId;
                    const border = isActive ? 'rgba(79,142,255,.6)' : 'var(--b1)';
                    const bg = isActive ? 'rgba(79,142,255,.12)' : 'var(--s2)';
                    const clr = isActive ? '#4f8eff' : 'var(--tx)';
                    return '<div onclick="wr2NoteSelect(\'' + n.id + '\')" style="display:flex;align-items:center;gap:4px;padding:4px 8px;border-radius:6px;font-size:11px;cursor:pointer;border:1px solid ' + border + ';background:' + bg + ';color:' + clr + ';white-space:nowrap;">'
                      + '<span>' + (n.title || '노트') + '</span>'
                      + '<span onclick="event.stopPropagation();wr2NoteDel(\'' + n.id + '\')" style="color:var(--mu);font-size:10px;margin-left:2px;padding:0 2px;">✕</span>'
                      + '</div>';
                  }).join('');
                }

                function _renderNoteEditor(room, noteId) {
                  const ta = document.getElementById('wr2NoteText');
                  if (!ta) return;
                  const notes = room.notes || [];
                  const note = noteId ? notes.find(n => n.id === noteId) : null;
                  _activeNoteId = note ? note.id : null;
                  ta.value = note ? (note.body || '') : '';
                  ta.placeholder = note ? '내용을 입력하세요...' : '＋ 노트 버튼으로 새 노트를 추가하세요';
                  ta.disabled = !note;
                  ta.oninput = () => {
                    clearTimeout(_noteTimer);
                    _noteTimer = setTimeout(() => {
                      const r = getActiveRoom();
                      if (!r || !_activeNoteId) return;
                      const n = (r.notes || []).find(x => x.id === _activeNoteId);
                      if (n) { n.body = ta.value; n.updatedAt = Date.now(); r.updatedAt = Date.now(); saveRooms(); }
                    }, 500);
                  };
                  // 제목 더블클릭으로 변경
                  ta.ondblclick = null;
                  _renderNoteList(room);
                }

                window.wr2NoteAdd = function() {
                  const room = getActiveRoom(); if (!room) return;
                  migrateRoomNote(room);
                  const idx = (room.notes.length || 0) + 1;
                  const note = { id: 'note_' + Date.now().toString(36), title: '노트 ' + idx, body: '', createdAt: Date.now() };
                  room.notes.push(note);
                  room.updatedAt = Date.now();
                  saveRooms();
                  _activeNoteId = note.id;
                  renderNoteWidget(room);
                  document.getElementById('wr2NoteText') && document.getElementById('wr2NoteText').focus();
                };

                window.wr2NoteSelect = function(noteId) {
                  const room = getActiveRoom(); if (!room) return;
                  _activeNoteId = noteId;
                  _renderNoteEditor(room, noteId);
                };

                window.wr2NoteDel = function(noteId) {
                  const room = getActiveRoom(); if (!room) return;
                  if (room.notes.length <= 1 && !confirm('마지막 노트를 삭제할까요?')) return;
                  room.notes = room.notes.filter(n => n.id !== noteId);
                  if (_activeNoteId === noteId) _activeNoteId = room.notes[0]?.id || null;
                  room.updatedAt = Date.now();
                  saveRooms();
                  renderNoteWidget(room);
                };

                function renderAttachments(room) {
                  const el = document.getElementById('wr2Attachments');
                  if (!el) return;
                  const files = room.attachments || [];
                  el.innerHTML = files.map((f, i) => {
                    if (f.type === 'image') {
                      return `<div class="wr2-attach-item"><img class="wr2-attach-img" src="${f.data}" title="${f.name}"><button class="wr2-attach-del" onclick="wr2DelAttach(${i})">✕</button></div>`;
                    }
                    return `<div class="wr2-attach-item"><div class="wr2-attach-file">📎 ${f.name}</div><button class="wr2-attach-del" onclick="wr2DelAttach(${i})">✕</button></div>`;
                  }).join('');
                }

                window.wr2DelAttach = function (idx) {
                  const room = getActiveRoom(); if (!room || !room.attachments) return;
                  room.attachments.splice(idx, 1);
                  room.updatedAt = Date.now();
                  saveRooms(); renderAttachments(room);
                };

                // 수익률 계산기 위젯 (초기값 없이 그냥 유지 — 별도 상태관리)
                function renderCalcWidget(room) {
                  // 물건 정보에서 자동 주입 (비어있을 때만)
                  const priceEl = document.getElementById('wc_price');
                  if (priceEl && !priceEl.value && room.calcState) {
                    const s = room.calcState;
                    if (document.getElementById('wc_price')) document.getElementById('wc_price').value = s.price || '';
                    if (document.getElementById('wc_deposit')) document.getElementById('wc_deposit').value = s.deposit || '';
                    if (document.getElementById('wc_rent')) document.getElementById('wc_rent').value = s.rent || '';
                    if (document.getElementById('wc_yield')) document.getElementById('wc_yield').value = s.yield || '';
                    if (s.target) wr2SetTarget(s.target);
                  }
                }

                // 지도 복원/저장
                window.wr2RestoreMap = function () {
                  const room = getActiveRoom(); if (!room) return;
                  if (typeof wrOpenMapScene === 'function') wrOpenMapScene(room.id);
                  else showToast('지도 복원 기능을 찾을 수 없습니다', 'warn');
                };
                window.wr2SaveCurrentMap = function () {
                  const room = getActiveRoom(); if (!room) return;
                  if (typeof wrUpdateCurrentRoom === 'function') wrUpdateCurrentRoom(room.id);
                  else showToast('지도 저장 기능을 찾을 수 없습니다', 'warn');
                };

                function renderSections(room) {
                  const el = document.getElementById('wr2Sections');
                  if (!el) return;

                  const list = wr2State.sections
                    .filter(s => s.roomId === room.id && s.phase === wr2State.activePhase)
                    .slice()
                    .sort((a, b) => (a.order || 1) - (b.order || 1));

                  el.innerHTML = '';

                  list.forEach(sec => {
                    const card = document.createElement('div');
                    card.className = 'wr2-section-card';

                    const hd = document.createElement('div');
                    hd.className = 'wr2-section-hd';

                    const titleSpan = document.createElement('span');
                    titleSpan.textContent = sec.title || defaultSectionTitle(sec.type);
                    hd.appendChild(titleSpan);

                    const hdRight = document.createElement('div');
                    hdRight.className = 'wr2-section-hd-right';

                    const renameBtn = document.createElement('button');
                    renameBtn.textContent = '이름';
                    renameBtn.className = 'wr2-small-btn';
                    renameBtn.onclick = () => {
                      const nv = prompt('섹션 이름을 입력하세요', sec.title || '');
                      if (nv !== null) updateSection(sec.id, { title: (nv.trim() || sec.title) });
                    };

                    const upBtn = document.createElement('button');
                    upBtn.textContent = '▲';
                    upBtn.className = 'wr2-small-btn';
                    upBtn.onclick = () => moveSection(sec.id, -1);

                    const downBtn = document.createElement('button');
                    downBtn.textContent = '▼';
                    downBtn.className = 'wr2-small-btn';
                    downBtn.onclick = () => moveSection(sec.id, +1);

                    const delBtn = document.createElement('button');
                    delBtn.textContent = '삭제';
                    delBtn.className = 'wr2-small-btn';
                    delBtn.onclick = () => deleteSection(sec.id);

                    hdRight.appendChild(renameBtn);
                    hdRight.appendChild(upBtn);
                    hdRight.appendChild(downBtn);
                    hdRight.appendChild(delBtn);
                    hd.appendChild(hdRight);

                    const body = document.createElement('div');
                    body.className = 'wr2-section-body';

                    if (sec.type === 'memo') {
                      const ta = document.createElement('textarea');
                      ta.className = 'wr2-memo-textarea';
                      ta.value = (sec.data && sec.data.content) || '';
                      ta.oninput = (e) => {
                        sec.data = sec.data || {};
                        sec.data.content = e.target.value;
                        saveSections();
                      };
                      body.appendChild(ta);
                    } else if (sec.type === 'checklist') {
                      const btnRow = document.createElement('div');
                      btnRow.style.marginBottom = '6px';

                      const addBtn = document.createElement('button');
                      addBtn.textContent = '+ 항목';
                      addBtn.className = 'wr2-small-btn';
                      addBtn.onclick = () => addChecklistItem(sec.id);

                      const prog = document.createElement('span');
                      prog.style.marginLeft = '8px';
                      prog.style.fontSize = '10px';
                      prog.style.color = 'var(--mu)';
                      const total = (sec.data.items || []).length;
                      const done = (sec.data.items || []).filter(it => it.done).length;
                      prog.textContent = total ? ('완료 ' + done + '/' + total) : '항목 0개';

                      btnRow.appendChild(addBtn);
                      btnRow.appendChild(prog);
                      body.appendChild(btnRow);

                      const listWrap = document.createElement('div');
                      (sec.data.items || []).forEach(it => {
                        const row = document.createElement('div');
                        row.className = 'wr2-checklist-item' + (it.done ? ' done' : '');

                        const cb = document.createElement('input');
                        cb.type = 'checkbox';
                        cb.checked = !!it.done;
                        cb.onchange = (e) => toggleChecklistDone(sec.id, it.id, e.target.checked);

                        const txt = document.createElement('input');
                        txt.type = 'text';
                        txt.value = it.text || '';
                        txt.oninput = (e) => updateChecklistText(sec.id, it.id, e.target.value);

                        const rm = document.createElement('button');
                        rm.textContent = '✕';
                        rm.className = 'wr2-small-btn';
                        rm.style.padding = '2px 6px';
                        rm.onclick = () => {
                          sec.data.items = (sec.data.items || []).filter(x => x.id !== it.id);
                          saveSections();
                          wr2Render();
                        };

                        row.appendChild(cb);
                        row.appendChild(txt);
                        row.appendChild(rm);
                        listWrap.appendChild(row);
                      });

                      body.appendChild(listWrap);
                    } else if (sec.type === 'metrics') {
                      const table = document.createElement('table');
                      table.className = 'wr2-metrics-table';

                      (sec.data.rows || []).forEach((rowData, idx) => {
                        const tr = document.createElement('tr');
                        const tdLabel = document.createElement('td');
                        const tdVal = document.createElement('td');

                        const inLabel = document.createElement('input');
                        inLabel.value = rowData.label || '';
                        inLabel.oninput = (e) => { rowData.label = e.target.value; saveSections(); };

                        const inVal = document.createElement('input');
                        inVal.value = rowData.value || '';
                        inVal.oninput = (e) => { rowData.value = e.target.value; saveSections(); };

                        tdLabel.appendChild(inLabel);
                        tdVal.appendChild(inVal);

                        tr.appendChild(tdLabel);
                        tr.appendChild(tdVal);
                        table.appendChild(tr);
                      });

                      const addRowBtn = document.createElement('button');
                      addRowBtn.textContent = '+ 행 추가';
                      addRowBtn.className = 'wr2-small-btn';
                      addRowBtn.style.marginTop = '6px';
                      addRowBtn.onclick = () => {
                        if (!sec.data.rows) sec.data.rows = [];
                        sec.data.rows.push({ label: '', value: '' });
                        saveSections();
                        wr2Render();
                      };

                      body.appendChild(table);
                      body.appendChild(addRowBtn);
                    } else if (sec.type === 'log') {
                      const inputWrap = document.createElement('div');
                      inputWrap.style.marginBottom = '6px';

                      const logInput = document.createElement('input');
                      logInput.type = 'text';
                      logInput.placeholder = '로그를 입력하고 Enter';
                      logInput.style.width = '100%';
                      logInput.onkeydown = (e) => {
                        if (e.key === 'Enter') {
                          addLogEntry(sec.id, e.target.value);
                          e.target.value = '';
                        }
                      };

                      inputWrap.appendChild(logInput);
                      body.appendChild(inputWrap);

                      const listEl = document.createElement('div');
                      listEl.className = 'wr2-log-list';

                      (sec.data.entries || []).forEach(ent => {
                        const item = document.createElement('div');
                        item.className = 'wr2-log-item';

                        const meta = document.createElement('div');
                        meta.className = 'wr2-log-meta';
                        meta.textContent = formatDateTime(ent.at);

                        const textEl = document.createElement('div');
                        textEl.className = 'wr2-log-text';
                        textEl.textContent = ent.text;

                        const del = document.createElement('button');
                        del.textContent = '삭제';
                        del.className = 'wr2-small-btn';
                        del.style.marginTop = '6px';
                        del.onclick = () => {
                          sec.data.entries = (sec.data.entries || []).filter(x => x.id !== ent.id);
                          saveSections();
                          wr2Render();
                        };

                        item.appendChild(meta);
                        item.appendChild(textEl);
                        item.appendChild(del);
                        listEl.appendChild(item);
                      });

                      body.appendChild(listEl);
                    }

                    card.appendChild(hd);
                    card.appendChild(body);
                    el.appendChild(card);
                  });
                }

                function moveSection(secId, dir) {
                  const room = getActiveRoom();
                  if (!room) return;
                  const phase = wr2State.activePhase;
                  const list = wr2State.sections
                    .filter(s => s.roomId === room.id && s.phase === phase)
                    .slice()
                    .sort((a, b) => (a.order || 1) - (b.order || 1));

                  const idx = list.findIndex(s => s.id === secId);
                  if (idx === -1) return;
                  const j = idx + dir;
                  if (j < 0 || j >= list.length) return;

                  const a = list[idx];
                  const b = list[j];
                  const ao = a.order || 1;
                  const bo = b.order || 1;

                  // swap
                  wr2State.sections = wr2State.sections.map(s => {
                    if (s.id === a.id) return Object.assign({}, s, { order: bo });
                    if (s.id === b.id) return Object.assign({}, s, { order: ao });
                    return s;
                  });
                  saveSections();
                  wr2Render();
                }

                function renderTimeline(room) {
                  const el = document.getElementById('wr2TimelineBody');
                  if (!el) return;

                  const logs = [];
                  wr2State.sections
                    .filter(s => s.roomId === room.id && s.type === 'log')
                    .forEach(s => {
                      (s.data.entries || []).forEach(ent => logs.push({ phase: s.phase, at: ent.at, text: ent.text }));
                    });

                  logs.sort((a, b) => (b.at || 0) - (a.at || 0));

                  el.innerHTML = '';
                  if (!logs.length) { el.textContent = '아직 기록된 로그가 없습니다.'; return; }

                  logs.forEach(l => {
                    const item = document.createElement('div');
                    item.textContent = '[' + formatDateTime(l.at) + ' / ' + statusLabel(l.phase) + '] ' + l.text;
                    el.appendChild(item);
                  });
                }

                // Modal
                function showNewModal() {
                  document.getElementById('wr2NewTitle').value = '';
                  document.getElementById('wr2NewAddress').value = '';
                  document.getElementById('wr2NewAuctionId').value = '';
                  document.getElementById('wr2NewListingId').value = '';
                  document.getElementById('wr2NewTags').value = '';
                  document.getElementById('wr2NewSeedDefaults').checked = true;
                  document.getElementById('wr2NewModal').style.display = 'flex';
                  setTimeout(() => document.getElementById('wr2NewTitle').focus(), 50);
                }
                function hideNewModal() { document.getElementById('wr2NewModal').style.display = 'none'; }

                // 지도 연동: 주소를 중심으로 map setCenter (가능할 때만)
                function openOnMapByAddress(address) {
                  const addr = (address || '').trim();
                  if (!addr) { alert('주소가 없습니다.'); return; }
                  if (!window.kakao || !window.kakao.maps || !window.geocoder || !window.map) {
                    alert('지도 시스템이 준비되지 않았습니다. (kakao/maps/geocoder/map 확인 필요)');
                    return;
                  }
                  window.geocoder.addressSearch(addr, function (result, status) {
                    if (status !== window.kakao.maps.services.Status.OK || !result || !result.length) {
                      alert('주소를 지도에서 찾지 못했습니다.');
                      return;
                    }
                    const y = parseFloat(result[0].y);
                    const x = parseFloat(result[0].x);
                    const pos = new window.kakao.maps.LatLng(y, x);
                    window.map.setCenter(pos);
                    // 너무 과도한 줌 변경은 피하고, 적당히만
                    try { window.map.setLevel(Math.min(4, window.map.getLevel ? window.map.getLevel() : 4)); } catch (e) { }
                    // 지도 탭으로 이동(존재하면)
                    if (typeof window.goPage === 'function') {
                      // 본 파일의 메인 탭 인덱스가 다를 수 있어 안전하게 try
                      try { window.goPage(2); } catch (e) { }
                    }
                  });
                }

                // ── v241: 필터칩 핸들러 ───────────────────────────
                window.wr2SetFilter = function (btn, val) {
                  document.querySelectorAll('#wr2FilterChips .wr2-chip').forEach(b => b.classList.remove('active'));
                  if (btn) btn.classList.add('active');
                  wr2State.statusFilter = val;
                  wr2Render();
                };

                // ── v241: 리사이즈 핸들 드래그 ───────────────────────
                function initResizeHandle() {
                  const handle = document.getElementById('wr2ResizeHandle');
                  const panel = document.getElementById('wr2ListPanel');
                  if (!handle || !panel) return;
                  let dragging = false, startX = 0, startW = 0;
                  handle.addEventListener('mousedown', function (e) {
                    dragging = true;
                    startX = e.clientX;
                    startW = panel.offsetWidth;
                    handle.classList.add('dragging');
                    document.body.style.userSelect = 'none';
                    e.preventDefault();
                  });
                  document.addEventListener('mousemove', function (e) {
                    if (!dragging) return;
                    const dw = e.clientX - startX;
                    const nw = Math.min(440, Math.max(160, startW + dw));
                    panel.style.width = nw + 'px';
                  });
                  document.addEventListener('mouseup', function () {
                    if (!dragging) return;
                    dragging = false;
                    handle.classList.remove('dragging');
                    document.body.style.userSelect = '';
                  });
                }

                function bindEventsOnce() {
                  const sortSel = document.getElementById('wr2Sort');
                  const newBtn = document.getElementById('wr2NewRoomBtn');
                  const newCreate = document.getElementById('wr2NewCreate');
                  const newCancel = document.getElementById('wr2NewCancel');
                  const titleInput = document.getElementById('wr2Title');
                  const addrInput = document.getElementById('wr2Address');
                  const statusSel = document.getElementById('wr2Status');
                  const auctionIn = document.getElementById('wr2AuctionId');
                  const addSecBtn = document.getElementById('wr2AddSectionBtn');
                  const secTypeSel = document.getElementById('wr2NewSectionType');
                  const delRoomBtn = document.getElementById('wr2DeleteRoomBtn');
                  const linkBtn = document.getElementById('wr2LinkSavedBtn');

                  if (sortSel) sortSel.onchange = e => { wr2State.sort = e.target.value; wr2Render(); };
                  if (newBtn) newBtn.onclick = showNewModal;
                  if (newCreate) newCreate.onclick = createRoomFromModal;
                  if (newCancel) newCancel.onclick = hideNewModal;
                  if (linkBtn) linkBtn.onclick = () => wr2ShowLinkModal();

                  const modal = document.getElementById('wr2NewModal');
                  if (modal) modal.addEventListener('click', e => { if (e.target === modal) hideNewModal(); });

                  const makeCommit = id => () => {
                    const el = document.getElementById(id); if (!el) return;
                    const r = getActiveRoom(); if (!r) return;
                    const patch = {};
                    if (id === 'wr2Title') patch.title = el.value;
                    if (id === 'wr2Address') patch.address = el.value;
                    if (id === 'wr2AuctionId') patch.auctionId = el.value.trim() || null;
                    if (id === 'wr2ListingId') patch.listingId = el.value.trim() || null;
                    patch.updatedAt = Date.now();
                    Object.assign(r, patch);
                    saveRooms(); wr2Render();
                  };

                  if (titleInput) { titleInput.oninput = e => { const r = getActiveRoom(); if (r) updateRoom(r.id, { title: e.target.value }, true); }; titleInput.onblur = makeCommit('wr2Title'); }
                  if (addrInput) { addrInput.oninput = e => { const r = getActiveRoom(); if (r) updateRoom(r.id, { address: e.target.value }, true); }; addrInput.onblur = makeCommit('wr2Address'); }
                  if (statusSel) statusSel.onchange = e => {
                    const r = getActiveRoom(); if (!r) return;
                    const newSt = e.target.value;
                    updateRoom(r.id, { status: newSt });
                    // ★ wrDb 쪽과 파이프라인 동기화
                    if (typeof window.wrDbUpdateStatus === 'function') window.wrDbUpdateStatus(r.id, newSt);
                  };
                  if (auctionIn) { auctionIn.oninput = e => { const r = getActiveRoom(); if (r) updateRoom(r.id, { auctionId: e.target.value.trim() || null }, true); }; auctionIn.onblur = makeCommit('wr2AuctionId'); }

                  if (addSecBtn) addSecBtn.onclick = () => {
                    const r = getActiveRoom(); if (!r) return;
                    const tp = secTypeSel ? secTypeSel.value : 'memo';
                    const ph = wr2State.activePhase || 'interest';
                    createSection(ph, tp);
                    saveSections();
                    // 단계 탭으로 자동 전환
                    if (wr2State.activeView !== 'phase') wr2SwitchView('phase');
                    else wr2Render();
                  };

                  if (delRoomBtn) delRoomBtn.onclick = () => {
                    const r = getActiveRoom(); if (!r) return;
                    deleteRoom(r.id);
                  };

                  // 노트 드롭존 (파일 드래그앤드롭)
                  initNoteDropZone();

                  document.addEventListener('keydown', e => {
                    if (e.key === 'Escape') {
                      const m = document.getElementById('wr2NewModal');
                      if (m && m.style.display === 'flex') hideNewModal();
                      document.getElementById('wr2LinkModal')?.remove();
                    }
                  }, { passive: true });
                }

                function initNoteDropZone() {
                  const zone = document.getElementById('wr2NoteDropZone');
                  if (!zone) return;
                  zone.addEventListener('dragover', e => { e.preventDefault(); zone.classList.add('drag-over'); });
                  zone.addEventListener('dragleave', e => { if (!zone.contains(e.relatedTarget)) zone.classList.remove('drag-over'); });
                  zone.addEventListener('drop', e => {
                    e.preventDefault(); zone.classList.remove('drag-over');
                    const files = Array.from(e.dataTransfer.files);
                    if (files.length) wr2HandleFilesArray(files);
                  });
                }

                window.wr2HandleFiles = function (input) {
                  wr2HandleFilesArray(Array.from(input.files));
                  input.value = '';
                };
                function wr2HandleFilesArray(files) {
                  const room = getActiveRoom(); if (!room) return;
                  if (!room.attachments) room.attachments = [];
                  let done = 0;
                  files.forEach(file => {
                    const reader = new FileReader();
                    reader.onload = e => {
                      const isImg = file.type.startsWith('image/');
                      room.attachments.push({ name: file.name, type: isImg ? 'image' : 'file', data: e.target.result });
                      room.updatedAt = Date.now(); done++;
                      if (done === files.length) { saveRooms(); renderAttachments(room); }
                    };
                    reader.readAsDataURL(file);
                  });
                }

                // INIT

                // ─────────────────────────────────────────────────────────────
                // 🔗 저장된 물건(팝업) ↔ 작업룸 연동
                //   - 팝업 상단의 [🗂 작업룸] 버튼에서 호출
                //   - savedId 기준으로 작업룸을 찾아 열고, 없으면 자동 생성 + 기본 템플릿 시딩
                // ─────────────────────────────────────────────────────────────
                function _wr2PickAddrFromSaved(item) {
                  const d = (item && item.data) ? item.data : {};
                  return d['소재지'] || d['주소'] || d['도로명주소'] || d['지번주소'] || d['address'] || '';
                }
                function _wr2PickTitleFromSaved(item) {
                  const d = (item && item.data) ? item.data : {};
                  return item.title || d['물건명'] || d['물건명칭'] || d['소재지'] || '';
                }
                function _wr2ParseNum(v) {
                  if (v === null || v === undefined) return null;
                  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
                  return isFinite(n) && n > 0 ? n : null;
                }

                window.wr2OpenOrCreateFromSavedId = function (savedId) {
                  try {
                    // 작업룸 탭으로 이동
                    if (typeof showInsTab === 'function') showInsTab(8);
                    const tab = document.getElementById('ipage8');
                    if (tab) tab.style.display = 'block';
                  } catch (e) { }

                  // init 보장
                  try {
                    if (!window.__wr2Inited && typeof window.wr2Init === 'function') {
                      window.__wr2Inited = true;
                      window.wr2Init();
                    }
                  } catch (e) { }

                  // saved item 로드
                  let item = null;
                  try {
                    if (typeof getSv === 'function') {
                      const sv = getSv() || [];
                      item = sv.find(s => String(s.id) === String(savedId)) || null;
                    }
                  } catch (e) { }
                  if (!item) {
                    alert('저장된 물건을 찾을 수 없습니다. (id=' + savedId + ')');
                    return;
                  }

                  // 기존 룸 탐색
                  const ex = (wr2State.rooms || []).find(r =>
                    String(r.linkedSavedId || '') === String(savedId) ||
                    String(r.auctionId || '') === String(savedId) ||
                    String(r.listingId || '') === String(savedId)
                  );

                  if (ex) {
                    setActiveRoom(ex.id);
                    // 팝업이 열려있다면 살짝 안내
                    try { if (typeof showToast === 'function') showToast('🗂 연결된 작업룸을 열었습니다', 'ok'); } catch (e) { }
                    return;
                  }

                  // 새 룸 생성 (자동 채움)
                  const now = Date.now();
                  const addr = _wr2PickAddrFromSaved(item);
                  const title = _wr2PickTitleFromSaved(item) || ('물건 ' + String(savedId).slice(0, 6));
                  const mode = item.mode || '';
                  const source = item.source || item.site || '';

                  const room = {
                    id: genId('room'),
                    title: title,
                    address: addr,
                    auctionId: (mode === 'auction') ? String(savedId) : null,
                    listingId: (mode !== 'auction') ? String(savedId) : null,
                    status: 'review',
                    phase: 'review',
                    tags: [source, (mode === 'auction' ? '경매' : (mode === 'transaction' ? '실거래' : '매물'))].filter(Boolean),
                    linkedSavedId: String(savedId),
                    createdAt: now,
                    updatedAt: now
                  };

                  wr2State.rooms.push(room);
                  saveRooms();

                  wr2State.activeRoomId = room.id;
                  wr2State.activePhase = room.phase;

                  // 기본 템플릿 자동 생성
                  try { seedDefaults(room.id); } catch (e) { }

                  // 숫자(보증금/월세/가격) 자동 주입: '3) 수익/가격 시나리오' 섹션이 있으면 채움
                  try {
                    const d = item.data || {};
                    const dep = _wr2ParseNum(d['보증금'] || d['임차보증금'] || d['보증금(원)']);
                    const rent = _wr2ParseNum(d['월세'] || d['임대료'] || d['월세(원)']);
                    const price = _wr2ParseNum(d['매매가'] || d['매매가(원)'] || d['낙찰가'] || d['최저가'] || d['감정가']);

                    const secs = (wr2State.sections || []).filter(s => s.roomId === room.id && s.phase === 'review' && s.type === 'metrics');
                    const target = secs.find(s => (s.title || '').includes('수익') || (s.title || '').includes('가격')) || secs[0];
                    if (target && target.data && Array.isArray(target.data.rows)) {
                      target.data.rows = target.data.rows.map(r => {
                        const lb = String(r.label || '');
                        if (dep && lb.includes('보증금')) return Object.assign({}, r, { value: dep.toLocaleString() });
                        if (rent && lb.includes('월세')) return Object.assign({}, r, { value: rent.toLocaleString() });
                        if (price && (lb.includes('예상낙찰가') || lb.includes('매매') || lb.includes('가격') || lb.includes('최저') || lb.includes('감정'))) {
                          // 기존 라벨을 크게 해치지 않기 위해, 비어있을 때만 넣음
                          if (!r.value) return Object.assign({}, r, { value: price.toLocaleString() });
                        }
                        return r;
                      });
                      saveSections();
                    }
                  } catch (e) { }

                  wr2Render();
                  try { if (typeof showToast === 'function') showToast('✅ 작업룸을 생성했습니다 (자동 연결)', 'ok'); } catch (e) { }
                };


                window.wr2Init = function () {
                  if (typeof window._wr2MigrateOld === 'function') window._wr2MigrateOld();
                  loadRooms();
                  loadSections();
                  bindEventsOnce();
                  initResizeHandle();
                  if (!wr2State.activeView) wr2State.activeView = 'overview';
                  // 최근 수정 룸 자동 선택
                  if (!wr2State.activeRoomId && wr2State.rooms.length) {
                    const sorted = wr2State.rooms.slice().sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));
                    wr2State.activeRoomId = sorted[0].id;
                    wr2State.activePhase = sorted[0].phase || 'interest';
                  }
                  wr2Render();
                };

              })();

