    (function () {
      function initScrollTopButtons() {
        // 저장목록 페이지 스크롤 감지
        const page1 = document.getElementById('page1');
        const savedBtn = document.getElementById('savedScrollTopBtn');
        if (page1 && savedBtn) {
          page1.addEventListener('scroll', function () {
            savedBtn.classList.toggle('visible', page1.scrollTop > 300);
          });
        }
        // 팝업 스크롤 감지
        const popBody = document.getElementById('popBody');
        const popBtn = document.getElementById('popupScrollTopBtn');
        if (popBody && popBtn) {
          popBody.addEventListener('scroll', function () {
            popBtn.classList.toggle('visible', popBody.scrollTop > 200);
          });
        }
      }
      // popup이 열릴 때마다 팝업 스크롤 버튼 재연결
      const _origOpenPopup = window.openPopup;
      if (typeof _origOpenPopup === 'undefined') {
        document.addEventListener('DOMContentLoaded', initScrollTopButtons);
      } else {
        initScrollTopButtons();
      }
      // DOMContentLoaded 후에도 실행
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initScrollTopButtons);
      } else {
        setTimeout(initScrollTopButtons, 500);
      }
    })();

    function showToast(msg, type, duration) {
      const c = document.getElementById('toast-container');
      if (!c) return;
      // ★ 중복 방지
      const existing = c.querySelectorAll('.toast-msg');
      for (let i = 0; i < existing.length; i++) { if (existing[i].textContent === msg) return; }
      const el = document.createElement('div');
      el.className = 'toast-msg' + (type === 'ok' ? ' toast-ok' : type === 'warn' ? ' toast-warn' : '');
      el.textContent = msg;
      c.appendChild(el);
      const ms = duration || 3000;
      setTimeout(() => {
        el.classList.add('toast-fade');
        setTimeout(() => { if (el.parentNode) el.parentNode.removeChild(el); }, 450);
      }, ms);
    }

