    let manualScale = 1.0;  // 수동 크기 조절
    let allCardsOpen = false;  // 모든 카드 열림 상태
    let zoomAutoResize = true;  // 줌 자동 크기 조절 ON/OFF
    let lastZoomLevel = null;  // 마지막 줌 레벨 추적 (임시 배율 유지용)
    let cardExpandState = new Map();  // 카드 펼침 상태 관리 (key: stackKey, value: true/false)
    const loadedMarkerIds = new Set(); // ★ 중복 마커 방지: 이미 지도에 올라간 마커 ID 추적

    // ★★ 중복 매물 판단 함수 (주소/층수/금액/면적 기준, 제목 제외) ★★
    function isDuplicateProperty(item1, item2) {
      if (!item1 || !item2) return false;
      if (item1.id === item2.id) return false; // 같은 ID면 자기자신

      const d1 = item1.data || {};
      const d2 = item2.data || {};
      const mode1 = item1.mode || '';
      const mode2 = item2.mode || '';

      // 타입이 다르면 다른 매물
      if (mode1 !== mode2) return false;

      // 1. 주소 비교 (대소문자 무시, 공백 제거)
      const addr1 = String(d1.소재지 || '').trim().toLowerCase().replace(/\s/g, '');
      const addr2 = String(d2.소재지 || '').trim().toLowerCase().replace(/\s/g, '');
      if (!addr1 || !addr2 || addr1 !== addr2) return false;

      // 2. 층수 비교
      const floor1 = String(d1.해당층 || d1.층수 || '').trim();
      const floor2 = String(d2.해당층 || d2.층수 || '').trim();
      if (floor1 && floor2 && floor1 !== floor2) return false;

      // 3. 금액 비교
      let price1 = 0, price2 = 0;
      if (mode1 === 'auction') {
        price1 = parseInt(String(d1.감정가 || d1.최저가 || '').replace(/[^0-9]/g, '')) || 0;
        price2 = parseInt(String(d2.감정가 || d2.최저가 || '').replace(/[^0-9]/g, '')) || 0;
      } else {
        price1 = parseInt(String(d1.매매가 || '').replace(/[^0-9]/g, '')) ||
          (parseInt(String(d1.기보증금_만원 || '').replace(/[^0-9]/g, '')) || 0) +
          (parseInt(String(d1.월세_만원 || '').replace(/[^0-9]/g, '')) || 0) * 100;
        price2 = parseInt(String(d2.매매가 || '').replace(/[^0-9]/g, '')) ||
          (parseInt(String(d2.기보증금_만원 || '').replace(/[^0-9]/g, '')) || 0) +
          (parseInt(String(d2.월세_만원 || '').replace(/[^0-9]/g, '')) || 0) * 100;
      }
      if (price1 && price2 && Math.abs(price1 - price2) > price1 * 0.05) return false; // 5% 이상 차이

      // 4. 면적 비교
      const area1 = parseFloat(d1.전용면적_m2 || d1.건물면적_m2 || d1.계약면적_m2 || 0);
      const area2 = parseFloat(d2.전용면적_m2 || d2.건물면적_m2 || d2.계약면적_m2 || 0);
      if (area1 && area2 && Math.abs(area1 - area2) > 1) return false; // 1㎡ 이상 차이

      return true; // 모든 조건 통과 → 중복 매물
    }

    // CSV 실거래가 데이터 (results 배열과 분리)
    let csvFiles = [];  // 업로드된 CSV 파일 정보 (메타데이터만)
    let transactionDataRaw = [];  // CSV 원본 데이터 (메모리)
    let loadedTransactions = [];  // 현재 지도에 표시중인 실거래가

    // IndexedDB 지오코딩 캐시
    let geocodeDB = null;
    const GEOCODE_DB_NAME = 'geocode_cache';
    const GEOCODE_DB_VERSION = 1;
    const GEOCODE_STORE = 'coords';

    // ===================================================
    // CSV 실거래 데이터 localStorage 자동저장
    // ===================================================
    const CSV_RAW_STORAGE_KEY = 'csv_transaction_raw';

    // CSV 데이터는 localStorage에 저장하지 않음 (용량 문제로 비활성화)
    // 기존 데이터가 남아있으면 즉시 삭제
    (function(){ try { localStorage.removeItem('csv_transaction_raw'); } catch(e){} })();
    function saveTransactionRawToStorage() {
      return false; // 저장 안 함 - 메모리에만 유지
      try {
        const toSave = transactionDataRaw.map(item => ({
          name: item.name,
          address: item.address || item.sigungu || (item.dong ? (item.sigungu || '') + ' ' + item.dong : ''),
          price: item.price,
          area: item.area || '-',
          floor: item.floor || '-',
          year: item.year || '',
          month: item.month || '',
          day: item.day || '',
          lat: item.lat || null,
          lng: item.lng || null,
          source: item.source || 'CSV',
          type: item.type || 'transaction',
          sigungu: item.sigungu || '',
          dong: item.dong || '',
          jibun: item.jibun || '',
          buildYear: item.buildYear || '',
          name2: item.name || ''
        }));
        localStorage.setItem(CSV_RAW_STORAGE_KEY, JSON.stringify(toSave));
        return true;
      } catch (e) {
        // localStorage 용량 초과 시 압축 저장 시도
        if (e.name === 'QuotaExceededError') {
          try {
            // 최근 10만 건만 유지
            const trimmed = transactionDataRaw.slice(-100000).map(item => ({
              name: item.name, address: item.address || ((item.sigungu || '') + ' ' + (item.dong || '')).trim(),
              price: item.price, area: item.area || '-', floor: item.floor || '-',
              year: item.year || '', month: item.month || '', day: item.day || '',
              lat: item.lat || null, lng: item.lng || null, source: item.source || 'CSV'
            }));
            localStorage.setItem(CSV_RAW_STORAGE_KEY, JSON.stringify(trimmed));
            return true;
          } catch (e2) {
            console.warn('CSV 저장 실패 (용량 초과). 데이터가 너무 큽니다:', e2);
            return false;
          }
        }
        console.error('CSV localStorage 저장 실패:', e);
        return false;
      }
    }

    // CSV 데이터 복원 비활성화 (저장 안 하므로 복원도 불필요)
    function loadTransactionRawFromStorage() {
      try { localStorage.removeItem('csv_transaction_raw'); } catch(e) {}
      return 0;
      try {
        const raw = localStorage.getItem(CSV_RAW_STORAGE_KEY);
        if (!raw) return 0;
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed) || parsed.length === 0) return 0;
        // 기존 데이터 유지 + 새 데이터 병합 (중복 제거는 address+year+month 기준)
        const existingKeys = new Set(transactionDataRaw.map(i => `${i.address || ''}|${i.year || ''}|${i.month || ''}`));
        let added = 0;
        parsed.forEach(item => {
          const key = `${item.address || ''}|${item.year || ''}|${item.month || ''}`;
          if (!existingKeys.has(key)) {
            transactionDataRaw.push(item);
            existingKeys.add(key);
            added++;
          }
        });
        return added;
      } catch (e) {
        console.warn('CSV 복원 실패:', e);
        return 0;
      }
    }

