    function showPage(n) {
      currentPage = n;
      [0, 1, 2, 3].forEach(i => {
        const page = document.getElementById('page' + i);
        const nav = document.getElementById('nav' + i);
        if (page) page.style.display = i === n ? '' : 'none';
        if (nav) nav.classList.toggle('on', i === n);
      });
      // 지도탭은 overflow:hidden 필요
      const mc = document.querySelector('.main-content');
      if (mc) mc.classList.toggle('map-active', n === 2);
      if (n === 1) renderSaved();
      if (n === 2) initMap();
      if (n === 3) onInsightOpen();
      if (n !== 2) closeCalcPanel();

      // ★ 탭 전환 시 전역 필터 패널 갱신
      if (n === 0 || n === 1) setTimeout(renderGFilterPanels, 0);
    }

    // ===================================================
