    // ── 디스코/플래닛 역지오코딩: 주소 없는 항목을 카카오API로 보완 ──
    async function _reverseGeocodeSavedItems(sourceName) {
      const kakaoKey = localStorage.getItem('kakao_api') || '';
      if (!window.kakao || !window.kakao.maps) return;
      // 카카오 지오코더 준비
      if (!window.kakao.maps.services) return;
      const gc = new kakao.maps.services.Geocoder();
      const sv = getSv();
      // 주소 없고 좌표 있는 항목만
      const toFix = sv.filter(s =>
        s.source === sourceName &&
        s.data &&
        (!s.data.소재지 || s.data.소재지.trim() === '') &&
        s.data.lat && s.data.lng
      );
      if (!toFix.length) return;
      let converted = 0;
      for (const item of toFix) {
        await new Promise(resolve => {
          gc.coord2Address(parseFloat(item.data.lng), parseFloat(item.data.lat), (result, status) => {
            if (status === kakao.maps.services.Status.OK && result[0]) {
              const road = result[0].road_address;
              const jibun = result[0].address;
              const addr = (road && road.address_name) || (jibun && jibun.address_name) || '';
              if (addr) {
                item.data.소재지 = addr;
                // title도 갱신 (거래년월만 있던 경우)
                if (!item.title || item.title === item.data.거래년월) {
                  item.title = addr;
                }
                converted++;
              }
            }
            resolve();
          });
        });
        await new Promise(r => setTimeout(r, 20)); // rate limit 완화
      }
      if (converted > 0) {
        setSv(sv); // 변경된 배열 저장
        renderSaved && renderSaved();
        showToast(`📍 주소 ${converted}건 자동 보완 완료`, 'ok');
      }
    }

    // ★ [v155] 저장 후 주소→좌표 자동 변환 (lat/lng 없는 항목 채우기)
    async function _forwardGeocodeSavedItems(sourceName) {
      if (!window.kakao || !window.kakao.maps || !window.kakao.maps.services) return;
      const gc = new kakao.maps.services.Geocoder();
      const sv = getSv();
      // 좌표 없고 주소 있는 항목만
      const toFix = sv.filter(s =>
        (sourceName ? s.source === sourceName : true) &&
        s.data &&
        (!s.lat || !s.lng) &&
        (s.data.소재지 || s.data.물건소재지 || s.data.주소 || s.data.address)
      );
      if (!toFix.length) return;
      let converted = 0;
      for (const item of toFix) {
        const addr = String(item.data.소재지 || item.data.물건소재지 || item.data.주소 || item.data.address || '').trim();
        if (!addr) continue;
        // 캐시 먼저 확인
        const cached = await geocodeWithCache(addr).catch(() => null);
        if (cached) {
          item.lat = cached.lat;
          item.lng = cached.lng;
          converted++;
        } else {
          await new Promise(resolve => {
            gc.addressSearch(addr, (result, status) => {
              if (status === kakao.maps.services.Status.OK && result[0]) {
                item.lat = parseFloat(result[0].y);
                item.lng = parseFloat(result[0].x);
                saveCachedCoords(addr, item.lat, item.lng);
                converted++;
              }
              resolve();
            });
          });
        }
        await new Promise(r => setTimeout(r, 30));
      }
      if (converted > 0) {
        setSv(sv);
        console.log(`[좌표 자동보완] ${sourceName || '전체'} ${converted}개 좌표 보완 완료`);
      }
    }

