          if (계약 > 0) return `${fi(d.계약면적_m2, '계약면적', 'area', idx, '계약면적_m2', isPopup)}<div class="fi" style="grid-column:1/-1"><div class="fl" style="color:#ffb347;">⚠️ 전용면적</div><div class="fv" style="color:#ffb347;font-size:11px;">미확인 — 계약면적과 다를 수 있음</div></div>`;
