    let nplLinkedItemId = null;

    function populateItemSelects() {
      const sv = getSv();
      const auctionOnly = sv.filter(it => (it.mode || '') === 'auction');
      const auctionOpts = '<option value="">-- 경매 물건 선택 --</option>' +
        auctionOnly.map(it => `<option value="${it.id}">${esc(it.title || it.data?.소재지 || it.id)}</option>`).join('');
      const allOpts = '<option value="">-- 저장목록에서 물건 선택 --</option>' +
        sv.map(it => `<option value="${it.id}">${esc(it.title || it.data?.소재지 || it.id)}</option>`).join('');
      ['nplLinkSel', 'yrLinkSel', 'bdLinkSel', 'flLinkSel', 'rtLinkSel'].forEach(id => { const el = document.getElementById(id); if (el) el.innerHTML = auctionOpts; });
      ['noteLinkSel'].forEach(id => { const el = document.getElementById(id); if (el) el.innerHTML = allOpts; });
      // 연결된 노트에 현재 선택 복원
      if (currentNoteId) {
        const note = insNotes.find(n => n.id === currentNoteId);
        const sel = document.getElementById('noteLinkSel');
        if (sel && note) sel.value = note.linkedItemId || '';
      }
    }

    function loadNplItem() {
      const sel = document.getElementById('nplLinkSel');
      if (!sel || !sel.value) { showToast('물건을 먼저 선택하세요', 'warn'); return; }
      const saved = getSv(); const item = saved.find(s => s.id === sel.value);
      if (!item) { showToast('물건을 찾을 수 없습니다', 'warn'); return; }
      nplLinkedItemId = item.id;
      const d = item.data || {};
      const lbl = document.getElementById('nplLinked');
      // 원 단위로 그대로 입력
      const toWon = v => { const n = parseInt(String(v).replace(/,/g, '')); return isNaN(n) ? 0 : n; };
      if (d.감정가) setCalcVal('npl_a', toWon(d.감정가));
      const minBid = d.최저입찰가 || d.최저가;
      if (minBid) setCalcVal('npl_m', toWon(minBid));
      else if (d.감정가) setCalcVal('npl_m', Math.round(toWon(d.감정가) * 0.7));
      // 최저가 뱃지
      if (lbl) { lbl.innerHTML = '🔗 ' + esc(item.title || d.소재지 || item.id) + (minBid ? `<span style="margin-left:8px;background:rgba(255,99,112,.15);color:#ff6370;border:1px solid rgba(255,99,112,.3);border-radius:5px;padding:1px 6px;font-size:10px;">최저 ${toWon(minBid).toLocaleString('ko-KR')}원</span>` : ''); lbl.style.display = ''; }
      calcNPL();
      showToast(`✅ [${item.title || item.id}] 불러옴`, 'ok');
    }

