    const fmt = n => (n >= 0 ? '+' : '') + fW(Math.abs(Math.round(n)));
    // 콤마 제거 후 숫자 파싱
    const gv = id => { const raw = (document.getElementById(id)?.value || '').replace(/,/g, ''); const v = parseFloat(raw); return isNaN(v) ? 0 : v; };

    // 계산기 인풋에 콤마 포맷으로 값 설정
    function sv(id, val) {
      const el = document.getElementById(id); if (!el) return;
      const n = parseFloat(val);
      if (!isNaN(n)) el.value = n.toLocaleString('ko-KR');
    }
    function setCalcVal(id, val) {
      const el = document.getElementById(id); if (!el) return;
      const n = parseFloat(val);
      if (!isNaN(n)) el.value = n.toLocaleString('ko-KR');
    }
    // 입력 중 천단위 콤마 자동 포맷 (% 입력칸 제외)
    function formatCalcInput(el) {
      const isPercent = el.id.endsWith('_yr') || el.id.endsWith('_rate') || el.id.endsWith('_tax');
      if (isPercent) return; // 수익률/이율 칸은 콤마 안 씀
      const raw = el.value.replace(/,/g, '');
      if (raw === '' || raw === '-') return;
      const n = parseFloat(raw);
      if (!isNaN(n)) {
        const pos = el.selectionStart;
        const oldLen = el.value.length;
        el.value = n.toLocaleString('ko-KR');
        // 커서 위치 보정
        const newLen = el.value.length;
        el.setSelectionRange(pos + (newLen - oldLen), pos + (newLen - oldLen));
      }
    }

    function calcNPL() {
      const 감 = gv('npl_a'), 입 = gv('npl_bid'), d1 = gv('npl_d1'), d2max = gv('npl_d2'), 매입 = gv('npl_bp');
      const setR = (id, v, c) => { const el = document.getElementById(id); if (el) { el.textContent = v; if (c) el.style.color = c; } };
      if (!입) { ['r_npl_div', 'r_npl_cash', 'r_npl_profit'].forEach(id => setR(id, '-')); return; }
      const 배당 = Math.min(Math.max(0, 입 - d1), d2max);
      const 실투 = 입 - 배당;
      const 차익 = 배당 - 매입;
      setR('r_npl_div', fW(배당) || 배당.toLocaleString() + '원');
      setR('r_npl_cash', fW(실투) || 실투.toLocaleString() + '원', '#ff6370');
      setR('r_npl_profit', (차익 >= 0 ? '+' : '') + fW(Math.abs(차익)), 차익 >= 0 ? 'var(--g)' : '#ff6370');
    }

    function calcYield() {
      const price = gv('yr_price'), rent = gv('yr_rent'), dep = gv('yr_dep'), exp = gv('yr_exp'), loan = gv('yr_loan'), rate = gv('yr_rate'), area = gv('yr_area');
      const setR = (id, v, c) => { const el = document.getElementById(id); if (el) { el.textContent = v; if (c) el.style.color = c; } };
      if (!price || !rent) { ['r_yr_ann', 'r_yr_int', 'r_yr_cap', 'r_yr_gross', 'r_yr_net'].forEach(id => setR(id, '-')); return; }
      const ann = rent * 12 - exp;
      const interest = loan * rate / 100;
      const capital = price - dep;
      const gross = capital > 0 ? (ann / capital * 100) : 0;
      const netIncome = ann - interest;
      const equity = price - dep - loan;
      const net = equity > 0 ? (netIncome / equity * 100) : 0;
      setR('r_yr_ann', fW(ann) + '/년');
      setR('r_yr_int', fW(interest) + '/년', '#ff6370');
      setR('r_yr_cap', fW(capital));
      setR('r_yr_gross', gross.toFixed(2) + '%', gross >= 5 ? 'var(--g)' : '#ff6370');
      setR('r_yr_net', net.toFixed(2) + '%', net >= 5 ? 'var(--ac)' : '#ff6370');
      // 수익률 테이블
      const wrap = document.getElementById('yieldTableWrap');
      if (wrap && capital > 0) {
        const rates = [4, 5, 6, 7, 8];
        wrap.innerHTML = '<div style="font-size:11px;color:var(--mu);margin-bottom:5px;">목표 수익률별 필요 월세</div>' +
          rates.map(r => {
            const needed = capital * r / 100 / 12;
            const isNear = Math.abs(gross - r) < 0.5;
            return `<div style="display:flex;justify-content:space-between;padding:3px 0;font-size:11px;${isNear ? 'color:var(--ac);font-weight:700;' : 'color:var(--mu);'}">
          <span>${r}%</span><span>${fW(Math.round(needed))}/월</span></div>`;
          }).join('');
      }
    }

    // ★ [v177] 수익률 계산기 역산: 수익률→매매가
    window.calcYieldReverse = function () {
      const yr = parseFloat((document.getElementById('yr_target_yield') || {}).value || 0);
      const dep = parseFloat(String((document.getElementById('yr_dep') || {}).value || '0').replace(/[^0-9.]/g, '')) || 0;
      const rent = parseFloat(String((document.getElementById('yr_rent') || {}).value || '0').replace(/[^0-9.]/g, '')) || 0;
      const resEl = document.getElementById('yr_reverse_result');
      if (!resEl) return;
      if (yr > 0 && rent > 0) {
        const price = Math.round(rent * 12 / (yr / 100) + dep);
        resEl.innerHTML = `목표 수익률 <b style="color:var(--ac2);">${yr}%</b>를 위한 적정 매매가: <b style="color:var(--ac);font-size:12px;">${price.toLocaleString()}원</b>`;
        // 매입가 필드에도 반영
        const priceEl = document.getElementById('yr_price');
        if (priceEl && !priceEl.value) { priceEl.value = price.toLocaleString(); calcYield(); }
      } else {
        resEl.textContent = yr > 0 ? '월 임대료를 먼저 입력하세요' : '';
      }
    };

    // ★ [v177] 실거래 카드 매매수익률 계산기 토글
    window.toggleTxSaleCalc = function (uid) {
      const panel = document.getElementById('txcalc_' + uid);
      if (!panel) return;
      const isOpen = panel.style.display !== 'none';
      panel.style.display = isOpen ? 'none' : 'block';
    };

    // ★ [v177] 매매가→수익률 계산
    window.calcTxSaleYield = function (uid) {
      const priceEl = document.getElementById('txc_price_' + uid);
      const depEl = document.getElementById('txc_dep_' + uid);
      const rentEl = document.getElementById('txc_rent_' + uid);
      const yieldEl = document.getElementById('txc_yield_' + uid);
      const resEl = document.getElementById('txc_result_' + uid);
      if (!priceEl) return;
      const price = parseInt((priceEl.value || '').replace(/[^0-9]/g, '')) || 0;
      const dep = parseInt((depEl?.value || '').replace(/[^0-9]/g, '')) || 0;
      const rent = parseInt((rentEl?.value || '').replace(/[^0-9]/g, '')) || 0;
      if (price > 0 && rent > 0) {
        const yr = rent * 12 / (price - dep) * 100;
        if (yieldEl) { yieldEl.value = yr.toFixed(2); }
        if (resEl) { resEl.textContent = '연 임대수입: ' + (rent * 12).toLocaleString() + '원 / 실투자금: ' + (price - dep).toLocaleString() + '원'; }
      } else if (price > 0) {
        if (yieldEl) yieldEl.value = '';
        if (resEl) resEl.textContent = '월세를 입력하면 수익률이 계산됩니다';
      }
    };

    // ★ [v177] 수익률→매매가 역산
    window.calcTxSaleYieldFromRate = function (uid) {
      const priceEl = document.getElementById('txc_price_' + uid);
      const depEl = document.getElementById('txc_dep_' + uid);
      const rentEl = document.getElementById('txc_rent_' + uid);
      const yieldEl = document.getElementById('txc_yield_' + uid);
      const resEl = document.getElementById('txc_result_' + uid);
      if (!yieldEl) return;
      const yr = parseFloat(yieldEl.value) || 0;
      const dep = parseInt((depEl?.value || '').replace(/[^0-9]/g, '')) || 0;
      const rent = parseInt((rentEl?.value || '').replace(/[^0-9]/g, '')) || 0;
      if (yr > 0 && rent > 0) {
        const price = Math.round(rent * 12 / (yr / 100) + dep);
        if (priceEl) { priceEl.value = price.toLocaleString(); }
        if (resEl) resEl.textContent = '적정 매매가: ' + price.toLocaleString() + '원';
      }
    };

    function calcBid() {
      const app = gv('bd_app'), yr = gv('bd_yr'), rent = gv('bd_rent'), dep = gv('bd_dep'), tax = gv('bd_tax'), evic = gv('bd_evic'), inter = gv('bd_int');
      const minOverride = gv('bd_min');
      const setR = (id, v, c) => { const el = document.getElementById(id); if (el) { el.textContent = v; if (c) el.style.color = c; } };
      if (!rent) { ['r_bd_ann', 'r_bd_cost', 'r_bd_price', 'r_bd_ratio', 'r_bd_min'].forEach(id => setR(id, '-')); return; }
      const ann = rent * 12;
      const extraCosts = evic + inter;
      // 최저입찰가: 직접 입력 or 감정가×80%
      const minBid = minOverride > 0 ? minOverride : (app > 0 ? Math.round(app * 0.8) : 0);
      // 적정 낙찰가: (연임대수입/목표수익률) - 부대비용 - 보증금
      const bidPrice = yr > 0 ? (ann / (yr / 100)) - extraCosts - dep : 0;
      const ratio = app > 0 ? (bidPrice / app * 100) : 0;
      const totalCosts = bidPrice * tax / 100 + extraCosts;
      setR('r_bd_ann', fW(ann) + '/년');
      setR('r_bd_cost', fW(Math.round(totalCosts)), '#ff6370');
      setR('r_bd_min', minBid > 0 ? fW(minBid) : '-', 'var(--warn)');
      setR('r_bd_price', fW(Math.round(bidPrice)), bidPrice > 0 ? 'var(--g)' : '#ff6370');
      setR('r_bd_ratio', ratio.toFixed(1) + '%', ratio < 80 ? 'var(--g)' : ratio < 95 ? 'var(--ac)' : '#ff6370');
      const wrap = document.getElementById('bidTableWrap');
      if (wrap && app > 0 && rent > 0) {
        const rates = [5, 6, 7, 8, 10];
        wrap.innerHTML = '<div style="font-size:11px;color:var(--mu);margin-bottom:5px;">목표 수익률별 적정 입찰가</div>' +
          rates.map(r => {
            const bp = (rent * 12 / (r / 100)) - extraCosts - dep;
            const isTarget = r === yr;
            return `<div style="display:flex;justify-content:space-between;padding:3px 0;font-size:11px;${isTarget ? 'color:var(--ac);font-weight:700;' : 'color:var(--mu);'}">
          <span>${r}%</span><span>${fW(Math.round(bp))} (감정가의 ${(bp / app * 100).toFixed(0)}%)</span></div>`;
          }).join('');
      }
    }

    // ── 면적 계산기 ──────────────────────────────────────
    function calcArea(from) {
      const SQM_PER_PYEONG = 3.30579;
      const SQFT_PER_SQM = 10.7639;
      let sqm = 0;
      if (from === 'sqm') {
        sqm = gv('area_sqm');
      } else if (from === 'pyeong') {
        sqm = gv('area_pyeong') * SQM_PER_PYEONG;
      } else if (from === 'sqft') {
        sqm = gv('area_sqft') / SQFT_PER_SQM;
      } else if (from === 'pub') {
        sqm = gv('area_pub');
      }
      if (sqm <= 0) return;
      const pyeong = sqm / SQM_PER_PYEONG;
      const sqft = sqm * SQFT_PER_SQM;
      // 각 필드 업데이트 (현재 입력 필드 제외)
      if (from !== 'sqm') document.getElementById('area_sqm').value = sqm.toFixed(2);
      if (from !== 'pyeong') document.getElementById('area_pyeong').value = pyeong.toFixed(2);
      if (from !== 'sqft') document.getElementById('area_sqft').value = sqft.toFixed(2);
      if (from !== 'pub') document.getElementById('area_pub').value = sqm.toFixed(2);
      // 결과 표시
      const setR = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
      setR('r_area_pyeong', pyeong.toFixed(2) + '평');
      setR('r_area_sqm', sqm.toFixed(2) + '㎡');
      setR('r_area_sqft', sqft.toFixed(2) + 'ft²');
      // 평당가도 재계산
      calcAreaPrice();
    }

    function calcAreaPrice() {
      const price = gv('area_price');
      const size = gv('area_size');
      const SQM_PER_PYEONG = 3.30579;
      const setR = (id, v, c) => { const el = document.getElementById(id); if (el) { el.textContent = v; if (c) el.style.color = c; } };
      if (price <= 0 || size <= 0) {
        setR('r_price_per_sqm', '-');
        setR('r_price_per_pyeong', '-');
        return;
      }
      const perSqm = Math.round(price / size);
      const perPyeong = Math.round(price / (size / SQM_PER_PYEONG));
      setR('r_price_per_sqm', fW(perSqm) + '/㎡', 'var(--g)');
      setR('r_price_per_pyeong', fW(perPyeong) + '/평', 'var(--ac)');
    }

    // ── 부동산 수익 분석 계산기 ──────────────────────────
    function calcRealEstate() {
      const appraisal = gv('re_appraisal'), bid = gv('re_bid'), loanPct = gv('re_loan_pct'),
        acqTax = gv('re_acq_tax'), legal = gv('re_legal'), prepay = gv('re_prepay'),
        intRate = gv('re_int_rate'), repair = gv('re_repair'), eviction = gv('re_eviction'),
        misc = gv('re_misc'), sell = gv('re_sell'), incTax = gv('re_inc_tax');
      const setR = (id, v, c) => { const el = document.getElementById(id); if (el) { el.textContent = v; if (c) el.style.color = c; } };
      if (!bid) { ['r_re_bid_ratio', 'r_re_total_cost', 'r_re_total_inv', 'r_re_equity', 'r_re_capital_gain', 'r_re_inc_tax_amt', 'r_re_net_profit', 'r_re_roi'].forEach(id => setR(id, '-')); return; }
      const loan = bid * (loanPct / 100);
      const acqTaxAmt = bid * (acqTax / 100);
      const legalAmt = bid * (legal / 100);
      const prepayAmt = loan * (prepay / 100);
      const intAmt = loan * (intRate / 100) / 4; // 3개월 이자
      const totalCost = acqTaxAmt + legalAmt + prepayAmt + intAmt + repair + eviction + misc;
      const totalInv = bid + totalCost;
      const equity = totalInv - loan;
      const bidRatio = appraisal > 0 ? (bid / appraisal * 100) : 0;
      const capitalGain = sell > 0 ? sell - bid - totalCost : 0;
      const incTaxAmt = capitalGain > 0 ? capitalGain * (incTax / 100) : 0;
      const netProfit = sell > 0 ? sell - totalInv - incTaxAmt : 0;
      const roi = equity > 0 && sell > 0 ? (netProfit / equity * 100) : 0;
      setR('r_re_bid_ratio', appraisal > 0 ? bidRatio.toFixed(1) + '% (감정가 대비)' : '-');
      setR('r_re_total_cost', fW(Math.round(totalCost)), '#ff6370');
      setR('r_re_total_inv', fW(Math.round(totalInv)));
      setR('r_re_equity', fW(Math.round(equity)), 'var(--warn)');
      setR('r_re_capital_gain', sell > 0 ? fW(Math.round(capitalGain)) : '-');
      setR('r_re_inc_tax_amt', incTaxAmt > 0 ? fW(Math.round(incTaxAmt)) : '-', '#ff6370');
      setR('r_re_net_profit', sell > 0 ? fW(Math.round(netProfit)) : '-', netProfit > 0 ? 'var(--g)' : '#ff6370');
      setR('r_re_roi', sell > 0 ? roi.toFixed(1) + '%' : '-', roi > 0 ? 'var(--ac)' : '#ff6370');
    }



    // ── 계산기 → 작업룸 저장 ────────────────────────────
    window.saveCalcToRoom = function(type) {
      var rooms = typeof wrGetRooms === 'function' ? wrGetRooms() : [];
      if (!rooms.length) { showToast('작업룸이 없습니다. 먼저 작업룸을 만들어주세요.', 'warn'); return; }

      var stMap = typeof UNIFIED_STATUS !== 'undefined' ? UNIFIED_STATUS : {};
      var typeLabel = type === 'flip' ? '🏠 주택 경매 수익분석' : '🏢 상가 경매 수익분석';

      // 문자열 연결 방식으로 HTML 생성 (중첩 backtick 회피)
      var roomsHtml = rooms.map(function(r) {
        var st = typeof _migrateStatus === 'function' ? _migrateStatus(r.status || 'review') : (r.status || 'review');
        var info = stMap[st] || { label: r.status || st, color: '#60a5fa' };
        var d = new Date(r.updatedAt || Date.now());
        var dt = (d.getMonth()+1) + '/' + d.getDate();
        var title = (r.title || r.name || '작업룸').replace(/'/g, "\'").substring(0, 20);
        return '<div onclick="window._calcRoomSelect(\'' + r.id + '\',\'' + type + '\');document.getElementById(\'calcRoomModal\').remove();"'
          + ' style="padding:10px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:8px;cursor:pointer;display:flex;align-items:center;gap:8px;"'
          + ' onmouseenter="this.style.borderColor=\'rgba(167,139,250,.5)\';this.style.background=\'rgba(167,139,250,.06)\'"'
          + ' onmouseleave="this.style.borderColor=\'var(--b1)\';this.style.background=\'var(--s2)\'">'
          + '<span style="font-size:16px;">🗂</span>'
          + '<div style="flex:1;min-width:0;">'
          + '<div style="font-size:12px;font-weight:600;color:var(--tx);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + (r.title || r.name || '작업룸') + '</div>'
          + '<div style="font-size:10px;color:var(--di);">' + dt + ' 수정</div>'
          + '</div>'
          + '<span style="font-size:10px;padding:2px 7px;border-radius:5px;background:' + info.color + '18;color:' + info.color + ';border:1px solid ' + info.color + '33;white-space:nowrap;">' + info.label + '</span>'
          + '</div>';
      }).join('');

      var modal = document.createElement('div');
      modal.id = 'calcRoomModal';
      modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:99999;display:flex;align-items:center;justify-content:center;';
      modal.innerHTML = '<div style="background:#1a1f2e;border:1px solid #2a3045;border-radius:14px;padding:20px;min-width:320px;max-width:480px;width:90%;max-height:80vh;display:flex;flex-direction:column;gap:10px;">'
        + '<div style="font-size:14px;font-weight:700;color:var(--tx);">🗂 작업룸에 저장</div>'
        + '<div style="font-size:11px;color:var(--mu);">' + typeLabel + ' 결과를 저장할 작업룸을 선택하세요</div>'
        + '<div style="overflow-y:auto;max-height:300px;display:flex;flex-direction:column;gap:6px;">' + roomsHtml + '</div>'
        + '<button onclick="document.getElementById(\'calcRoomModal\').remove();" style="padding:8px;background:var(--s2);border:1px solid var(--b1);border-radius:8px;color:var(--mu);font-size:12px;cursor:pointer;font-family:inherit;">취소</button>'
        + '</div>';

      modal.addEventListener('click', function(e) { if (e.target === modal) modal.remove(); });
      document.body.appendChild(modal);
    };

    window._calcRoomSelect = function(roomId, type) {
      // 계산 결과 텍스트 수집
      const ts = new Date().toLocaleString('ko-KR');
      let content = '';
      const gv = id => { const el = document.getElementById(id); return el ? (el.value || el.textContent || '-').trim() : '-'; };

      const fmtV = id => { const el = document.getElementById(id); if (!el) return '-'; return (el.value || el.textContent || '-').trim() || '-'; };
      const fmtN = id => { const el = document.getElementById(id); if (!el) return '-'; const v = el.textContent.trim(); return v && v !== '-' ? v : '-'; };

      if (type === 'flip') {
        const caseNo = fmtV('fl_case');
        const bid     = fmtV('fl_bid');
        const app     = fmtV('fl_appraisal');
        const loan    = fmtN('fl_r_loan');
        const cost    = fmtN('fl_r_total_cost');
        const invest  = fmtN('fl_r_total_invest');
        const real    = fmtN('fl_r_real_invest');
        const profit  = fmtN('fl_r_net_profit');
        const roi     = fmtN('fl_r_roi');
        content = [
          '[ 🏠 주택 경매 수익분석 ]',
          '저장일시: ' + ts,
          caseNo && caseNo !== '-' ? '사건번호: ' + caseNo : null,
          '─────────────────────',
          '입찰가:    ' + bid,
          '감정가:    ' + app,
          '대출금:    ' + loan,
          '─────────────────────',
          '총 비용:   ' + cost,
          '총 투자금: ' + invest,
          '실투자금:  ' + real,
          '─────────────────────',
          '세후이익:  ' + profit,
          '순투자수익률: ' + roi,
        ].filter(l => l !== null).join('\n');
      } else {
        const caseNo  = fmtV('rt_case');
        const bid     = fmtV('rt_bid');
        const app     = fmtV('rt_appraisal');
        const dep     = fmtV('rt_deposit');
        const mon     = fmtV('rt_monthly');
        const real    = fmtN('rt_r_real');
        const yield1  = fmtN('rt_r_yield');
        const yield2  = fmtN('rt_r_yield2');
        const cashflow= fmtN('rt_r_cashflow');
        content = [
          '[ 🏢 상가 경매 수익분석 ]',
          '저장일시: ' + ts,
          caseNo && caseNo !== '-' ? '사건번호: ' + caseNo : null,
          '─────────────────────',
          '입찰가:     ' + bid,
          '감정가:     ' + app,
          '임대보증금: ' + dep,
          '월세:       ' + mon,
          '─────────────────────',
          '실투자금:   ' + real,
          '순현금흐름: ' + cashflow + '/월',
          '─────────────────────',
          '임대수익률: ' + yield1,
          '매매수익률: ' + yield2,
        ].filter(l => l !== null).join('\n');
      }

      // 작업룸 메모 섹션에 추가 (wr2State 방식)
      try {
        if (window.wr2State && window.wr2State.sections !== undefined) {
          // wr2 섹션 방식으로 저장
          const _targetPhase = type === 'flip' ? 'bid' : 'review';
          const roomSections = window.wr2State.sections.filter(s => s.roomId === roomId && s.type === 'memo' && s.phase === _targetPhase);
          // 해당 단계의 첫 번째 메모 섹션에 추가 (없으면 새로 생성)
          let targetSec = roomSections[0] || null;
          // ① 섹션(단계탭)에 저장
          if (targetSec) {
            targetSec.data.content = (targetSec.data.content ? targetSec.data.content + '\n\n---\n\n' : '') + content;
          } else {
            const newSec = {
              id: 'calc_' + Date.now(),
              roomId: roomId,
              phase: _targetPhase,
              type: 'memo',
              title: type === 'flip' ? '🏠 주택 계산 결과' : '🏢 상가 계산 결과',
              order: 999,
              data: { content: content }
            };
            window.wr2State.sections.push(newSec);
          }
          localStorage.setItem('wr2_sections', JSON.stringify(window.wr2State.sections));

          // ② 개요탭 노트 위젯(room.note)에도 추가 → 어느 탭에서든 바로 확인 가능
          const _room = window.wr2State.rooms.find(r => r.id === roomId);
          if (_room) {
            // AI 분석 결과를 노트에 추가
            if (!_room.notes) _room.notes = [];
            if (_room.notes.length === 0) { _room.notes.push({ id: 'note_' + Date.now().toString(36), title: '노트 1', body: '', createdAt: Date.now() }); }
            const _tgtNote = _room.notes[_room.notes.length - 1];
            const sep = _tgtNote.body ? '\n\n---\n\n' : '';
            _tgtNote.body = (_tgtNote.body || '') + sep + content;
            _tgtNote.updatedAt = Date.now();
            _room.updatedAt = Date.now();
            localStorage.setItem('wr2_rooms', JSON.stringify(window.wr2State.rooms));
          }

          // ③ 해당 작업룸 열고 단계탭으로 이동
          window.wr2State.activeRoomId = roomId;
          window.wr2State.activePhase = _targetPhase;
          window.wr2State.activeView = 'phase';
          showPage(3);
          showInsTab(8);
          setTimeout(function() {
            if (typeof window.wr2SwitchView === 'function') window.wr2SwitchView('phase');
            if (typeof window.wr2Render === 'function') window.wr2Render();
          }, 150);
          showToast('🗂 작업룸에 저장됐어요!', 'ok');
          return;
        }
      } catch(e) { console.error(e); }

      // fallback: wrDb 방식 (room.calcResults 배열)
      try {
        const rooms = wrGetRooms();
        const room = rooms.find(r => r.id === roomId);
        if (room) {
          if (!room.calcResults) room.calcResults = [];
          room.calcResults.push({ type, content, savedAt: Date.now() });
          room.updatedAt = Date.now();
          wrSetRooms(rooms);
          showToast('🗂 작업룸에 저장됨!', 'ok');
        }
      } catch(e) { showToast('저장 중 오류: ' + e.message, 'warn'); }
    };

    // ── 계산기 → 노트 저장 (기존 함수 확장) ────────────────
    function saveCalcToNote(type) {
      let content = '';
      const ts = new Date().toLocaleString('ko-KR');
      const fmtV = id => { const el = document.getElementById(id); if (!el) return '-'; return (el.value || el.textContent || '-').trim() || '-'; };
      const fmtN = id => { const el = document.getElementById(id); if (!el) return '-'; const v = el.textContent.trim(); return v && v !== '-' ? v : '-'; };
      if (type === 'flip') {
        const caseNo = fmtV('fl_case');
        content = [
          '[ 🏠 주택 경매 수익분석 ]',
          '저장일시: ' + ts,
          caseNo && caseNo !== '-' ? '사건번호: ' + caseNo : null,
          '입찰가: ' + fmtV('fl_bid') + ' | 감정가: ' + fmtV('fl_appraisal'),
          '실투자금: ' + fmtN('fl_r_real_invest'),
          '세후이익: ' + fmtN('fl_r_net_profit') + ' | 수익률: ' + fmtN('fl_r_roi'),
        ].filter(l => l !== null).join('\n');
      } else if (type === 'rent') {
        const caseNo = fmtV('rt_case');
        content = [
          '[ 🏢 상가 경매 수익분석 ]',
          '저장일시: ' + ts,
          caseNo && caseNo !== '-' ? '사건번호: ' + caseNo : null,
          '입찰가: ' + fmtV('rt_bid') + ' | 감정가: ' + fmtV('rt_appraisal'),
          '월세: ' + fmtV('rt_monthly') + ' | 보증금: ' + fmtV('rt_deposit'),
          '임대수익률: ' + fmtN('rt_r_yield') + ' | 매매수익률: ' + fmtN('rt_r_yield2'),
        ].filter(l => l !== null).join('\n');
      } else if (type === 'npl') {
        content = `[NPL 시뮬레이션 - ${ts}]\n입찰가: ${gv('npl_bid')}만원\n예상 배당금: ${document.getElementById('r_npl_div')?.textContent}\n실투자금: ${document.getElementById('r_npl_cash')?.textContent}\n배당 차익: ${document.getElementById('r_npl_profit')?.textContent}`;
      } else if (type === 'yield') {
        content = `[수익률 계산 - ${ts}]\n매입가: ${gv('yr_price')}만원 | 월세: ${gv('yr_rent')}만원\n총 수익률: ${document.getElementById('r_yr_gross')?.textContent} | 순 수익률: ${document.getElementById('r_yr_net')?.textContent}`;
      } else if (type === 'bid') {
        content = `[입찰가 분석 - ${ts}]\n임대료: ${gv('bd_rent')}만원/월 | 목표수익률: ${gv('bd_yr')}%\n적정 입찰가: ${document.getElementById('r_bd_price')?.textContent} (감정가 대비 ${document.getElementById('r_bd_ratio')?.textContent})`;
      } else if (type === 're') {
        content = `[부동산 수익 분석 - ${ts}]\n입찰가: ${document.getElementById('re_bid')?.value} | 매도가: ${document.getElementById('re_sell')?.value}\n세후이익: ${document.getElementById('r_re_net_profit')?.textContent} | 순투자수익률: ${document.getElementById('r_re_roi')?.textContent}`;
      }
      // ntActiveId로 현재 열린 노트 확인
      const _activeId = (typeof ntActiveId !== 'undefined') ? ntActiveId : null;
      const _notes = (typeof ntNotes !== 'undefined') ? ntNotes : [];
      if (_activeId) {
        const note = _notes.find(n => n.id === _activeId);
        if (note) {
          note.body += (note.body ? '\n\n' : '') + content;
          note.updatedAt = new Date().toISOString();
          if (typeof ntSave === 'function') ntSave();
          if (typeof ntRender === 'function') ntRender();
          showPage(3);
          showInsTab(0);
          showToast('📓 노트에 저장됐어요!', 'ok');
          return;
        }
      }
      // 현재 노트 없으면 새 노트 생성
      const note = { id: 'note_' + Date.now(), title: '계산 결과 ' + new Date().toLocaleDateString('ko-KR'), body: content, tags: ['계산기'], linkedItemId: null, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      _notes.unshift(note);
      if (typeof ntSave === 'function') ntSave();
      // 인사이트탭 > 노트로 자동 이동
      showPage(3);
      showInsTab(0);
      setTimeout(() => { if (typeof ntOpen === 'function') ntOpen(note.id); }, 150);
      showToast('📓 노트에 저장됐어요!', 'ok');
    }

    function saveCalcToItemMemo(type) {
      if (!nplLinkedItemId) { showToast('물건을 먼저 연결하세요', 'warn'); return; }
      const sv = getSv(); const item = sv.find(s => s.id === nplLinkedItemId);
      if (!item) { showToast('물건을 찾을 수 없습니다', 'warn'); return; }
      const ts = new Date().toLocaleString('ko-KR');
      const memo = `[NPL 시뮬레이션 - ${ts}]\n입찰가: ${gv('npl_bid')}만원\n배당: ${document.getElementById('r_npl_div')?.textContent} | 차익: ${document.getElementById('r_npl_profit')?.textContent}`;
      item.memo = (item.memo ? item.memo + '\n\n' : '') + memo;
      setSv(sv); showToast(`✅ [${item.title || item.id}] 메모에 저장됨`, 'ok');
    }

    // ═══════════════════════════════════════════════════
    // 📰 뉴스 클리핑
    // ═══════════════════════════════════════════════════
    // ═══════════════════════════════════════════════════
    // 📰 뉴스 클리핑 - 네이버 자동수집 + Gemini 분석
    // ═══════════════════════════════════════════════════

    let newsClips = JSON.parse(localStorage.getItem('ins_news') || '[]');
    let newsKeywords = JSON.parse(localStorage.getItem('ins_kw') || '["상가 경매","토지 경매","경매 낙찰가율","GTX 호재","상권 개발"]');
    let newsFeedCache = JSON.parse(localStorage.getItem('ins_feed') || '{}'); // {keyword: [{title,link,pubDate,description}]}
    let newsFeedActiveKw = null; // 현재 보여주는 키워드 (null=전체)

    function saveNewsData() { localStorage.setItem('ins_news', JSON.stringify(newsClips)); }
    function saveKeywords() { localStorage.setItem('ins_kw', JSON.stringify(newsKeywords)); }
    function saveFeedCache() { localStorage.setItem('ins_feed', JSON.stringify(newsFeedCache)); }

    // ── 네이버 API 키 헬퍼 ─────────────────────────────
    function getNaverKeys() {
      const id = document.getElementById('naverClientId')?.value?.trim() || localStorage.getItem('naver_id') || '';
      const sec = document.getElementById('naverClientSecret')?.value?.trim() || localStorage.getItem('naver_sec') || '';
      return { id, sec };
    }

    // ── 네이버 API 키 저장/상태 초기화 ────────────────
    (() => {
      const id = localStorage.getItem('naver_id'), sec = localStorage.getItem('naver_sec');
      if (id && document.getElementById('naverClientId')) document.getElementById('naverClientId').value = id;
      if (sec && document.getElementById('naverClientSecret')) document.getElementById('naverClientSecret').value = sec;
      if (id && sec) document.getElementById('naverDot')?.classList.add('on');
      ['naverClientId', 'naverClientSecret'].forEach(elId => {
        document.getElementById(elId)?.addEventListener('input', () => {
          const { id: i, sec: s } = getNaverKeys();
          const ok = i.length > 3 && s.length > 3;
          document.getElementById('naverDot')?.classList.toggle('on', ok);
          if (ok) { localStorage.setItem('naver_id', i); localStorage.setItem('naver_sec', s); }
        });
      });
    })();

    // ── 키워드 렌더 ────────────────────────────────────
    function renderKeywords() {
      const el = document.getElementById('kwList'); if (!el) return;
      el.innerHTML = newsKeywords.map((kw, i) => `
    <div style="display:flex;align-items:center;gap:5px;padding:4px 6px;background:var(--s2);border-radius:5px;border:1px solid var(--b1);">
      <span style="flex:1;font-size:11px;color:var(--tx);cursor:pointer;" onclick="setFeedKw('${kw}')">${kw}</span>
      <button onclick="removeKeyword(${i})" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:12px;line-height:1;">×</button>
    </div>`).join('');
      renderFeedTabs();
    }

    function addKeyword() {
      const inp = document.getElementById('kwInput'); if (!inp) return;
      const kw = inp.value.trim(); if (!kw) return;
      if (newsKeywords.includes(kw)) { showToast('이미 있는 키워드예요', 'warn'); return; }
      newsKeywords.push(kw); saveKeywords(); renderKeywords();
      inp.value = ''; showToast(`'${kw}' 추가됨`, 'ok');
    }

    function removeKeyword(i) {
      newsKeywords.splice(i, 1); saveKeywords(); renderKeywords();
    }

    // ── 피드 탭 (키워드별 필터) ───────────────────────
    function renderFeedTabs() {
      const el = document.getElementById('newsFeedTabs'); if (!el) return;
      const tabs = [{ label: '전체', kw: null }, ...newsKeywords.map(kw => ({ label: kw, kw }))];
      el.innerHTML = tabs.map(t => `
    <button onclick="setFeedKw(${t.kw === null ? 'null' : `'${t.kw}'`})"
      style="padding:3px 9px;font-size:11px;border-radius:12px;cursor:pointer;white-space:nowrap;
      background:${newsFeedActiveKw === t.kw ? 'var(--ac)' : 'var(--s2)'};
      color:${newsFeedActiveKw === t.kw ? '#111' : 'var(--tx)'};
      border:1px solid ${newsFeedActiveKw === t.kw ? 'var(--ac)' : 'var(--b1)'};">
      ${t.label}
    </button>`).join('');
    }

    function setFeedKw(kw) { newsFeedActiveKw = kw; renderFeedTabs(); renderFeedList(); }

    // ── 피드 목록 렌더 ─────────────────────────────────
    function renderFeedList() {
      const el = document.getElementById('newsFeedList'); if (!el) return;

      // 표시할 키워드 목록
      const kwsToShow = newsFeedActiveKw ? [newsFeedActiveKw] : newsKeywords;

      // 모든 기사 합치기 (중복 제거)
      const seen = new Set();
      const items = [];
      kwsToShow.forEach(kw => {
        (newsFeedCache[kw] || []).forEach(item => {
          if (!seen.has(item.link)) { seen.add(item.link); items.push({ ...item, kw }); }
        });
      });

      // 날짜순 정렬
      items.sort((a, b) => new Date(b.pubDate) - new Date(a.pubDate));

      if (!items.length) {
        el.innerHTML = '<div style="color:var(--mu);font-size:12px;text-align:center;padding:40px 0;">키워드를 추가하고 🔄 새로고침 버튼을 눌러주세요</div>';
        return;
      }

      el.innerHTML = items.map((item, i) => {
        const desc = (item.description || '').replace(/<[^>]+>/g, '').slice(0, 100);
        const date = new Date(item.pubDate).toLocaleDateString('ko-KR', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' });
        return `<div style="padding:10px;background:var(--s2);border-radius:8px;border:1px solid var(--b1);border-left:3px solid var(--ac);">
      <div style="display:flex;align-items:flex-start;gap:6px;">
        <span style="font-size:10px;background:rgba(167,139,250,0.15);color:var(--ac);padding:1px 5px;border-radius:3px;white-space:nowrap;flex-shrink:0;">${item.kw}</span>
        <a href="${item.link}" target="_blank" style="font-size:12px;font-weight:600;color:var(--tx);text-decoration:none;line-height:1.4;flex:1;"
          onmouseover="this.style.color='var(--ac)'" onmouseout="this.style.color='var(--tx)'">${item.title.replace(/<[^>]+>/g, '')}</a>
        <button onclick="scrapFeedItem(${i},'${encodeURIComponent(JSON.stringify(item))}')" title="스크랩"
          style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:15px;flex-shrink:0;padding:0;">⭐</button>
      </div>
      ${desc ? `<div style="font-size:11px;color:var(--mu);margin-top:5px;line-height:1.5;">${esc(desc)}...</div>` : ''}
      <div style="font-size:10px;color:var(--di);margin-top:6px;">${date}</div>
    </div>`;
      }).join('');
    }

    // ── 네이버 뉴스 API 호출 ─────────────────────────
    async function fetchNaverNews() {
      if (!newsKeywords.length) { showToast('키워드를 먼저 추가해주세요', 'warn'); return; }
      const { id, sec } = getNaverKeys();
      if (!id || !sec) { showToast('상단에 Naver API 키를 입력해주세요', 'warn'); return; }

      const btn = document.getElementById('newsFetchBtn');
      const status = document.getElementById('newsFeedStatus');
      if (btn) { btn.disabled = true; btn.textContent = '⏳ 수집 중...'; }
      if (status) status.textContent = '';

      let successCount = 0, failCount = 0;

      // localhost:8000에서는 네이버 앱 설정에 등록된 경우 직접 호출 가능
      for (const kw of newsKeywords) {
        try {
          const resp = await fetch(`https://openapi.naver.com/v1/search/news.json?query=${encodeURIComponent(kw)}&display=10&sort=date`, {
            headers: {
              'X-Naver-Client-Id': id,
              'X-Naver-Client-Secret': sec
            }
          });
          if (!resp.ok) throw new Error('HTTP ' + resp.status);
          const data = await resp.json();
          newsFeedCache[kw] = data.items || [];
          successCount++;
        } catch (e) {
          console.warn('Naver API 오류 [' + kw + ']:', e.message);
          failCount++;
          if (!newsFeedCache[kw]) newsFeedCache[kw] = [];
        }
      }

      saveFeedCache();
      renderFeedList();

      if (btn) { btn.disabled = false; btn.textContent = '🔄 새로고침'; }

      if (successCount > 0) {
        const now = new Date().toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' });
        if (status) status.textContent = `최종: ${now}`;
        showToast(`${successCount}개 키워드 수집 완료`, 'ok');
      } else if (failCount > 0) {
        showToast('CORS 오류: 아래 안내 확인', 'warn');
        const el = document.getElementById('newsFeedList');
        if (el) el.innerHTML = `
      <div style="padding:16px;background:rgba(255,99,112,0.08);border:1px solid rgba(255,99,112,0.2);border-radius:10px;">
        <div style="font-size:13px;font-weight:700;color:#ff6370;margin-bottom:10px;">⚠️ 네이버 API CORS 오류</div>
        <div style="font-size:12px;color:var(--tx);line-height:1.9;">
          <b style="color:var(--warn);">원인:</b> 네이버 검색 API는 서버사이드 전용으로, 브라우저에서 직접 호출 시 CORS 정책에 막힙니다.<br><br>
          <b style="color:var(--ac);">해결법 1 (권장):</b> 네이버 개발자 센터 → 내 애플리케이션 → <b>환경 추가</b>에서<br>
          &nbsp;&nbsp;• 서비스 환경: <code style="background:var(--s1);padding:2px 5px;border-radius:3px;">WEB 설정</code><br>
          &nbsp;&nbsp;• 웹 서비스 URL: <code style="background:var(--s1);padding:2px 5px;border-radius:3px;">http://localhost:8000</code> 으로 등록<br><br>
          <b style="color:var(--ac);">해결법 2:</b> Chrome 보안 해제 모드로 실행:<br>
          <code style="font-size:10px;background:var(--s1);padding:6px 8px;border-radius:4px;display:block;margin-top:6px;word-break:break-all;">/Applications/Google\ Chrome.app/Contents/MacOS/Google\ Chrome --disable-web-security --user-data-dir=/tmp/chrome_dev</code>
          <div style="margin-top:10px;font-size:11px;color:var(--mu);">* 해결법 2는 개발/테스트용으로만 사용하세요</div>
        </div>
      </div>`;
      }
    }

    // ── 스크랩 저장 ────────────────────────────────────
    function scrapFeedItem(i, encoded) {
      let item;
      try { item = JSON.parse(decodeURIComponent(encoded)); } catch (e) { return; }
      const title = (item.title || '').replace(/<[^>]+>/g, '');
      const desc = (item.description || '').replace(/<[^>]+>/g, '');
      newsClips.unshift({
        id: 'clip_' + Date.now(),
        title,
        text: title + (desc ? ('\n\n' + desc) : ''),
        link: item.link || '',
        kw: item.kw || '',
        analysis: '',
        savedAt: new Date().toISOString()
      });
      saveNewsData(); renderNewsClips();
      showToast('스크랩 저장됨 ⭐', 'ok');
    }

    // ── 스크랩 보관함 렌더 ─────────────────────────────
    let clipFilterMode = 'all';
    function filterClips(mode) {
      clipFilterMode = mode;
      ['all', 'link', 'news'].forEach(m => {
        const btn = document.getElementById('clipFilter_' + m);
        if (btn) {
          btn.style.background = m === mode ? 'var(--ac)' : 'var(--s2)';
          btn.style.color = m === mode ? '#111' : 'var(--mu)';
          btn.style.border = m === mode ? 'none' : '1px solid var(--b1)';
        }
      });
      renderNewsClips();
    }
    function renderNewsClips() {
      const list = document.getElementById('newsClipList'); if (!list) return;
      let clips = newsClips;
      if (clipFilterMode === 'link') clips = clips.filter(c => c.clipType === 'link');
      else if (clipFilterMode === 'news') clips = clips.filter(c => c.clipType !== 'link');
      if (!clips.length) {
        list.innerHTML = '<div style="color:var(--mu);font-size:12px;text-align:center;padding:30px 0;">⭐ 뉴스 옆 별표를 눌러 스크랩하거나<br>링크/YouTube를 저장해보세요</div>';
        return;
      }
      list.innerHTML = clips.map((c, i) => {
        const realIdx = newsClips.indexOf(c);
        const d = new Date(c.savedAt).toLocaleDateString('ko-KR', { month: 'numeric', day: 'numeric' });
        const title = c.title || c.text?.slice(0, 50) || '제목 없음';
        const isYt = c.link && (c.link.includes('youtube.com') || c.link.includes('youtu.be'));
        const isLink = c.clipType === 'link';
        const typeIcon = isYt ? '🎬' : isLink ? '🔗' : '📰';
        const typeBg = isYt ? 'rgba(255,80,80,.12)' : isLink ? 'rgba(79,142,255,.1)' : 'rgba(167,139,250,.08)';
        const typeBorder = isYt ? 'rgba(255,80,80,.2)' : isLink ? 'rgba(79,142,255,.2)' : 'rgba(167,139,250,.15)';
        return `<div style="padding:9px 10px;background:var(--s2);border-radius:8px;border:1px solid var(--b1);border-left:3px solid ${isYt ? '#ff5050' : isLink ? 'var(--ac)' : 'var(--g)'};">
      <div style="display:flex;align-items:flex-start;gap:5px;margin-bottom:4px;">
        <span style="font-size:13px;flex-shrink:0;">${typeIcon}</span>
        <span style="flex:1;font-size:12px;font-weight:600;color:var(--tx);line-height:1.4;">${esc(title)}</span>
        <button onclick="newsClips.splice(${realIdx},1);saveNewsData();renderNewsClips();" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:12px;flex-shrink:0;">×</button>
      </div>
      ${c.memo ? `<div style="font-size:11px;color:var(--warn);margin:4px 0;font-style:italic;">📝 ${esc(c.memo)}</div>` : ''}
      ${c.kw ? `<span style="font-size:10px;color:var(--ac);">#${c.kw}</span>` : ''}
      <div style="display:flex;gap:5px;margin-top:7px;flex-wrap:wrap;">
        ${c.link ? `<a href="${c.link}" target="_blank" style="font-size:10px;color:var(--mu);text-decoration:none;padding:2px 6px;background:var(--bg);border:1px solid var(--b1);border-radius:4px;">${isYt ? '▶ 영상보기' : '원문'}</a>` : ''}
        <button onclick="analyzeClip(${realIdx})" style="font-size:10px;color:var(--ac);background:rgba(167,139,250,0.1);border:1px solid rgba(79,142,255,0.2);border-radius:4px;padding:2px 6px;cursor:pointer;">🤖 AI분석</button>
        <button onclick="clipToKcard(${realIdx})" style="font-size:10px;color:#ffd166;background:rgba(255,209,102,0.1);border:1px solid rgba(255,209,102,0.2);border-radius:4px;padding:2px 6px;cursor:pointer;">⭐ 알짜정보화</button>
        <button onclick="clipToNote(${realIdx})" style="font-size:10px;color:var(--mu);background:var(--bg);border:1px solid var(--b1);border-radius:4px;padding:2px 6px;cursor:pointer;">📓 노트저장</button>
      </div>
      ${c.analysis ? `<div style="font-size:11px;color:var(--tx);margin-top:7px;padding:7px;background:${typeBg};border-radius:5px;border:1px solid ${typeBorder};line-height:1.6;white-space:pre-wrap;">${esc(c.analysis)}</div>` : ''}
      <div style="font-size:10px;color:var(--di);margin-top:5px;">${d}</div>
    </div>`;
      }).join('');
    }

    // ── 링크/YouTube 저장 ─────────────────────────────────
    function toggleClipScript() {
      const area = document.getElementById('clipScriptArea');
      const toggle = document.getElementById('clipScriptToggle');
      if (!area) return;
      const shown = area.style.display !== 'none';
      area.style.display = shown ? 'none' : '';
      toggle.textContent = (shown ? '▶' : '▼') + ' 스크립트 붙여넣기 (AI 요약용)';
    }

    function saveClipLink() {
      const link = (document.getElementById('clipLinkInput')?.value || '').trim();
      const memo = (document.getElementById('clipMemoInput')?.value || '').trim();
      const script = (document.getElementById('clipScriptInput')?.value || '').trim();
      if (!link) { showToast('링크를 입력해주세요', 'warn'); return; }
      const isYt = link.includes('youtube.com') || link.includes('youtu.be');
      const title = isYt ? 'YouTube 영상' : link.replace(/https?:\/\//, '').slice(0, 50);
      newsClips.unshift({
        id: 'clip_' + Date.now(),
        clipType: 'link',
        title,
        link,
        memo,
        script,
        text: memo || title,
        analysis: '',
        savedAt: new Date().toISOString()
      });
      saveNewsData(); renderNewsClips();
      // 입력 초기화
      if (document.getElementById('clipLinkInput')) document.getElementById('clipLinkInput').value = '';
      if (document.getElementById('clipMemoInput')) document.getElementById('clipMemoInput').value = '';
      if (document.getElementById('clipScriptInput')) document.getElementById('clipScriptInput').value = '';
      if (document.getElementById('clipAiQueryInput')) document.getElementById('clipAiQueryInput').value = '';
      showToast('링크 저장됨 🔗', 'ok');
    }

    async function saveClipLinkWithAI() {
      const link = (document.getElementById('clipLinkInput')?.value || '').trim();
      const memo = (document.getElementById('clipMemoInput')?.value || '').trim();
      const script = (document.getElementById('clipScriptInput')?.value || '').trim();
      const aiQuery = (document.getElementById('clipAiQueryInput')?.value || '').trim();
      if (!link) { showToast('링크를 입력해주세요', 'warn'); return; }
      const apiKey = gk();
      if (!apiKey) { showToast('Gemini API 키가 필요합니다', 'warn'); return; }

      const isYt = link.includes('youtube.com') || link.includes('youtu.be');
      const title = isYt ? 'YouTube 영상' : link.replace(/https?:\/\//, '').slice(0, 50);

      // 먼저 저장
      const clip = {
        id: 'clip_' + Date.now(),
        clipType: 'link',
        title,
        link,
        memo,
        script,
        text: memo || title,
        analysis: '⏳ AI 분석 중...',
        savedAt: new Date().toISOString()
      };
      newsClips.unshift(clip); saveNewsData(); renderNewsClips();

      // 입력 초기화
      if (document.getElementById('clipLinkInput')) document.getElementById('clipLinkInput').value = '';
      if (document.getElementById('clipMemoInput')) document.getElementById('clipMemoInput').value = '';
      if (document.getElementById('clipScriptInput')) document.getElementById('clipScriptInput').value = '';
      if (document.getElementById('clipAiQueryInput')) document.getElementById('clipAiQueryInput').value = '';

      // AI 분석
      try {
        let promptText = '';
        if (script) {
          promptText = `다음은 유튜브 영상 스크립트입니다:\n링크: ${link}\n${memo ? '메모: ' + memo : ''}\n\n스크립트:\n${script}\n\n`;
          if (aiQuery) {
            promptText += `사용자 요청: ${aiQuery}\n\n`;
          } else {
            promptText += `이 영상에서 부동산/경매 투자에 중요한 핵심 정보를 추출해서 정리해주세요.\n`;
          }
          promptText += `형식:\n📍 핵심 요약: (2-3줄)\n💡 주요 공식/방법론: (있으면)\n🎯 투자 시사점: (경매 투자 관점)\n📌 기억할 포인트: (불릿 포인트 3-5개)`;
        } else {
          promptText = `다음 링크/내용을 부동산 투자자 관점에서 분석해주세요:\n링크: ${link}\n${memo ? '메모: ' + memo : ''}\n${aiQuery ? '질문: ' + aiQuery : ''}\n\n형식:\n📍 핵심: (2줄)\n💡 투자 시사점: (2-3줄)\n📌 기억할 포인트: (불릿 포인트)`;
        }

        clip.analysis = await geminiText(promptText);
        if (!clip.analysis) clip.analysis = '분석 실패 (응답 없음)';
      } catch (e) { clip.analysis = '❌ AI 오류: ' + e.message + '\n\n(API 키 확인 또는 잠시 후 재시도)'; }
      saveNewsData(); renderNewsClips();
      showToast('링크 저장 + AI 분석 완료 ✨', 'ok');
    }

    // ── 클립 → 지식 카드화 ───────────────────────────────
    function clipToKcard(i) {
      const clip = newsClips[i]; if (!clip) return;
      // 지식 카드 탭으로 이동하고 새 카드 편집기 열기
      showInsTab(4);
      setTimeout(() => {
        openKcardEditor(null);
        const title = clip.title || clip.link || '제목 없음';
        if (document.getElementById('kcardTitle')) document.getElementById('kcardTitle').value = title.slice(0, 60);
        const body = [
          clip.link ? `🔗 ${clip.link}` : '',
          clip.memo ? `📝 메모: ${clip.memo}` : '',
          '',
          clip.analysis ? clip.analysis : clip.text || ''
        ].filter(Boolean).join('\n');
        if (document.getElementById('kcardBody')) document.getElementById('kcardBody').value = body;
        if (document.getElementById('kcardTags')) document.getElementById('kcardTags').value = clip.clipType === 'link' ? '링크, 영상' : '뉴스, 클리핑';
      }, 200);
    }

    // ── 스크랩 AI 분석 ─────────────────────────────────
    async function analyzeClip(i) {
      const clip = newsClips[i]; if (!clip) return;
      const apiKey = gk();
      if (!apiKey) { showToast('Gemini API 키가 필요합니다', 'warn'); return; }
      clip.analysis = '⏳ 분석 중...'; renderNewsClips();
      try {
        let promptContent = '';
        if (clip.clipType === 'link' && clip.script) {
          promptContent = `다음 유튜브/영상 스크립트를 분석해주세요:\n링크: ${clip.link}\n${clip.memo ? '메모: ' + clip.memo : ''}\n\n스크립트:\n${clip.script}\n\n형식:\n📍 핵심 요약: (2-3줄)\n💡 주요 공식/방법론: (있으면)\n🎯 투자 시사점:\n📌 기억할 포인트: (불릿 포인트)`;
        } else if (clip.clipType === 'link') {
          promptContent = `다음 링크를 부동산 투자자 관점에서 분석해주세요:\n링크: ${clip.link}\n${clip.memo ? '메모: ' + clip.memo : ''}\n\n형식:\n📍 핵심: (2줄)\n💡 투자 시사점: (2-3줄)\n📌 기억할 포인트: (불릿 포인트)`;
        } else {
          promptContent = `다음 부동산 뉴스를 상가/토지 경매 투자자 관점에서 분석해주세요:\n\n${clip.text || clip.title}\n\n형식:\n📍 핵심: (1줄)\n🏙️ 수혜지역: (지역명)\n💡 투자 시사점: (2-3줄)\n⚠️ 리스크:`;
        }
        clip.analysis = await geminiText(promptContent);
        if (!clip.analysis) clip.analysis = '분석 실패';
        const regions = (clip.analysis.match(/[가-힣]+[시군구동읍면리]+/g) || []);
        clip.regions = [...new Set(regions)].slice(0, 5);
      } catch (e) { clip.analysis = '오류: ' + e.message; }
      saveNewsData(); renderNewsClips();
    }

    // ── 스크랩 → 노트 저장 ────────────────────────────
    function clipToNote(i) {
      const clip = newsClips[i]; if (!clip) return;
      const title = clip.title || clip.text.slice(0, 30);
      const body = [
        '📰 뉴스 클리핑',
        `제목: ${title}`,
        clip.link ? `링크: ${clip.link}` : '',
        '',
        clip.analysis ? ('🤖 AI 분석:\n' + clip.analysis) : '',
      ].filter(Boolean).join('\n');
      // createNote 함수 활용
      const note = { id: 'note_' + Date.now(), title: '[뉴스] ' + title.slice(0, 20), body, tags: ['뉴스클리핑'], linkedItemId: null, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      insNotes.unshift(note); saveNotes(); renderNotes();
      showInsTab(0); setTimeout(() => openNote(note.id), 100);
      showToast('노트에 저장됨 📓', 'ok');
    }

    // ── 붙여넣기 분석 (기존 유지) ──────────────────────
    async function analyzeNews() {
      const txt = document.getElementById('newsInput')?.value?.trim();
      if (!txt) { showToast('분석할 뉴스 내용을 입력하세요', 'warn'); return; }
      const apiKey = gk();
      if (!apiKey) { showToast('Gemini API 키가 필요합니다 (상단에 입력)', 'warn'); return; }
      const box = document.getElementById('newsResultBox'); const res = document.getElementById('newsResult');
      box.style.display = ''; res.textContent = '⏳ AI 분석 중...';
      try {
        const text = await geminiText(`다음 부동산/개발 뉴스를 분석해주세요:\n\n${txt}\n\n형식:\n📍 핵심 내용: (2줄 요약)\n🏙️ 관련 지역: (지역명 나열)\n📈 부동산 영향: (상가/토지/주거 각각 예상 영향)\n💡 투자 시사점: (경매/투자 관점에서 체크할 포인트)\n⚠️ 주의사항: (리스크)`);
        res.textContent = text || '분석 실패';
        const regions = (text.match(/[가-힣]+[시군구동읍면리]+/g) || []);
        const tagWrap = document.getElementById('newsRegionTags');
        if (tagWrap) tagWrap.innerHTML = [...new Set(regions)].slice(0, 8).map(r =>
          `<span class="ntag" onclick="filterSavedByRegion('${r}')" title="저장목록에서 ${r} 검색">#${r}</span>`
        ).join('');
      } catch (e) { res.textContent = '오류: ' + e.message; }
    }

    function saveNewsClip() {
      const txt = document.getElementById('newsInput')?.value?.trim();
      if (!txt) { showToast('저장할 내용을 입력하세요', 'warn'); return; }
      const result = document.getElementById('newsResult')?.textContent || '';
      newsClips.unshift({ id: 'clip_' + Date.now(), title: txt.slice(0, 50), text: txt, link: '', kw: '직접입력', analysis: result, savedAt: new Date().toISOString() });
      saveNewsData(); renderNewsClips(); showToast('뉴스 클리핑 저장됨', 'ok');
      document.getElementById('newsInput').value = '';
    }

    function clearNewsClips() { if (confirm('전체 클리핑을 삭제하시겠습니까?')) { newsClips = []; saveNewsData(); renderNewsClips(); } }
    function filterSavedByRegion(r) { showPage(1); setTimeout(() => { const el = document.getElementById('regionSearch'); if (el) { el.value = r; renderSaved(); } }, 100); }

    // ── 초기 렌더 ──────────────────────────────────────
    renderKeywords();
    renderFeedList();

    // ═══════════════════════════════════════════════════
    // 📊 나의 기준 & 체크리스트
    // ═══════════════════════════════════════════════════
    const DEFAULT_VARS = [
      { label: '1층 대비 2층 임대료', value: '40~50%' },
      { label: '목표 최소 수익률', value: '6.5%' },
      { label: '경락대출 기준 이율', value: '3.8%' },
      { label: '상가 취득세율', value: '4.6%' },
      { label: '명도 평균 비용', value: '200~500만원' },
    ];
    const DEFAULT_CL = [
      '권리분석 기본 이해 (말소기준권리)',
      '임차인 대항력 체크 방법',
      '현장 방문 체크리스트 작성',
      '입찰 전 등기부등본 최종 확인',
      '명도 절차 및 비용 파악',
      '낙찰 후 취득세 납부 기한 확인',
    ];

    function loadInvestVars() { return JSON.parse(localStorage.getItem('ins_vars') || JSON.stringify(DEFAULT_VARS)); }
    function saveInvestVars(vars) { localStorage.setItem('ins_vars', JSON.stringify(vars)); }
    function loadChecklist() { return JSON.parse(localStorage.getItem('ins_cl') || JSON.stringify(DEFAULT_CL.map((t, i) => ({ id: i, text: t, done: false })))); }
    function saveChecklist(cl) { localStorage.setItem('ins_cl', JSON.stringify(cl)); }

    function renderInvestVars() {
      const list = document.getElementById('investVarList'); if (!list) return;
      const vars = loadInvestVars();
      list.innerHTML = vars.map((v, i) => `
    <div class="ivar-row">
      <input value="${esc(v.label)}" onchange="updateVar(${i},'label',this.value)" style="flex:1;">
      <input value="${esc(v.value)}" onchange="updateVar(${i},'value',this.value)" style="width:90px;text-align:right;color:var(--ac);font-weight:700;">
      <button onclick="removeVar(${i})" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:16px;padding:0 2px;">×</button>
    </div>`).join('');
    }
    function updateVar(i, key, val) { const v = loadInvestVars(); v[i][key] = val; saveInvestVars(v); }
    function addInvestVar() { const v = loadInvestVars(); v.push({ label: '새 변수', value: '0%' }); saveInvestVars(v); renderInvestVars(); }
    function removeVar(i) { const v = loadInvestVars(); v.splice(i, 1); saveInvestVars(v); renderInvestVars(); }

    function renderChecklist() {
      const list = document.getElementById('studyChecklist'); if (!list) return;
      const cl = loadChecklist();
      list.innerHTML = cl.map((item, i) => `
    <div class="ck-item">
      <input type="checkbox" ${item.done ? 'checked' : ''} onchange="toggleCl(${i})" style="width:15px;height:15px;accent-color:var(--ac);cursor:pointer;">
      <span style="font-size:12px;color:var(--tx);flex:1;${item.done ? 'text-decoration:line-through;opacity:.5' : ''}">${esc(item.text)}</span>
      <button onclick="removeCl(${i})" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:13px;">×</button>
    </div>`).join('');
    }
    function toggleCl(i) { const cl = loadChecklist(); cl[i].done = !cl[i].done; saveChecklist(cl); renderChecklist(); refreshInsStats(); }
    function removeCl(i) { const cl = loadChecklist(); cl.splice(i, 1); saveChecklist(cl); renderChecklist(); }
    function addChecklistItem() {
      const txt = prompt('새 항목 이름을 입력하세요'); if (!txt || !txt.trim()) return;
      const cl = loadChecklist(); cl.push({ id: Date.now(), text: txt.trim(), done: false }); saveChecklist(cl); renderChecklist();
    }

    // ── 기준값 → 계산기에 반영 ──────────────────────────
    function applyVarsToCalc() {
      const vars = loadInvestVars();
      // 숫자 추출 헬퍼 (예: "3.8%" → 3.8, "6.5%" → 6.5)
      const extractNum = (s) => {
        if (!s) return null;
        const m = String(s).match(/[\d.]+/);
        return m ? parseFloat(m[0]) : null;
      };

      let applied = [];
      vars.forEach(v => {
        const lbl = (v.label || '').toLowerCase();
        const num = extractNum(v.value);
        if (num === null) return;

        // 목표 수익률 → 입찰가 계산기
        if (lbl.includes('수익률') && lbl.includes('목표')) {
          const el = document.getElementById('bd_yr');
          if (el) { el.value = num; calcBid(); applied.push('목표수익률→입찰가계산기'); }
          const yrEl = document.getElementById('yr_rate');
          // 수익률 계산기의 금리는 별도
        }
        // 대출 이율 → 수익률 계산기
        if (lbl.includes('이율') || lbl.includes('금리') || lbl.includes('이자')) {
          const el = document.getElementById('yr_rate');
          if (el) { el.value = num; calcYield(); applied.push('대출이율→수익률계산기'); }
        }
        // 취득세율 → 입찰가 계산기
        if (lbl.includes('취득세')) {
          const el = document.getElementById('bd_tax');
          if (el) { el.value = num; calcBid(); applied.push('취득세율→입찰가계산기'); }
        }
      });

      if (applied.length > 0) {
        showInsTab(1); // 계산기 탭으로 이동
        showToast('기준값 반영 완료: ' + applied.join(', '), 'ok');
      } else {
        showToast('반영할 수 있는 수치형 기준값이 없습니다 (예: 6.5%, 3.8%)', 'warn');
      }
    }

    function refreshInsStats() {
      const sv = getSv();
      const linked = insNotes.filter(n => n.linkedItemId).length;
      const cl = loadChecklist();
      const done = cl.filter(c => c.done).length;
      const s = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
      s('stat_notes', insNotes.length + '개');
      s('stat_clips', newsClips.length + '개');
      s('stat_linked', linked + '개');
      s('stat_saved', sv.length + '개');
    }

    // ═══════════════════════════════════════════════════
    // 📚 지식 카드 시스템
    // ═══════════════════════════════════════════════════

    let kcards = JSON.parse(localStorage.getItem('ins_kcards') || '[]');
    let kcardCats = JSON.parse(localStorage.getItem('ins_kcat') || '["📐 면적/건축","⚖️ 권리분석","📋 경매 절차","💰 세금/비용","🏘️ 상권/지역"]');
    let kcardEditId = null; // 수정 중인 카드 ID (null=새 카드)
    let kcardActiveCat = '전체'; // 현재 필터 카테고리


    // ── v236: 알짜정보 → 노트 만들기 ──────────────────────
    window.ntCreateFromKcard = function (kcardId) {
      const card = kcards.find(k => k.id === kcardId);
      if (!card) { showToast('카드를 찾을 수 없습니다', 'err'); return; }

      const note = {
        id: 'nt_' + Date.now(),
        type: 'unified',
        title: card.title || '알짜정보 노트',
        tags: [...(card.tags || []), card.cat || '알짜정보'],
        domain: _kcatToDomain(card.cat),
        phase: null,
        linkedItemId: null,
        linkedItemSnapshot: null,
        body: '📌 출처: ' + (card.sourceUrl || card.cat || '알짜정보') + '\n\n' + (card.body || '') + '\n\n---\n✏️ 내 생각:\n',
        url: card.sourceUrl || '',
        timestamps: [],
        excerpt: (card.body || '').substring(0, 100),
        comment: '',
        attachments: [],
        youtubeUrls: [],
        articleUrls: [],
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        fromKcardId: kcardId,
      };
      ntNotes.unshift(note);
      ntSave();
      showPage(3);
      showInsTab(0);
      // 학습·정보 모드로 전환
      setTimeout(() => {
        ntSetMode('study');
        ntRender();
        ntOpen(note.id);
      }, 80);
      showToast('📝 알짜정보가 노트로 저장됐어요', 'ok');
    };

    function _kcatToDomain(cat) {
      if (!cat) return 'auction';
      if (cat.includes('권리')) return 'legal';
      if (cat.includes('세금') || cat.includes('비용')) return 'tax';
      if (cat.includes('상권') || cat.includes('지역')) return 'market';
      if (cat.includes('면적') || cat.includes('건축') || cat.includes('절차')) return 'operation';
      return 'auction';
    }

    function saveKcards() { localStorage.setItem('ins_kcards', JSON.stringify(kcards)); }
    function saveKcardCats() { localStorage.setItem('ins_kcat', JSON.stringify(kcardCats)); }

    // ── 카테고리 탭 렌더 ───────────────────────────────
    function renderKcatTabs() {
      const el = document.getElementById('kcatTabs'); if (!el) return;
      const cats = ['전체', ...kcardCats];
      el.innerHTML = cats.map(c => `
    <button onclick="setKcardCat('${c}')"
      style="padding:5px 12px;font-size:11px;border-radius:14px;cursor:pointer;white-space:nowrap;transition:all .15s;
      background:${kcardActiveCat === c ? 'var(--ac)' : 'var(--s2)'};
      color:${kcardActiveCat === c ? '#111' : 'var(--tx)'};
      border:1px solid ${kcardActiveCat === c ? 'var(--ac)' : 'var(--b1)'};">
      ${esc(c)} ${c !== '전체' ? `<span style="font-size:10px;opacity:.7;">${kcards.filter(k => k.cat === c).length}</span>` : `<span style="font-size:10px;opacity:.7;">${kcards.length}</span>`}
    </button>`).join('');
    }

    function setKcardCat(c) { kcardActiveCat = c; renderKcatTabs(); renderKcards(); }

    // ── 카드 그리드 렌더 ───────────────────────────────
    function renderKcards() {
      const el = document.getElementById('kcardGrid'); if (!el) return;
      const filtered = kcardActiveCat === '전체' ? kcards : kcards.filter(k => k.cat === kcardActiveCat);

      if (!filtered.length) {
        el.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:60px 0;color:var(--mu);">
      <div style="font-size:40px;margin-bottom:12px;">⭐</div>
      <div style="font-size:13px;font-weight:600;margin-bottom:6px;">${kcardActiveCat === '전체' ? '첫 알짜정보 카드를 만들어보세요' : '이 카테고리에 카드가 없어요'}</div>
      <div style="font-size:12px;">+ 새 카드 버튼으로 추가하거나 AI로 자동 생성</div>
    </div>`;
        return;
      }

      // 카테고리별 색상
      const catColor = (cat) => {
        const map = { '📐 면적/건축': '#4f8eff', '⚖️ 권리분석': '#ff6370', '📋 경매 절차': '#f9a825', '💰 세금/비용': '#a78bfa', '🏘️ 상권/지역': '#b47cff' };
        return map[cat] || '#ffd166';
      };

      el.innerHTML = filtered.map(card => {
        const d = new Date(card.createdAt).toLocaleDateString('ko-KR', { month: 'numeric', day: 'numeric' });
        const tags = (card.tags || []).map(t => `<span style="font-size:10px;padding:2px 6px;background:rgba(255,209,102,0.1);color:#ffd166;border-radius:8px;border:1px solid rgba(255,209,102,0.25);">#${esc(t)}</span>`).join('');
        const color = catColor(card.cat);
        // 내용 파싱: 불릿/번호 목록 → 핵심 포인트 카드
        const bodyLines = (card.body || '').split('\n').filter(Boolean);
        const keyLines = bodyLines.filter(l => l.startsWith('•') || l.startsWith('-') || l.startsWith('·') || l.match(/^\d+[.)]/));
        const plainLines = bodyLines.filter(l => !l.startsWith('•') && !l.startsWith('-') && !l.startsWith('·') && !l.match(/^\d+[.)]/));

        // 핵심 포인트가 있으면 뱃지 스타일로, 없으면 텍스트
        const keyHtml = keyLines.slice(0, 5).map(line => {
          const txt = line.replace(/^[•\-·]\s*/, '').replace(/^\d+[.)]\s*/, '');
          return `<div style="display:flex;align-items:flex-start;gap:6px;padding:5px 8px;background:${color}0d;border-left:2px solid ${color};border-radius:0 5px 5px 0;font-size:11px;color:var(--tx);line-height:1.5;">${esc(txt)}</div>`;
        }).join('');
        const summaryHtml = plainLines.slice(0, 2).map(l => `<div style="font-size:11px;color:var(--mu);line-height:1.6;">${esc(l)}</div>`).join('');

        const hasMore = bodyLines.length > 5;

        return `<div style="background:var(--s1);border:1px solid var(--b1);border-top:3px solid ${color};border-radius:0 0 12px 12px;overflow:hidden;display:flex;flex-direction:column;transition:transform .15s,box-shadow .15s;cursor:pointer;" 
      onmouseover="this.style.transform='translateY(-3px)';this.style.boxShadow='0 8px 24px rgba(0,0,0,.35)'" 
      onmouseout="this.style.transform='';this.style.boxShadow=''">
      <!-- 카드 헤더 -->
      <div style="padding:12px 14px 10px;">
        <div style="display:flex;align-items:flex-start;gap:7px;margin-bottom:8px;">
          <span style="font-size:10px;padding:2px 8px;border-radius:10px;font-weight:700;white-space:nowrap;flex-shrink:0;background:${color}1a;color:${color};border:1px solid ${color}33;letter-spacing:.3px;">${esc(card.cat || '기타')}</span>
          <div style="display:flex;gap:3px;flex-shrink:0;margin-left:auto;">
            <button onclick="event.stopPropagation();ntCreateFromKcard('${card.id}')" title="이 카드로 노트 만들기" style="background:rgba(79,142,255,.1);border:1px solid rgba(79,142,255,.25);color:#4f8eff;cursor:pointer;font-size:11px;padding:2px 6px;border-radius:4px;font-weight:700;" onmouseover="this.style.background='rgba(79,142,255,.25)'" onmouseout="this.style.background='rgba(79,142,255,.1)'">📝</button>
            <button onclick="event.stopPropagation();openKcardEditor('${card.id}')" title="수정" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:12px;padding:1px 4px;border-radius:3px;opacity:.6;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='.6'">✏️</button>
            <button onclick="event.stopPropagation();deleteKcard('${card.id}')" title="삭제" style="background:none;border:none;color:var(--mu);cursor:pointer;font-size:12px;padding:1px 4px;border-radius:3px;opacity:.6;" onmouseover="this.style.opacity='1';this.style.color='#ff6370'" onmouseout="this.style.opacity='.6';this.style.color='var(--mu)'">🗑</button>
          </div>
        </div>
        <div style="font-size:13px;font-weight:800;color:var(--tx);line-height:1.35;margin-bottom:10px;">${esc(card.title || '제목 없음')}</div>
        <!-- 핵심 포인트 -->
        <div style="display:flex;flex-direction:column;gap:4px;">
          ${summaryHtml}
          ${keyHtml}
          ${hasMore ? `<div style="font-size:10px;color:var(--di);margin-top:2px;">+${bodyLines.length - 5}줄 더...</div>` : ''}
        </div>
      </div>
      <!-- 카드 푸터 -->
      <div style="padding:8px 14px;border-top:1px solid var(--b1);display:flex;align-items:center;gap:6px;margin-top:auto;flex-wrap:wrap;">
        ${tags || ''}
        <span style="margin-left:auto;font-size:10px;color:var(--di);">${d}</span>
      </div>
    </div>`;
      }).join('');
    }

    // ── 에디터 열기/닫기 ───────────────────────────────
    function openKcardEditor(id) {
      kcardEditId = id;
      const modal = document.getElementById('kcardModal');
      if (!modal) return;

      // 카테고리 피커 렌더
      renderKcardCatPicker(id ? (kcards.find(k => k.id === id)?.cat || kcardCats[0]) : kcardCats[0]);

      if (id) {
        // 수정 모드: 기존 카드 데이터 채우기
        const card = kcards.find(k => k.id === id);
        if (!card) return;
        document.getElementById('kcardTitle').value = card.title || '';
        document.getElementById('kcardBody').value = card.body || '';
        document.getElementById('kcardTags').value = (card.tags || []).join(', ');
        document.getElementById('kcardAiInput').value = '';
      } else {
        // 새 카드
        document.getElementById('kcardTitle').value = '';
        document.getElementById('kcardBody').value = '';
        document.getElementById('kcardTags').value = '';
        document.getElementById('kcardAiInput').value = '';
      }

      modal.style.display = 'flex';
    }

    function closeKcardEditor() {
      const modal = document.getElementById('kcardModal');
      if (modal) modal.style.display = 'none';
      kcardEditId = null;
    }

    // ── 카테고리 피커 렌더 ─────────────────────────────
    let kcardSelectedCat = '';
    function renderKcardCatPicker(defaultCat) {
      kcardSelectedCat = defaultCat || kcardCats[0];
      const el = document.getElementById('kcardCatPicker'); if (!el) return;
      el.innerHTML = kcardCats.map(c => `
    <button onclick="selectKcardCat('${c}')" id="kcp_${btoa(encodeURIComponent(c)).slice(0, 8)}"
      style="padding:4px 10px;font-size:11px;border-radius:10px;cursor:pointer;transition:all .15s;
      background:${kcardSelectedCat === c ? 'var(--ac)' : 'var(--s2)'};
      color:${kcardSelectedCat === c ? '#111' : 'var(--tx)'};
      border:1px solid ${kcardSelectedCat === c ? 'var(--ac)' : 'var(--b1)'};">
      ${esc(c)}
    </button>`).join('');
    }

    function selectKcardCat(c) {
      kcardSelectedCat = c;
      renderKcardCatPicker(c);
    }

    function addKcardCat() {
      const inp = document.getElementById('kcardNewCat'); if (!inp) return;
      const c = inp.value.trim(); if (!c) return;
      if (kcardCats.includes(c)) { showToast('이미 있는 카테고리예요', 'warn'); return; }
      kcardCats.push(c); saveKcardCats();
      inp.value = '';
      renderKcardCatPicker(c);
      renderKcatTabs();
      showToast(`'${c}' 카테고리 추가됨`, 'ok');
    }

    // ── 카드 저장 ──────────────────────────────────────
    function saveKcard() {
      const title = document.getElementById('kcardTitle')?.value?.trim();
      const body = document.getElementById('kcardBody')?.value?.trim();
      const tagsRaw = document.getElementById('kcardTags')?.value?.trim();
      if (!title) { showToast('제목을 입력해주세요', 'warn'); return; }

      const tags = tagsRaw ? tagsRaw.split(/[,，]+/).map(t => t.trim()).filter(Boolean) : [];
      const now = new Date().toISOString();

      if (kcardEditId) {
        // 수정
        const card = kcards.find(k => k.id === kcardEditId);
        if (card) { card.title = title; card.body = body; card.tags = tags; card.cat = kcardSelectedCat; card.updatedAt = now; }
      } else {
        // 새 카드
        kcards.unshift({ id: 'kc_' + Date.now(), title, body, tags, cat: kcardSelectedCat, createdAt: now, updatedAt: now });
      }

      saveKcards();
      closeKcardEditor();
      renderKcatTabs();
      renderKcards();
      showToast(kcardEditId ? '카드 수정됨 ✅' : '카드 저장됨 📚', 'ok');
    }

    // ── 카드 삭제 ──────────────────────────────────────
    function deleteKcard(id) {
      if (!confirm('이 카드를 삭제할까요?')) return;
      kcards = kcards.filter(k => k.id !== id);
      saveKcards(); renderKcatTabs(); renderKcards();
      showToast('카드 삭제됨', 'ok');
    }

    // ── AI 카드 자동 생성 ─────────────────────────────
    // 현재 소스 타입 추적
    let kcardSrcType = 'text';
    let kcardFileData = null; // {type, base64, mimeType}

    function setKcardSrc(type) {
      kcardSrcType = type;
      ['text', 'file', 'url', 'youtube'].forEach(t => {
        const btn = document.getElementById('ksrc_' + t);
        const area = document.getElementById('ksrc_' + t + '_area');
        if (btn) btn.style.cssText = `flex:1;padding:5px;font-size:11px;border-radius:6px;cursor:pointer;` +
          (t === type ? 'background:var(--ac);color:#111;border:1px solid var(--ac);font-weight:600;' : 'background:var(--s2);color:var(--tx);border:1px solid var(--b1);');
        if (area) area.style.display = t === type ? '' : 'none';
      });
    }

    function handleKcardFileDrop(e) {
      e.preventDefault();
      const file = e.dataTransfer?.files?.[0];
      if (file) processKcardFile(file);
    }

    function handleKcardFile(input) {
      const file = input.files?.[0];
      if (file) processKcardFile(file);
    }

    function processKcardFile(file) {
      const status = document.getElementById('kcardFileStatus');
      const maxMB = 10;
      if (file.size > maxMB * 1024 * 1024) {
        if (status) status.textContent = '❌ 파일이 너무 큽니다 (최대 10MB)';
        return;
      }
      if (status) status.textContent = '⏳ 파일 읽는 중...';
      const reader = new FileReader();
      reader.onload = e => {
        const base64 = e.target.result.split(',')[1];
        const mimeType = file.type || (file.name.endsWith('.pdf') ? 'application/pdf' : 'image/jpeg');
        kcardFileData = { base64, mimeType, name: file.name };
        if (status) status.textContent = `✅ ${file.name} 준비됨`;
      };
      reader.onerror = () => { if (status) status.textContent = '❌ 파일 읽기 실패'; };
      reader.readAsDataURL(file);
    }

    async function aiSummarizeKcard() {
      const apiKey = gk();
      if (!apiKey) { showToast('Gemini API 키가 필요합니다', 'warn'); return; }

      const btn = document.querySelector('#kcardModal button[onclick="aiSummarizeKcard()"]');
      if (btn) { btn.textContent = '⏳ AI 분석 중...'; btn.disabled = true; }

      const prompt = `다음 부동산/경매 관련 내용을 지식 카드 형식으로 정리해줘.

규칙:
- 제목: 한 줄 (명확하고 짧게)
- 내용: 핵심만 불릿 포인트(• )로 5줄 이내
- 태그: 관련 키워드 3개 이내, 쉼표 구분

반드시 아래 형식으로만 답해줘:
제목: [제목]
내용:
• [핵심1]
• [핵심2]
태그: [태그1], [태그2]`;

      try {
        let parts = [];

        if (kcardSrcType === 'file' && kcardFileData) {
          // PDF or 이미지
          const isPdf = kcardFileData.mimeType === 'application/pdf';
          if (isPdf) {
            parts = [
              { inline_data: { mime_type: 'application/pdf', data: kcardFileData.base64 } },
              { text: prompt }
            ];
          } else {
            parts = [
              { inline_data: { mime_type: kcardFileData.mimeType, data: kcardFileData.base64 } },
              { text: prompt + '\n\n이 이미지/문서에서 부동산 관련 정보를 추출해서 카드로 만들어줘.' }
            ];
          }
        } else if (kcardSrcType === 'url') {
          const url = document.getElementById('kcardUrlInput')?.value?.trim();
          if (!url) { showToast('URL을 입력해주세요', 'warn'); return; }
          parts = [{ text: prompt + '\n\n다음 URL의 내용을 분석해줘: ' + url + '\n(URL에 직접 접근하기 어려우면 URL 정보를 바탕으로 추정해줘)' }];
        } else if (kcardSrcType === 'youtube') {
          const ytUrl = document.getElementById('kcardYtInput')?.value?.trim();
          if (!ytUrl) { showToast('유튜브 링크를 입력해주세요', 'warn'); return; }
          parts = [{ text: prompt + '\n\n다음 유튜브 영상 링크를 분석해줘: ' + ytUrl + '\n영상 제목/내용을 바탕으로 부동산 경매 관련 지식 카드를 만들어줘.' }];
        } else {
          // 텍스트
          const raw = document.getElementById('kcardAiInput')?.value?.trim();
          if (!raw) { showToast('내용을 입력해주세요', 'warn'); return; }
          parts = [{ text: prompt + '\n\n내용:\n' + raw }];
        }

        // Gemini 호출 (모델/버전 자동 폴백, PDF/이미지 inline_data 지원)
        const out = await callGEx(parts, { generationConfig: { temperature: 0.2, maxOutputTokens: 2500 } });
        const text = out.text || '';

        const titleMatch = text.match(/제목[：:\s]*(.+)/);
        const tagsMatch = text.match(/태그[：:\s]*(.+)/);
        const bullets = text.match(/[•·●\-]\s*.+/g) || [];

        if (titleMatch) document.getElementById('kcardTitle').value = titleMatch[1].trim();
        if (tagsMatch) document.getElementById('kcardTags').value = tagsMatch[1].trim().replace(/[•·]/g, '');
        if (bullets.length) document.getElementById('kcardBody').value = bullets.map(b => b.replace(/^[•·●\-]\s*/, '• ')).join('\n');

        showToast('✅ AI 카드 생성 완료! 확인 후 저장하세요', 'ok');
      } catch (e) {
        showToast('AI 생성 실패: ' + e.message, 'warn');
        console.error(e);
      } finally {
        if (btn) { btn.textContent = '✨ AI 카드 생성'; btn.disabled = false; }
      }
    }

    // ESC키로 모달 닫기
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape') {
        closeKcardEditor();
        closeAddSiteModal();
      }
    });

    // 초기 watchCnt 업데이트
    updateWatchCnt();

    // 🎯 검토 물건함
    // ═══════════════════════════════════════════════════════

    const WATCH_ORDER = ['', 'interest', 'review', 'field', 'bid', 'won'];

    window.cycleWatchStatus = function (id) {
      const sv = getSv();
      const item = sv.find(s => s.id === id);
      if (!item) return;
      const cur = item.watchStatus || '';
      const idx = WATCH_ORDER.indexOf(cur);
      const next = WATCH_ORDER[(idx + 1) % WATCH_ORDER.length];
      item.watchStatus = next || undefined;
      if (!next) delete item.watchStatus;
      setSv(sv);
      renderSaved();
      updateWatchCnt();
      const labels = { interest: '👀 관심으로 표시', review: '🔍 검토중으로 이동', field: '📍 현장으로 이동', bid: '🎯 입찰로 이동', won: '✅ 낙찰로 이동', '': '표시 해제' };
      showToast(labels[next || ''], 'ok', 1800);
      // ★ 연결된 작업룸 status 자동 동기화
      if (next) {
        try {
          var rooms = typeof wrGetRooms === 'function' ? wrGetRooms() : [];
          var itemIdStr = String(id);
          var linked = rooms.find(function(r) {
            return (r.linkedSavedId && String(r.linkedSavedId) === itemIdStr) ||
                   (r.auctionId && String(r.auctionId) === itemIdStr) ||
                   (r.listingId && String(r.listingId) === itemIdStr) ||
                   ((r.linkedItems||[]).map(String).includes(itemIdStr));
          });
          if (linked && linked.status !== next) {
            linked.status = next;
            linked.updatedAt = Date.now();
            if (typeof wrSetRooms === 'function') wrSetRooms(rooms);
            if (typeof wrDbRenderList === 'function') wrDbRenderList();
          }
        } catch(e) {}
      }
    };

    function updateWatchCnt() {
      const sv = getSv();
      const cnt = sv.filter(s => s.watchStatus).length;
      const el = document.getElementById('watchCnt');
      if (el) { el.style.display = cnt ? '' : 'none'; el.textContent = cnt; }
    }

    function renderWatchBoard() {
      const sv = getSv();
      const sortKey = document.getElementById('watchSortSel')?.value || 'savedAt';
      const statuses = ['interest', 'review', 'field', 'bid', 'won'];
      const cols = ['wCol0','wCol1','wCol2','wCol3','wCol4'].map(id=>document.getElementById(id));
      const cntEls = ['wCnt0','wCnt1','wCnt2','wCnt3','wCnt4'].map(id=>document.getElementById(id));
      const emptyEls = ['wEmpty0','wEmpty1','wEmpty2','wEmpty3','wEmpty4'].map(id=>document.getElementById(id));
      const rooms = wrGetRooms();

      statuses.forEach((status, ci) => {
        let items = sv.filter(s => s.watchStatus === status);
        if (sortKey === 'saledate') {
          items.sort((a, b) => { const da = a.data?.매각일 || ''; const db = b.data?.매각일 || ''; return da.localeCompare(db); });
        } else if (sortKey === 'price') {
          items.sort((a, b) => { const pa = parseInt(String(a.data?.감정가 || a.data?.매매가 || 0).replace(/[^0-9]/g, '')) || 0; const pb = parseInt(String(b.data?.감정가 || b.data?.매매가 || 0).replace(/[^0-9]/g, '')) || 0; return pb - pa; });
        }

        cntEls[ci].textContent = items.length;
        if (emptyEls[ci]) emptyEls[ci].style.display = items.length ? 'none' : '';

        if (cols[ci]) {
          Array.from(cols[ci].children).forEach(ch => { if (!ch.id?.startsWith('wEmpty')) ch.remove(); });
          items.forEach(item => {
            const d = item.data || {};
            const ia = item.mode === 'auction';

            // 가격
            let priceStr = '';
            if (ia) { priceStr = d.감정가 ? (parseInt(String(d.감정가).replace(/[^0-9]/g, '')) / 100000000).toFixed(1) + '억' : '-'; }
            else { priceStr = d.매매가 ? d.매매가 + '만' : (d.월세_만원 ? `${d.기보증금_만원 || 0}/${d.월세_만원}` : '-'); }

            // D-day
            let ddayHtml = '';
            if (ia && d.매각일) {
              const dDay = Math.ceil((new Date(d.매각일) - new Date()) / (1000 * 60 * 60 * 24));
              const dColor = dDay < 0 ? 'var(--di)' : dDay <= 3 ? '#ff6370' : dDay <= 7 ? 'var(--or)' : '#4ade80';
              const dLabel = dDay < 0 ? '종료' : (dDay === 0 ? 'D-Day' : 'D-' + dDay);
              ddayHtml = `<span style="font-size:10px;font-weight:700;color:${dColor};background:${dColor}18;padding:1px 5px;border-radius:4px;">${dLabel}</span>`;
            }

            // 연결 작업룸
            var itemIdStr = String(item.id);
            const linkedRoom = rooms.find(r =>
              (r.linkedSavedId && String(r.linkedSavedId) === itemIdStr) ||
              (r.auctionId && String(r.auctionId) === itemIdStr) ||
              (r.listingId && String(r.listingId) === itemIdStr) ||
              ((r.linkedItems || []).map(String).includes(itemIdStr))
            );
            // 작업룸 상태 동기화 배지
            const roomStatusHtml = linkedRoom ? (() => {
              const key = typeof _migrateStatus === 'function' ? _migrateStatus(linkedRoom.status) : (linkedRoom.status || 'review');
              const info = (typeof UNIFIED_STATUS !== 'undefined' ? UNIFIED_STATUS : {})[key] || { label: linkedRoom.status, color: '#60a5fa' };
              return `<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:${info.color}18;color:${info.color};border:1px solid ${info.color}44;">${info.label}</span>`;
            })() : '';

            // 노트 수
            const noteCnt = (typeof insNotes !== 'undefined' ? insNotes : (JSON.parse(localStorage.getItem('nt_notes') || '[]'))).filter(n => n.linkedItemId === item.id).length;

            // 분석 진행도 (연결된 작업룸 기준)
            let progressHtml = '';
            if (linkedRoom) {
              const done = (linkedRoom.checklist || []).filter(c => c.done).length;
              const total = 8; // WR_ANALYSIS_ITEMS.length
              const pct = Math.round(done / total * 100);
              progressHtml = `<div style="margin-top:6px;display:flex;align-items:center;gap:5px;">
            <div style="flex:1;height:3px;background:var(--b1);border-radius:2px;overflow:hidden;">
              <div style="height:100%;width:${pct}%;background:linear-gradient(90deg,#4f8eff,#00d4aa);"></div>
            </div>
            <span style="font-size:9px;color:var(--di);">분석 ${done}/${total}</span>
          </div>`;
            }

            const card = document.createElement('div');
            card.style.cssText = `background:var(--s2);border-radius:9px;border:1px solid ${linkedRoom ? 'rgba(167,139,250,.25)' : 'var(--b1)'};padding:10px 12px;transition:all .15s;position:relative;`;
            card.onmouseenter = () => { card.style.borderColor = 'rgba(79,142,255,0.5)'; card.style.background = 'rgba(79,142,255,.04)'; };
            card.onmouseleave = () => { card.style.borderColor = linkedRoom ? 'rgba(167,139,250,.25)' : 'var(--b1)'; card.style.background = 'var(--s2)'; };

            // 왼쪽 컬럼 색상 바
            const colColors = ['rgba(148,163,184,.5)','rgba(96,165,250,.5)','rgba(251,191,36,.5)','rgba(249,115,22,.5)','rgba(74,222,128,.5)'];
            card.innerHTML = `
          <div style="position:absolute;left:0;top:8px;bottom:8px;width:3px;background:${colColors[ci]};border-radius:0 2px 2px 0;"></div>
          <div style="padding-left:6px;">
            <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:4px;margin-bottom:4px;">
              <div style="font-size:12px;font-weight:600;color:var(--tx);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;cursor:pointer;" onclick="openPopup('${item.id}')">${esc(item.title || d.소재지 || item.id)}</div>
              <div style="display:flex;align-items:center;gap:3px;flex-shrink:0;">
                ${ddayHtml}
                <div style="position:relative;display:inline-block;">
                  <button onclick="event.stopPropagation();this.nextElementSibling.style.display=this.nextElementSibling.style.display==='block'?'none':'block';" title="단계 이동" style="padding:2px 7px;background:none;border:1px solid var(--b1);border-radius:4px;color:var(--di);font-size:10px;cursor:pointer;">↻</button>
                  <div onclick="event.stopPropagation();" style="display:none;position:absolute;right:0;top:100%;margin-top:2px;background:#1a1f2e;border:1px solid #2a3045;border-radius:8px;padding:4px;z-index:999;min-width:110px;box-shadow:0 4px 16px rgba(0,0,0,.5);">
                    ${['interest','review','field','bid','won','pass'].map(k=>{
                      const info=UNIFIED_STATUS[k];
                      return `<div onclick="event.stopPropagation();_wbSetStatus('${item.id}','${k}');this.closest('div[style*=position]').style.display='none';" style="padding:5px 8px;border-radius:5px;font-size:11px;cursor:pointer;color:${info.color};white-space:nowrap;" onmouseenter="this.style.background='rgba(255,255,255,.06)'" onmouseleave="this.style.background=''">${info.label}</div>`;
                    }).join('')}
                  </div>
                </div>
              </div>
            </div>
            <div style="font-size:10px;color:var(--mu);margin-bottom:5px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(String(d.소재지 || ''))}</div>
            <div style="display:flex;align-items:center;gap:5px;flex-wrap:wrap;">
              <span style="font-size:12px;font-weight:700;color:${ia ? 'var(--auction-c)' : 'var(--listing-c)'};">${priceStr}</span>
              ${roomStatusHtml}
              ${noteCnt ? `<span style="font-size:10px;color:var(--ac);">📓${noteCnt}</span>` : ''}
            </div>
            ${progressHtml}
            <div style="display:flex;gap:4px;margin-top:8px;border-top:1px solid var(--b1);padding-top:7px;">
              ${linkedRoom
                ? `<button onclick="_wbGoRoom('${linkedRoom.id}')" style="flex:1;padding:4px 3px;background:rgba(167,139,250,.12);border:1px solid rgba(167,139,250,.35);border-radius:5px;color:#a78bfa;font-size:10px;font-weight:600;cursor:pointer;">🗂 ${esc((linkedRoom.title || linkedRoom.name || '').substring(0, 10))}</button>`
                : `<button onclick="_wbCreateAndLink('${item.id}')" style="flex:1;padding:4px 3px;background:rgba(167,139,250,.08);border:1px dashed rgba(167,139,250,.4);border-radius:5px;color:#a78bfa;font-size:10px;cursor:pointer;" title="작업룸을 새로 만들고 바로 연결">＋ 작업룸 만들기</button>`
              }
              <button onclick="_wbNote('${item.id}')" style="padding:4px 7px;background:var(--s1);border:1px solid var(--b1);border-radius:5px;color:var(--mu);font-size:10px;cursor:pointer;">📓</button>
              <button onclick="openPopup('${item.id}')" style="padding:4px 7px;background:var(--s1);border:1px solid var(--b1);border-radius:5px;color:var(--di);font-size:10px;cursor:pointer;">상세</button>
            </div>
          </div>
        `;
            cols[ci].appendChild(card);
          });
        }
      });
      // ── 물건 없는 작업룸도 가상 카드로 표시 ──
      statuses.forEach((status, ci) => {
        if (!cols[ci]) return;
        const roomOnlyItems = rooms.filter(r => {
          // 물건 연결 없는 작업룸
          const hasItem = (r.linkedSavedId || r.auctionId || r.listingId || (r.linkedItems||[]).length);
          if (hasItem) return false;
          const rStatus = typeof _migrateStatus === 'function' ? _migrateStatus(r.status || 'review') : (r.status || 'review');
          return rStatus === status;
        });
        roomOnlyItems.forEach(room => {
          const st = (typeof UNIFIED_STATUS !== 'undefined' ? UNIFIED_STATUS : {})[status] || { color: '#60a5fa' };
          const colColors = ['rgba(148,163,184,.5)','rgba(96,165,250,.5)','rgba(251,191,36,.5)','rgba(249,115,22,.5)','rgba(74,222,128,.5)'];
          const card = document.createElement('div');
          card.style.cssText = `background:var(--s2);border-radius:9px;border:1px solid rgba(167,139,250,.25);padding:10px 12px;transition:all .15s;position:relative;cursor:pointer;`;
          card.onmouseenter = () => { card.style.borderColor = 'rgba(167,139,250,.5)'; card.style.background = 'rgba(167,139,250,.04)'; };
          card.onmouseleave = () => { card.style.borderColor = 'rgba(167,139,250,.25)'; card.style.background = 'var(--s2)'; };
          card.onclick = () => _wbGoRoom(room.id);
          const d = new Date(room.updatedAt || Date.now());
          const dt = (d.getMonth()+1) + '/' + d.getDate();
          card.innerHTML = `
            <div style="position:absolute;left:0;top:8px;bottom:8px;width:3px;background:rgba(167,139,250,.6);border-radius:0 2px 2px 0;"></div>
            <div style="padding-left:6px;">
              <div style="display:flex;align-items:center;justify-content:space-between;gap:4px;margin-bottom:4px;">
                <div style="font-size:12px;font-weight:600;color:var(--tx);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">🗂 ${esc(room.title||room.name||'작업룸')}</div>
                <span style="font-size:9px;color:var(--di);">${dt}</span>
              </div>
              <div style="font-size:9px;color:#a78bfa;margin-bottom:6px;">물건 미연결 작업룸</div>
              <div style="display:flex;gap:4px;border-top:1px solid var(--b1);padding-top:6px;">
                <button onclick="event.stopPropagation();_wbGoRoom('${room.id}')" style="flex:1;padding:4px;background:rgba(167,139,250,.12);border:1px solid rgba(167,139,250,.35);border-radius:5px;color:#a78bfa;font-size:10px;font-weight:600;cursor:pointer;">🗂 작업룸 열기</button>
              </div>
            </div>`;
          cols[ci].appendChild(card);
          // 카운트 업데이트
          const cnt = parseInt(cntEls[ci].textContent||'0') + 1;
          cntEls[ci].textContent = cnt;
          if (emptyEls[ci]) emptyEls[ci].style.display = 'none';
        });
      });

      updateWatchCnt();
    }

    // ── 파이프라인 헬퍼 함수들 ────────────────────────────────
    window._wbCycleStatus = function (itemId) {
      cycleWatchStatus(itemId);
      setTimeout(renderWatchBoard, 50);
    };
    window._wbSetStatus = function (itemId, status) {
      var sv = typeof getSv === 'function' ? getSv() : [];
      var item = sv.find(function(s){ return s.id === itemId; });
      if (!item) return;
      if (status === 'pass' || !status) { delete item.watchStatus; }
      else { item.watchStatus = status; }
      if (typeof setSv === 'function') setSv(sv);
      if (typeof renderSaved === 'function') renderSaved();
      if (typeof updateWatchCnt === 'function') updateWatchCnt();
      // 연결된 작업룸 동기화
      try {
        var rooms = typeof wrGetRooms === 'function' ? wrGetRooms() : [];
        var idStr = String(itemId);
        var linked = rooms.find(function(r){
          return (r.linkedSavedId && String(r.linkedSavedId)===idStr) ||
                 (r.auctionId && String(r.auctionId)===idStr) ||
                 (r.listingId && String(r.listingId)===idStr) ||
                 ((r.linkedItems||[]).map(String).includes(idStr));
        });
        if (linked) {
          linked.status = status || 'pass';
          linked.updatedAt = Date.now();
          if (typeof wrSetRooms === 'function') wrSetRooms(rooms.length ? rooms : [linked]);
          if (typeof wrDbRenderList === 'function') wrDbRenderList();
        }
      } catch(e) {}
      var info = (typeof UNIFIED_STATUS !== 'undefined' ? UNIFIED_STATUS[status] : null) || { label: status };
      if (typeof showToast === 'function') showToast(info.label + '로 이동했습니다', 'ok', 1500);
      setTimeout(renderWatchBoard, 50);
    };
    window._wbGoRoom = function (roomId) {
      showInsTab(8);
      setTimeout(function () { if (typeof window.wrDbOpenRoom === 'function') window.wrDbOpenRoom(roomId); }, 80);
    };
    window._wbCreateAndLink = function (itemId) {
      if (typeof window.wr2OpenOrCreateFromSavedId === 'function') {
        window.wr2OpenOrCreateFromSavedId(itemId);
        return;
      }
      showInsTab(8);
      showToast('작업룸 기능을 불러오는 중입니다. 잠시 후 다시 시도해주세요.', 'warn');
    };
    window._wbNote = function (itemId) {
      if (typeof wrCreateNoteForItem === 'function') wrCreateNoteForItem(itemId);
      else {
        showInsTab(0);
        showToast('노트 탭으로 이동했습니다', 'ok');
      }
    };

    // ── 파이프라인에서 물건 노트 바로 만들기 ──────────────────
    window.wrCreateNoteForItem = function (itemId) {
      const sv = getSv();
      const item = sv.find(s => s.id === itemId);
      if (!item) { showToast('물건을 찾을 수 없습니다', 'warn'); return; }
      const d = item.data || {};
      const notes = JSON.parse(localStorage.getItem('ins_notes') || '[]');
      const note = {
        id: 'note_' + Date.now(),
        title: (d.소재지 || item.title || item.id).substring(0, 30) + ' 분석',
        body: `[물건 정보]\n주소: ${d.소재지 || '-'}\n${item.mode === 'auction' ? `감정가: ${d.감정가 ? Math.round(d.감정가 / 10000) + '만원' : '-'}\n최저가: ${d.최저가 ? Math.round(d.최저가 / 10000) + '만원' : '-'}\n매각일: ${d.매각일 || '-'}` : `매매가: ${d.매매가 || '-'}만원`}\n\n[분석 메모]\n`,
        tags: [],
        linkedItemId: itemId,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      notes.unshift(note);
      localStorage.setItem('ins_notes', JSON.stringify(notes));
      showInsTab(0);
      setTimeout(() => openNote(note.id), 100);
      showToast('📓 노트가 만들어졌습니다', 'ok');
    };

