    function getSites() {
      const custom = JSON.parse(localStorage.getItem('site_bookmarks') || '[]');
      // 기본 사이트 + 사용자 추가 (중복 id 방지)
      const customIds = new Set(custom.map(s => s.id));
      const defaults = DEFAULT_SITES.filter(s => !customIds.has(s.id));
      return [...defaults, ...custom];
    }

    function saveSites(sites) {
      // 사용자 추가분만 저장 (builtin 제외)
      const custom = sites.filter(s => !s.builtin);
      localStorage.setItem('site_bookmarks', JSON.stringify(custom));
    }

    function renderSiteBookmarks() {
      const sites = getSites();
      const grid = document.getElementById('siteBookmarkGrid');
      if (!grid) return;

      // 카테고리별 그룹
      const cats = {};
      sites.forEach(s => { if (!cats[s.cat]) cats[s.cat] = []; cats[s.cat].push(s); });

      const catOrder = ['경매', '부동산', '공공/행정', '지도', '금융', '기타'];
      const allCats = [...catOrder.filter(c => cats[c]), ...Object.keys(cats).filter(c => !catOrder.includes(c))];

      grid.innerHTML = allCats.map(cat => {
        const items = cats[cat] || [];
        const accent = CAT_ACCENT[cat] || 'var(--mu)';
        const bg = CAT_COLORS[cat] || 'rgba(107,117,144,0.10)';
        return `
      <div>
        <div style="font-size:11px;font-weight:700;color:${accent};text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;display:flex;align-items:center;gap:6px;">
          <div style="width:3px;height:12px;background:${accent};border-radius:2px;"></div>
          ${cat}
          <span style="font-weight:400;color:var(--di);text-transform:none;">(${items.length})</span>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:8px;">
          ${items.map(s => `
            <div style="background:${bg};border:1px solid ${accent.replace('var(', '').replace(')', '').includes('#') ? accent + '33' : 'rgba(107,117,144,0.2)'};border-radius:9px;padding:12px 14px;display:flex;flex-direction:column;gap:5px;position:relative;transition:transform .15s,box-shadow .15s;" 
              onmouseenter="this.style.transform='translateY(-2px)';this.style.boxShadow='0 4px 16px rgba(0,0,0,0.3)'"
              onmouseleave="this.style.transform='';this.style.boxShadow=''">
              <div style="display:flex;align-items:center;gap:8px;">
                <img src="https://www.google.com/s2/favicons?domain=${encodeURIComponent(new URL(s.url).hostname)}&sz=16" width="16" height="16" style="border-radius:3px;flex-shrink:0;" onerror="this.style.display='none'">
                <a href="${s.url}" target="_blank" onclick="event.stopPropagation()" style="font-size:13px;font-weight:600;color:var(--tx);text-decoration:none;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${s.url}">${esc(s.name)}</a>
              </div>
              ${s.memo ? `<div style="font-size:11px;color:var(--mu);line-height:1.4;">${esc(s.memo)}</div>` : ''}
              ${!s.builtin ? `<button onclick="deleteSiteBookmark('${s.id}')" style="position:absolute;top:6px;right:6px;background:none;border:none;color:var(--di);cursor:pointer;font-size:14px;line-height:1;padding:2px;" title="삭제">×</button>` : ''}
            </div>
          `).join('')}
        </div>
      </div>
    `;
      }).join('');
    }

    function openAddSiteModal() {
      const m = document.getElementById('addSiteModal');
      if (m) { m.style.display = 'flex'; document.getElementById('siteNameIn').focus(); }
    }
    function closeAddSiteModal() {
      const m = document.getElementById('addSiteModal');
      if (m) m.style.display = 'none';
    }
    function saveSiteBookmark() {
      const name = document.getElementById('siteNameIn').value.trim();
      const url = document.getElementById('siteUrlIn').value.trim();
      const cat = document.getElementById('siteCatIn').value;
      const memo = document.getElementById('siteMemoIn').value.trim();
      if (!name || !url) { showToast('이름과 URL을 입력해주세요', 'warn'); return; }
      let fullUrl = url;
      if (!/^https?:\/\//.test(fullUrl)) fullUrl = 'https://' + fullUrl;
      const sites = getSites();
      const newSite = { id: 'usr_' + Date.now(), name, url: fullUrl, cat, memo, builtin: false };
      sites.push(newSite);
      saveSites(sites);
      closeAddSiteModal();
      renderSiteBookmarks();
      // 입력 초기화
      ['siteNameIn', 'siteUrlIn', 'siteMemoIn'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
      showToast('✅ 사이트가 추가되었습니다', 'ok');
    }
    window.deleteSiteBookmark = function (id) {
      if (!confirm('이 사이트를 삭제할까요?')) return;
      const sites = getSites().filter(s => s.id !== id);
      saveSites(sites);
      renderSiteBookmarks();
      showToast('삭제되었습니다', 'ok');
    };

