    // ── 메모 저장 (debounce 600ms) ───────────────────────────
    var _wrMemoTimers = {};
    window._wrSecSaveMemo = function (roomId, phId, secId, val) {
      var key = roomId + phId + secId;
      clearTimeout(_wrMemoTimers[key]);
      _wrMemoTimers[key] = setTimeout(function () {
        var rooms = wrGetRooms();
        var room = rooms.find(function (r) { return r.id === roomId; });
        if (!room) return;
        var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
        if (!ph) return;
        var sec = ph.sections.find(function (s) { return s.id === secId; });
        if (!sec) return;
        sec.content = val;
        room.updatedAt = Date.now();
        wrSetRooms(rooms);
      }, 600);
    };

    // ── 체크리스트 ────────────────────────────────────────────
    window._wrSecCheckToggle = function (roomId, phId, secId, idx) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.items) return;
      sec.items[idx].d = !sec.items[idx].d;
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrSecCheckAdd = function (roomId, phId, secId) {
      var inp = document.getElementById('ckIn_' + roomId + '_' + phId + '_' + secId);
      var text = inp && inp.value.trim();
      if (!text) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.items) sec.items = [];
      sec.items.push({ t: text, d: false });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrSecCheckDelete = function (roomId, phId, secId, idx) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.items) return;
      sec.items.splice(idx, 1);
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 수치 행 ───────────────────────────────────────────────
    var _wrMetricTimers = {};
    window._wrMetricRowUpdate = function (roomId, phId, secId, ri, field, val) {
      var key = roomId + phId + secId + ri + field;
      clearTimeout(_wrMetricTimers[key]);
      _wrMetricTimers[key] = setTimeout(function () {
        var rooms = wrGetRooms();
        var room = rooms.find(function (r) { return r.id === roomId; });
        if (!room) return;
        var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
        if (!ph) return;
        var sec = ph.sections.find(function (s) { return s.id === secId; });
        if (!sec || !sec.rows) return;
        if (sec.rows[ri]) sec.rows[ri][field] = val;
        room.updatedAt = Date.now();
        wrSetRooms(rooms);
        // ✅ 저장 피드백: 해당 입력 테두리를 잠깐 초록으로
        var inputs = document.querySelectorAll('#wrSec_' + roomId + '_' + phId + '_' + secId + ' input');
        inputs.forEach(function (inp) {
          inp.style.borderBottomColor = '#4ade80';
          setTimeout(function () { inp.style.borderBottomColor = 'var(--b1)'; }, 600);
        });
      }, 500);
    };
    window._wrMetricRowAdd = function (roomId, phId, secId) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.rows) sec.rows = [];
      sec.rows.push({ k: '', v: '' });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrMetricRowDelete = function (roomId, phId, secId, ri) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.rows) return;
      sec.rows.splice(ri, 1);
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 날짜 기록 ────────────────────────────────────────────
    window._wrLogAdd = function (roomId, phId, secId) {
      var dateEl = document.getElementById('logDate_' + roomId + '_' + phId + '_' + secId);
      var textEl = document.getElementById('logText_' + roomId + '_' + phId + '_' + secId);
      var text = textEl && textEl.value.trim();
      if (!text) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.logs) sec.logs = [];
      sec.logs.unshift({ date: dateEl ? dateEl.value : '', text: text });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrLogDelete = function (roomId, phId, secId, li) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.logs) return;
      sec.logs.splice(li, 1);
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 좌측 패널 리사이즈 ───────────────────────────────────
    (function () {
      var handle = document.getElementById('wrDbResizeHandle');
      var panel = document.getElementById('wrDbListPanel');
      if (!handle || !panel) return;
      var dragging = false, startX = 0, startW = 0;
      handle.addEventListener('mousedown', function (e) {
        dragging = true; startX = e.clientX; startW = panel.offsetWidth;
        handle.classList.add('dragging');
        document.body.style.userSelect = 'none';
        e.preventDefault();
      });
      document.addEventListener('mousemove', function (e) {
        if (!dragging) return;
        var w = Math.min(Math.max(startW + (e.clientX - startX), 160), 440);
        panel.style.width = w + 'px';
      });
      document.addEventListener('mouseup', function () {
        if (!dragging) return;
        dragging = false;
        handle.classList.remove('dragging');
        document.body.style.userSelect = '';
        localStorage.setItem('wr_list_panel_w', panel.style.width);
      });
      var saved = localStorage.getItem('wr_list_panel_w');
      if (saved) panel.style.width = saved;
    })();

    console.log('[v239-fix] 작업룸 버그수정 로드 완료 (wrDbUpdateName/Status/LinkItem 추가, _wrPhaseGet 저장 수정, 섹션ID 중복 해결, 일반매물 연결, 접기 DOM직접조작)');




