/* ════════════════════════════════════════════════════════
   블록14: 뉴스 클리핑
════════════════════════════════════════════════════════ */
        // 📰 클리핑 탭 (ipage3) — 뉴스 클리퍼 연동 v1
        // ═══════════════════════════════════════════════════════════
        (function() {
        const CLIP_KEY = 'news_clip_v1';
        let _clipData = null;   // 현재 로드된 clip JSON
        let _clipFilter = 'all'; // 현재 필터
  
        // ── 탭 진입 시 호출 ──
        window.clipTabInit = function() {
          const saved = localStorage.getItem(CLIP_KEY);
        if (saved) {
            try {
          _clipData = JSON.parse(saved);
        _clipRender();
            } catch(e) {
          _clipShowEmpty();
            }
          } else {
          _clipShowEmpty();
          }
        };
  
        // ── 파일 선택으로 JSON 로드 ──
        window.clipLoadFile = function(input) {
          const file = input.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = function(e) {
            try {
              const data = JSON.parse(e.target.result);
        // clip_YYYY-MM-DD.json 형식 검증
        if (!data.analysis || !data.rawNews) {
                if (typeof showToast === 'function') showToast('올바른 clip_날짜.json 파일이 아닙니다', 'warn');
        return;
              }
        _clipData = data;
        localStorage.setItem(CLIP_KEY, JSON.stringify(data));
        _clipFilter = 'all';
        _clipRender();
        if (typeof showToast === 'function') showToast('📰 뉴스 클리핑 로드 완료 (' + (data.rawNews || []).length + '건)', 'ok');
            } catch(err) {
              if (typeof showToast === 'function') showToast('JSON 파싱 실패: ' + err.message, 'warn');
            }
          };
        reader.readAsText(file, 'utf-8');
        // input 초기화 (같은 파일 재선택 가능하도록)
        input.value = '';
        };
  
        // ── 데이터 초기화 ──
        window.clipClearData = function() {
          if (!confirm('저장된 뉴스 클리핑 데이터를 삭제할까요?')) return;
        localStorage.removeItem(CLIP_KEY);
        _clipData = null;
        _clipFilter = 'all';
        _clipShowEmpty();
        if (typeof showToast === 'function') showToast('초기화 완료', 'ok');
        };
  
        // ── 필터 전환 ──
        window.clipFilterSet = function(f) {
          _clipFilter = f;
          document.querySelectorAll('.clip-fc').forEach(el => {
            el.classList.toggle('on', el.dataset.f === f);
          });
          // 전체 재렌더 (테마/신호/지역도 필터 반영)
          _clipRender();
        };
  
        // ── 기사 번호 클릭 → 링크 직접 열기 + 하이라이트 ──
        window.clipHighlightArticle = function(id) {
          // 1) 해당 기사 링크 요소 찾기
          const target = document.getElementById('clip-art-' + id);
          // 2) 링크가 있으면 새 탭으로 바로 열기
          if (target && target.href && target.href !== '#' && !target.href.endsWith('#')) {
            window.open(target.href, '_blank', 'noopener,noreferrer');
            return;
          }
          // 3) 링크 없으면 기존처럼 스크롤+하이라이트
          document.querySelectorAll('.clip-article-link').forEach(el => {
            el.style.borderColor = 'rgba(255,255,255,.05)';
            el.style.background = 'rgba(20,24,36,.6)';
            el.style.boxShadow = 'none';
          });
          if (target) {
            target.style.borderColor = 'rgba(79,142,255,.7)';
            target.style.background = 'rgba(30,50,90,.9)';
            target.style.boxShadow = '0 0 12px rgba(79,142,255,.25)';
            target.scrollIntoView({behavior: 'smooth', block: 'nearest'});
            setTimeout(() => {
              target.style.borderColor = 'rgba(255,255,255,.05)';
              target.style.background = 'rgba(20,24,36,.6)';
              target.style.boxShadow = 'none';
            }, 3000);
          }
        };
  
        // ── 빈 상태 표시 ──
        function _clipShowEmpty() {
          _el('clipEmpty').style.display = 'flex';
        _el('clipContent').style.display = 'none';
        _el('clipFilterBar').style.display = 'none';
        _el('clipLastLoaded').textContent = '데이터 없음 — JSON 파일을 불러오세요';
        }
  
        // ── 필터링 ID 계산 (공통 헬퍼) ──
        const FILTER_KW = {
          apartment: /(아파트|APT|재건축|재개발|분양|청약|주택|공동주택|오피스텔|빌라|연립|LH|SH|국민주택)/,
          commercial: /(상가|오피스텔|상업|근린|점포|빌딩|오피스|리테일|임대수익|상권|모아타운|신통기획|지식산업센터)/,
          land:       /(토지|단독|전원주택|농지|임야|대지|나대지|공장|창고|물류|개발|소형주택)/,
          policy:     /(정책|규제|대출|DSR|LTV|DTI|금리|세금|양도|취득세|보유세|공시가|임차|전세|보증금|법원|공매|온비드|캠코)/,
          auction:    /(경매|낙찰|공매|입찰|유찰|감정가|최저가|NPL|경공매|법원경매|온비드)/,
        };

        function _calcAllowedIds(f, analysis, rawNews, articles) {
          if (f === 'all') return null;
          const byType = analysis.by_type || {};
          const kwRe   = FILTER_KW[f];
          let allowedIds = null;

          // ① by_type articles
          const section = byType[f];
          if (section && section.articles && section.articles.length > 0) {
            allowedIds = new Set(section.articles.map(Number));
          }

          // ② 키워드 매칭으로 보강
          if (kwRe) {
            const kwIds = new Set();
            rawNews.forEach((n, i) => {
              if (kwRe.test((n.title||'') + (n.description||'') + (n.keyword||'')))
                kwIds.add(i + 1);
            });
            articles.forEach(art => {
              if (kwRe.test((art.title||'') + (art.one_line||'') + (art.keyword||'')))
                kwIds.add(Number(art.id));
            });
            if (!allowedIds || allowedIds.size < 3) {
              allowedIds = kwIds.size > 0 ? kwIds : allowedIds;
            } else {
              kwIds.forEach(id => allowedIds.add(id));
            }
          }
          return allowedIds;
        }

        // ── 전체 렌더 ──
        function _clipRender() {
          if (!_clipData) {_clipShowEmpty(); return; }
        const analysis = _clipData.analysis || { };
        const rawNews  = _clipData.rawNews || [];
        const articles = analysis.articles || [];
        const date     = _clipData.date || analysis.date || '';
        const f        = _clipFilter;
        const allowedIds = _calcAllowedIds(f, analysis, rawNews, articles);

        // 상태 표시 업데이트
        _el('clipEmpty').style.display = 'none';
        _el('clipContent').style.display = '';
        _el('clipFilterBar').style.display = 'flex';
        const filteredCount = allowedIds ? allowedIds.size : rawNews.length;
        _el('clipLastLoaded').textContent = date + ' 기준 · ' + rawNews.length + '건 수집'
          + (f !== 'all' ? ` · ${filteredCount}건 필터됨` : '');

        // 시장 심리 배너 (필터 무관하게 항상 표시)
        _renderSentiment(analysis);
        // 핵심 테마 (필터 적용)
        _renderThemes(analysis, allowedIds);
        // 투자 신호 (필터 적용)
        _renderSignals(analysis, allowedIds);
        // 주요 수치 (필터 적용)
        _renderNumbers(analysis, allowedIds);
        // 유형별 (필터 적용)
        _renderByType(analysis, f);
        // 지역별 (필터 적용)
        _renderRegions(analysis, allowedIds);
        // 액션 아이템 (필터 적용)
        _renderActions(analysis, allowedIds);
        // 기사 목록
        _clipRenderArticles(allowedIds);
        }
  
        // 기사 목록만 재렌더 (필터 시 사용)
        // ── 기사 목록 렌더 (allowedIds: Set|null) ──
        function _clipRenderArticles(allowedIds) {
          if (!_clipData) return;
          const analysis = _clipData.analysis || {};
          const rawNews  = _clipData.rawNews || [];
          const articles = analysis.articles || [];

          // ID → rawNews 매핑
          const idToNews = {};
          rawNews.forEach((n, i) => { idToNews[i + 1] = n; });

          let html = '', count = 0;

          // analysis.articles 기반으로 렌더 (one_line + 링크 포함)
          if (articles.length > 0) {
            articles.forEach(art => {
              const aid = Number(art.id);
              if (allowedIds && !allowedIds.has(aid)) return;
              const news    = idToNews[aid] || {};
              const link    = news.link || '#';
              const kw      = art.keyword || news.keyword || '';
              const title   = art.title   || news.title   || '';
              const oneLine = art.one_line || news.description || '';
              const source  = news.source || '';
              const hasLink = link && link !== '#';
              html += `\x3ca id="clip-art-${aid}" href="${link}" target="_blank" rel="noopener noreferrer" class="clip-article-link" style="${hasLink ? '' : 'pointer-events:none;'}">
          \x3cdiv style="display:flex;align-items:center;gap:6px;margin-bottom:3px;">
            \x3cspan style="font-size:10px;font-weight:700;color:rgba(255,255,255,.5);flex-shrink:0;">#${aid}\x3c/span>
            \x3cspan style="font-size:10px;font-weight:700;background:rgba(79,142,255,.25);color:#8bbfff;padding:2px 7px;border-radius:4px;flex-shrink:0;max-width:100px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${kw}\x3c/span>
            \x3cspan class="clip-article-title">${title}\x3c/span>
            \x3cspan style="flex-shrink:0;font-size:12px;color:${hasLink ? '#6aa3ff' : 'rgba(255,255,255,.2)'};">${hasLink ? '↗' : '—'}\x3c/span>
          \x3c/div>
          \x3cdiv style="display:flex;align-items:center;gap:6px;padding-left:22px;margin-top:2px;">
            ${source ? `\x3cspan class="clip-article-source">${source}\x3c/span>` : ''}
            \x3cspan class="clip-article-desc">${oneLine}\x3c/span>
          \x3c/div>
        \x3c/a>`;
              count++;
            });
          } else {
            // articles 없으면 rawNews 직접 렌더
            rawNews.forEach((news, i) => {
              const aid = i + 1;
              if (allowedIds && !allowedIds.has(aid)) return;
              const hasLink = !!(news.link);
              html += `\x3ca id="clip-art-${aid}" href="${news.link || '#'}" target="_blank" rel="noopener noreferrer" class="clip-article-link" style="${hasLink ? '' : 'pointer-events:none;'}">
          \x3cdiv style="display:flex;align-items:center;gap:6px;margin-bottom:3px;">
            \x3cspan style="font-size:10px;font-weight:700;color:rgba(255,255,255,.5);flex-shrink:0;">#${aid}\x3c/span>
            \x3cspan class="clip-article-title">${news.title || ''}\x3c/span>
            \x3cspan style="flex-shrink:0;font-size:12px;color:${hasLink ? '#6aa3ff' : 'rgba(255,255,255,.2)'};">${hasLink ? '↗' : '—'}\x3c/span>
          \x3c/div>
          \x3cdiv style="font-size:11px;color:rgba(255,255,255,.6);line-height:1.55;padding-left:22px;">${news.description || ''}\x3c/div>
        \x3c/a>`;
              count++;
            });
          }

          const totalLabel = allowedIds ? `${count}건 (필터됨)` : `${count}건`;
          _el('clipArticles').innerHTML = html ||
            '\x3cdiv style="font-size:12px;color:rgba(255,255,255,.4);padding:16px;text-align:center;">해당 유형의 기사가 없습니다\x3c/div>';
          _el('clipArticleCount').textContent = `수집 기사 (${totalLabel})`;
        }


        // ── 시장 심리 배너 ──
        function _renderSentiment(analysis) {
          const sentiment = analysis.market_sentiment || '중립';
        const reason = analysis.sentiment_reason || '';
        const summary = analysis.summary || '';
        const STYLES = {
          '긍정': ['#00d4aa', 'rgba(0,212,170,.1)', '📈'],
        '부정': ['#ff4d4d', 'rgba(255,77,77,.1)', '📉'],
        '혼재': ['#ff8c42', 'rgba(255,140,66,.1)', '↔️'],
        '중립': ['#6b7590', 'rgba(107,117,144,.1)', '➖'],
          };
        const [c, bg, em] = STYLES[sentiment] || STYLES['중립'];
        _el('clipSentimentBanner').innerHTML = `
        \x3cdiv style="background:${bg};border:1px solid ${c}30;border-radius:9px;padding:12px 16px;display:flex;align-items:flex-start;gap:12px;">
          \x3cdiv style="background:${bg};border:1px solid ${c};border-radius:20px;padding:4px 12px;font-size:13px;font-weight:700;color:${c};white-space:nowrap;flex-shrink:0;">${em} ${sentiment}\x3c/div>
          \x3cdiv style="flex:1;">
            \x3cdiv style="font-size:13px;color:rgba(255,255,255,.9);line-height:1.7;margin-bottom:5px;font-weight:500;">${summary}\x3c/div>
            ${reason ? `\x3cdiv style="font-size:11px;color:rgba(255,255,255,.6);margin-top:2px;">근거: ${reason}\x3c/div>` : ''}
          \x3c/div>
        \x3c/div>`;
        }
  
        // ── 핵심 테마 ──
        function _renderThemes(analysis, allowedIds) {
          const themes = analysis.key_themes || [];
        if (!themes.length) {_el('clipThemes').innerHTML = '\x3cdiv style="font-size:11px;color:rgba(255,255,255,.4);padding:8px;">테마 없음\x3c/div>'; return; }
        const IMPACT = {'높음': '#ff4d4d', '중간': '#ff8c42', '낮음': '#6b7590' };
          const filtered = allowedIds ? themes.filter(t => (t.articles||[]).some(id => allowedIds.has(Number(id)))) : themes;
          if (!filtered.length) {_el('clipThemes').innerHTML = '\x3cdiv style="font-size:11px;color:rgba(255,255,255,.4);padding:8px;">해당 유형 테마 없음\x3c/div>'; return; }
          _el('clipThemes').innerHTML = filtered.map(t => {
            const ic = IMPACT[t.impact] || '#6b7590';
            const refs = (t.articles || []).map(id => `\x3cspan class="clip-art-ref" onclick="clipHighlightArticle(${id})">#${id}\x3c/span>`).join('');
        return `\x3cdiv class="clip-theme-card">
          \x3cdiv style="display:flex;align-items:center;justify-content:space-between;margin-bottom:5px;">
            \x3cdiv class="clip-card-title">${t.emoji || '📌'} ${t.theme || ''}\x3c/div>
            \x3cspan style="font-size:10px;background:rgba(0,0,0,.35);border:1px solid ${ic};color:${ic};border-radius:4px;padding:1px 7px;font-weight:700;">영향 ${t.impact || ''}\x3c/span>
          \x3c/div>
          \x3cdiv class="clip-card-desc">${t.desc || ''}\x3c/div>
          ${refs ? `\x3cdiv style="margin-top:6px;">${refs}\x3c/div>` : ''}
        \x3c/div>`;
          }).join('');
        }
  
        // ── 투자 신호 ──
        function _renderSignals(analysis, allowedIds) {
          const signals = analysis.investment_signals || [];
        if (!signals.length) {_el('clipSignals').innerHTML = '\x3cdiv style="font-size:11px;color:var(--di);padding:8px;">신호 없음\x3c/div>'; return; }
        const SIGNAL = {'기회': ['#00d4aa', 'rgba(0,212,170,.1)', '🟢'], '위험': ['#ff4d4d', 'rgba(255,77,77,.09)', '🔴'], '중립': ['#6b7590', 'rgba(107,117,144,.09)', '⚪'] };
          const filteredSig = allowedIds ? signals.filter(s => (s.articles||[]).some(id => allowedIds.has(Number(id)))) : signals;
          if (!filteredSig.length) {_el('clipSignals').innerHTML = '\x3cdiv style="font-size:11px;color:rgba(255,255,255,.4);padding:8px;">해당 유형 투자 신호 없음\x3c/div>'; return; }
          _el('clipSignals').innerHTML = filteredSig.map(s => {
            const [sc, sbg, icon] = SIGNAL[s.type] || SIGNAL['중립'];
            const refs = (s.articles || []).map(id => `\x3cspan class="clip-art-ref" onclick="clipHighlightArticle(${id})">#${id}\x3c/span>`).join('');
        return `\x3cdiv class="clip-signal-card" style="background:${sbg};border-left-color:${sc};">
          \x3cdiv style="display:flex;align-items:center;gap:7px;margin-bottom:4px;">
            \x3cspan style="font-size:11px;font-weight:800;color:${sc};">${icon} ${s.type}\x3c/span>
            \x3cspan class="clip-card-title" style="color:rgba(255,255,255,.9);font-size:12px;">${s.signal || ''}\x3c/span>
          \x3c/div>
          \x3cdiv class="clip-card-desc">${s.detail || ''}\x3c/div>
          ${refs ? `\x3cdiv style="margin-top:5px;">${refs}\x3c/div>` : ''}
        \x3c/div>`;
          }).join('');
        }
  
        // ── 주요 수치 ──
        function _renderNumbers(analysis, allowedIds) {
          const nums = analysis.key_numbers || [];
        if (!nums.length) {_el('clipNumbers').innerHTML = ''; return; }
          const filteredNums = allowedIds ? nums.filter(n => (n.articles||[]).some(id => allowedIds.has(Number(id)))) : nums;
          if (!filteredNums.length) { _el('clipNumbers').innerHTML = ''; return; }
        _el('clipNumbers').innerHTML = `\x3cdiv style="display:grid;grid-template-columns:repeat(auto-fill,minmax(110px,1fr));gap:6px;margin-top:4px;">${
          filteredNums.map(n => `\x3cdiv style="background:rgba(30,35,48,.8);border-radius:7px;padding:8px;text-align:center;">
              \x3cdiv style="font-size:10px;color:rgba(255,255,255,.5);margin-bottom:4px;font-weight:600;">${n.label || ''}\x3c/div>
              \x3cdiv style="font-size:16px;font-weight:800;color:#6aa8ff;">${n.value || ''}\x3c/div>
              \x3cdiv style="font-size:10px;color:rgba(255,255,255,.5);margin-top:3px;line-height:1.4;">${n.context || ''}\x3c/div>
            \x3c/div>`).join('')
        }\x3c/div>`;
        }
  
        // ── 유형별 요약 ──
        function _renderByType(analysis, activeFilter) {
          const byType = analysis.by_type || { };
        const CONFIG = {apartment: ['🏠', '아파트', '#4f8eff'], commercial: ['🏢', '상가/지산', '#ff8c42'], land: ['🌿', '토지/단독', '#00d4aa'], policy: ['📋', '정책/규제', '#9b8aff'] };
        let html = '';
          Object.entries(CONFIG).forEach(([key, [icon, label, color]]) => {
            // 필터 중이면 해당 유형만 표시
            if (activeFilter && activeFilter !== 'all' && activeFilter !== 'auction' && key !== activeFilter) return;
            const s = byType[key] || { };
        if (s.headline && s.headline !== '-') {
              const refs = (s.articles || []).map(id => `\x3cspan class="clip-art-ref" onclick="clipHighlightArticle(${id})">#${id}\x3c/span>`).join('');
        html += `\x3cdiv style="background:rgba(255,255,255,.04);border:1px solid ${color}40;border-radius:9px;padding:10px 12px;">
          \x3cdiv style="display:flex;align-items:center;gap:6px;margin-bottom:5px;">
            \x3cspan style="font-size:14px;">${icon}\x3c/span>
            \x3cspan style="font-size:12px;font-weight:800;color:${color};">${label}\x3c/span>
          \x3c/div>
          \x3cdiv style="font-size:12px;color:rgba(255,255,255,.78);line-height:1.6;">${s.headline}\x3c/div>
          ${refs ? `\x3cdiv style="margin-top:5px;">${refs}\x3c/div>` : ''}
        \x3c/div>`;
            }
          });
        _el('clipByType').innerHTML = html || '\x3cdiv style="font-size:11px;color:var(--di);">데이터 없음\x3c/div>';
        _el('clipByTypeWrap').style.display = html ? '' : 'none';
        }
  
        // ── 지역별 분석 ──
        function _renderRegions(analysis, allowedIds) {
          const regions = analysis.regional_analysis || [];
        if (!regions.length) {_el('clipRegionsWrap').style.display = 'none'; return; }
        _el('clipRegionsWrap').style.display = '';
        const RTYPE = {'호재': ['#00d4aa', 'rgba(0,212,170,.08)', '📈'], '악재': ['#ff4d4d', 'rgba(255,77,77,.07)', '📉'], '중립': ['#6b7590', 'rgba(107,117,144,.07)', '➖'] };
          const filteredReg = allowedIds ? regions.filter(r => (r.articles||[]).some(id => allowedIds.has(Number(id)))) : regions;
          if (!filteredReg.length) { _el('clipRegionsWrap').style.display = 'none'; return; }
          _el('clipRegions').innerHTML = filteredReg.map(r => {
            const [rc, rbg, icon] = RTYPE[r.issue_type] || RTYPE['중립'];
            const refs = (r.articles || []).map(id => `\x3cspan class="clip-art-ref" onclick="clipHighlightArticle(${id})">#${id}\x3c/span>`).join('');
        return `\x3cdiv class="clip-region-card" style="background:${rbg};border:1px solid ${rc}40;">
          \x3cdiv style="display:flex;align-items:center;gap:5px;margin-bottom:4px;">
            \x3cspan style="font-size:13px;">${icon}\x3c/span>
            \x3cspan style="font-size:13px;font-weight:800;color:${rc};">${r.region || ''}\x3c/span>
          \x3c/div>
          \x3cdiv class="clip-card-desc">${r.details || ''}\x3c/div>
          ${refs ? `\x3cdiv style="margin-top:5px;">${refs}\x3c/div>` : ''}
        \x3c/div>`;
          }).join('');
        }
  
        // ── 액션 아이템 ──
        function _renderActions(analysis, allowedIds) {
          const actions = analysis.action_items || [];
        if (!actions.length) {_el('clipActionsWrap').style.display = 'none'; return; }
          const filteredAct = allowedIds ? actions.filter(a => (typeof a === 'object' ? (a.articles||[]) : []).some(id => allowedIds.has(Number(id)))) : actions;
          if (!filteredAct.length) { _el('clipActionsWrap').style.display = 'none'; return; }
        _el('clipActionsWrap').style.display = '';
        _el('clipActions').innerHTML = `\x3cdiv style="background:rgba(0,212,170,.05);border:1px solid rgba(0,212,170,.15);border-radius:9px;padding:10px 14px;">${
          filteredAct.map(a => {
            const action = typeof a === 'string' ? a : (a.action || '');
            const reason = typeof a === 'string' ? '' : (a.reason || '');
            const refs = (typeof a === 'object' ? (a.articles || []) : []).map(id => `\x3cspan class="clip-art-ref" onclick="clipHighlightArticle(${id})">#${id}\x3c/span>`).join('');
            return `\x3cdiv style="display:flex;align-items:flex-start;gap:8px;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.04);">
                \x3cspan style="color:#00d4aa;font-size:13px;flex-shrink:0;">✓\x3c/span>
                \x3cdiv>
                  \x3cdiv style="font-size:13px;color:rgba(255,255,255,.9);font-weight:700;line-height:1.5;">${action}\x3c/div>
                  ${reason ? `\x3cdiv style="font-size:11px;color:rgba(255,255,255,.58);margin-top:3px;">${reason}\x3c/div>` : ''}
                  ${refs ? `\x3cdiv style="margin-top:4px;">${refs}\x3c/div>` : ''}
                \x3c/div>
              \x3c/div>`;
          }).join('')
        }\x3c/div>`;
        }
  
        // ── 헬퍼 ──
        function _el(id) { return document.getElementById(id); }
  
        // ── AI 브리핑: 프록시(8080) → 네이버 뉴스 API 실수집 → Gemini 분석 ──
        window.clipStartBriefing = async function() {
          const geminiKey = (typeof gk === 'function') ? gk() : '';
          if (!geminiKey) {
            if (typeof showToast === 'function') showToast('Gemini API 키를 먼저 설정하세요 (우상단 ⚙️)', 'warn');
            return;
          }

          // 네이버 API 키 (뉴스피드 탭과 동일한 저장소)
          const naverId  = localStorage.getItem('naver_id') || '';
          const naverSec = localStorage.getItem('naver_sec') || '';
          if (!naverId || !naverSec) {
            if (typeof showToast === 'function') showToast('네이버 API 키를 먼저 입력해주세요 (뉴스피드 탭 상단)', 'warn');
            return;
          }

          const today = new Date().toISOString().slice(0, 10);

          // ── 로딩 UI ──
          _el('clipEmpty').style.display = 'none';
          _el('clipContent').style.display = '';
          _el('clipFilterBar').style.display = 'none';
          _el('clipLastLoaded').textContent = '📡 네이버 뉴스 수집 중...';
          _el('clipSentimentBanner').innerHTML = `
          \x3cdiv style="background:rgba(79,142,255,.08);border:1px solid rgba(79,142,255,.25);border-radius:9px;padding:16px;text-align:center;">
            \x3cdiv style="font-size:13px;color:#4f8eff;margin-bottom:6px;">📡 네이버에서 실시간 기사 수집 중...</div>
            \x3cdiv style="font-size:11px;color:var(--di);">로컬 프록시(8080)를 통해 진짜 뉴스를 가져옵니다</div>
          \x3c/div>`;
          ['clipThemes','clipSignals','clipNumbers','clipByType','clipRegions','clipActions','clipArticles']
            .forEach(id => { const el = _el(id); if (el) el.innerHTML = ''; });

          // ── 필터 ──
          const RE_ESTATE = /(아파트|부동산|경매|낙찰|임대|전세|분양|재건축|재개발|상가|오피스텔|토지|주택|역세권|GTX|호재|공시가|낙찰가율|대출|임차|건물|지식산업센터|뉴타운|청약|공급|LH|캠코|시세|매매)/;
          const RE_NOISE  = /(와인|달항아리|포켓몬|골동품|예술품|그림|조각|미술|주식|코인|가상화폐|암호화폐|NFT|스포츠|야구|축구|농구|골프|배구|연예|영화|드라마|음악|콘서트|게임|아이돌)/;

          // 저장된 키워드 우선, 없으면 기본값
          const savedKws  = JSON.parse(localStorage.getItem('ins_kw') || '[]');
          const defaultKws = ['부동산 법원경매', '아파트 낙찰가율', '상가 오피스텔 경매', '토지 단독주택 경매', '부동산 대출 규제', '재건축 재개발 시장', 'GTX 역세권 분양', '전세 임대 시장'];
          const keywords  = savedKws.length > 0 ? savedKws : defaultKws;

          // ── 1단계: 프록시 통해 진짜 뉴스 수집 ──
          const PROXY = window.PROXY_URL;
          const allNews = [];
          const seenLinks = new Set();
          let fetchOk = 0, fetchFail = 0;

          for (const kw of keywords) {
            try {
              const url = `${PROXY}/api/news?keyword=${encodeURIComponent(kw)}&display=7&client_id=${encodeURIComponent(naverId)}&client_secret=${encodeURIComponent(naverSec)}`;
              const resp = await fetch(url);
              if (!resp.ok) throw new Error('HTTP ' + resp.status);
              const data = await resp.json();

              for (const item of (data.items || [])) {
                const title = item.title.replace(/<[^>]+>/g, '').trim();
                const desc  = (item.description || '').replace(/<[^>]+>/g, '').trim();
                const link  = (item.originallink || item.link || '').trim();
                if (seenLinks.has(link)) continue;
                if (RE_NOISE.test(title + desc)) continue;
                if (!RE_ESTATE.test(title + desc)) continue;
                seenLinks.add(link);
                allNews.push({
                  title,
                  description: desc,
                  link,
                  pubDate: item.pubDate || '',
                  keyword: kw,
                  source: (() => { try { return new URL(link).hostname.replace('www.', ''); } catch(e) { return ''; } })()
                });
              }
              fetchOk++;
            } catch(e) {
              console.warn('[클리핑] 뉴스 수집 실패 [' + kw + ']:', e.message);
              fetchFail++;
            }
            await new Promise(r => setTimeout(r, 150));
          }

          if (allNews.length === 0) {
            const proxyMsg = fetchFail === keywords.length
              ? '프록시 서버(8080)가 실행 중인지 확인하세요. <code>python3 proxy_server_floor_v16.py</code>'
              : '수집된 뉴스가 없습니다. 키워드나 API 키를 확인하세요.';
            _el('clipSentimentBanner').innerHTML = `
              \x3cdiv style="background:rgba(255,77,77,.08);border:1px solid rgba(255,77,77,.25);border-radius:9px;padding:14px;text-align:center;">
                \x3cdiv style="font-size:13px;color:#ff4d4d;margin-bottom:6px;">❌ 뉴스 수집 실패 (${fetchFail}/${keywords.length} 키워드 오류)</div>
                \x3cdiv style="font-size:11px;color:var(--di);">${proxyMsg}</div>
              \x3c/div>`;
            _el('clipEmpty').style.display = 'flex';
            _el('clipContent').style.display = 'none';
            if (typeof showToast === 'function') showToast('뉴스 수집 실패 — 프록시 서버 확인', 'warn');
            return;
          }

          // ── 2단계: 수집한 진짜 뉴스를 Gemini로 분석 ──
          _el('clipLastLoaded').textContent = `진짜 기사 ${allNews.length}건 수집 완료 → Gemini 분석 중...`;
          _el('clipSentimentBanner').innerHTML = `
          \x3cdiv style="background:rgba(155,138,255,.08);border:1px solid rgba(155,138,255,.25);border-radius:9px;padding:16px;text-align:center;">
            \x3cdiv style="font-size:13px;color:#9b8aff;margin-bottom:6px;">🤖 실제 뉴스 ${allNews.length}건을 Gemini가 분석 중...</div>
            \x3cdiv style="font-size:11px;color:var(--di);">잠시만 기다려주세요 (약 15~30초)</div>
          \x3c/div>`;

          // 프롬프트용 뉴스 텍스트 — 최대 40건, 요약 80자로 압축 (토큰 절약)
          const newsForPrompt = allNews.slice(0, 40);
          let newsText = '';
          newsForPrompt.forEach((item, i) => {
            const shortDesc = (item.description || '').slice(0, 80);
            newsText += `[${i+1}] [${item.keyword}] ${item.title} / ${shortDesc}\n`;
          });

          const prompt = `당신은 한국 부동산 경매·공매 전문 투자 애널리스트입니다.
아래는 오늘(${today}) 네이버에서 실제 수집한 부동산·경매 관련 뉴스 ${newsForPrompt.length}건입니다.
이 뉴스들만 바탕으로 분석해주세요. 뉴스에 없는 내용은 절대 추가하지 마세요.
독자는 법원경매·온비드 공매로 아파트·상가·토지에 투자하는 실전 투자자입니다.

=== 실제 수집 뉴스 (${newsForPrompt.length}건) ===
${newsText}

=== 분석 지침 ===
1. 위 뉴스 내용만 사용 — 없는 정보 절대 창작 금지
2. key_themes, investment_signals 등의 articles 배열에 근거 기사 번호 반드시 명시
3. regional_analysis: 뉴스에 나온 구체적 지역·노선·이슈만 작성
4. key_numbers: 뉴스에 실제 등장한 수치만 포함
5. articles 배열: 수집된 기사 전체를 id/title/keyword/one_line으로 정리

코드블록 없이 순수 JSON만 반환:

{
  "date": "${today}",
  "summary": "수집 뉴스 기반 2~3줄 핵심 요약",
  "market_sentiment": "긍정/부정/중립/혼재",
  "sentiment_reason": "뉴스에서 인용한 구체적 근거 1줄",
  "key_themes": [
    {"theme": "테마명", "emoji": "이모지", "desc": "뉴스 기반 설명 2~3줄", "articles": [기사번호], "impact": "높음/중간/낮음"}
  ],
  "investment_signals": [
    {"signal": "신호명", "type": "기회/위험/중립", "detail": "구체적 시사점", "articles": [기사번호]}
  ],
  "regional_analysis": [
    {"region": "지역명", "issue_type": "호재/악재/중립", "details": "뉴스 기반 구체적 이슈", "articles": [기사번호]}
  ],
  "by_type": {
    "apartment": {"headline": "아파트 핵심 이슈 1줄", "articles": [기사번호]},
    "commercial": {"headline": "상가/오피스텔 핵심 이슈 1줄", "articles": [기사번호]},
    "land": {"headline": "토지/단독 핵심 이슈 1줄", "articles": [기사번호]},
    "policy": {"headline": "정책/규제 핵심 이슈 1줄", "articles": [기사번호]}
  },
  "key_numbers": [
    {"label": "항목명", "value": "뉴스에 나온 수치", "context": "맥락 설명", "articles": [기사번호]}
  ],
  "action_items": [
    {"action": "뉴스 기반 구체적 액션", "reason": "뉴스 근거", "articles": [기사번호]}
  ],
  "articles": [
    {"id": 1, "title": "기사 제목", "keyword": "검색키워드", "one_line": "한 줄 요약"}
  ]
}`;

          try {
            const raw = await geminiText(prompt, { generationConfig: { temperature: 0.1, maxOutputTokens: 8192 } });
            const cleaned = raw.replace(/```json\s*/g, '').replace(/\s*```/g, '').trim();
            let analysis;
            try {
              analysis = JSON.parse(cleaned);
            } catch(pe) {
              const m = cleaned.match(/\{[\s\S]*\}/);
              if (m) analysis = JSON.parse(m[0]);
              else throw new Error('JSON 파싱 실패: ' + pe.message);
            }

            // articles 배열이 비어있으면 rawNews로부터 자동 생성
            if (!analysis.articles || analysis.articles.length === 0) {
              analysis.articles = allNews.map((n, i) => ({
                id: i + 1,
                title: n.title,
                keyword: n.keyword,
                one_line: n.description.slice(0, 80)
              }));
            }

            const clipData = {
              id: 'clip_' + today.replace(/-/g, ''),
              date: today,
              title: `📰 ${today} 실시간 브리핑 (${allNews.length}건)`,
              sentiment: analysis.market_sentiment || '중립',
              summary: analysis.summary || '',
              rawNews: allNews,   // 원문 링크 포함된 진짜 뉴스 배열
              analysis,
              createdAt: new Date().toISOString(),
              version: 3,
              source: 'naver_proxy',
            };

            _clipData = clipData;
            localStorage.setItem(CLIP_KEY, JSON.stringify(clipData));
            _clipFilter = 'all';
            _clipRender();
            if (typeof showToast === 'function') showToast(`📰 브리핑 완료! 실제 뉴스 ${allNews.length}건 분석`, 'ok');

          } catch(err) {
            _el('clipSentimentBanner').innerHTML = `
              \x3cdiv style="background:rgba(255,77,77,.08);border:1px solid rgba(255,77,77,.25);border-radius:9px;padding:14px;text-align:center;">
                \x3cdiv style="font-size:13px;color:#ff4d4d;margin-bottom:4px;">❌ Gemini 분석 실패</div>
                \x3cdiv style="font-size:11px;color:var(--di);">${err.message}</div>
              \x3c/div>`;
            _el('clipEmpty').style.display = 'flex';
            _el('clipContent').style.display = 'none';
            if (typeof showToast === 'function') showToast('분석 실패: ' + err.message, 'warn');
          }
        };
  
      })();

